    // BMR Calculator
    public function bmr($request){
        // dd($request->all());
        if (is_numeric($request->age) && is_numeric($request->weight ) || is_numeric($request->{'height-ft'}) || is_numeric($request->{'height-in'}) || is_numeric($request->{'height-cm'})) {
            $age=$request->age;
            $weight=$request->weight;
            $height_ft=$request->{'height-ft'};
            $height_in=$request->{'height-in'};
            $height_cm=$request->{'height-cm'};
            if ($request->unit==="lbs") {
                $weight = $weight / 2.205;
            }
            if ($request->unit_ft_in==='ft/in') {
                $height_cm=$height_ft * 30.48;
                if ($height_in!=null) {
                    $height_in= $height_in * 2.54;
                    $height_cm=$height_cm + $height_in;
                }
            }
            if ($request->gender==='Female') {
                $bmr= round((9.99 * $weight) + (6.25 * $height_cm) - (4.92 * $age) - 161,2);
                $hbmr=round(447.593 + ( 9.247 * $weight ) + ( 3.098 * $height_cm ) - (4.330 * $age ));
                if ($age >= 18 && $age < 30) {
                $sbmr = 14.818 * $weight + 486.6;
                } 
                else if ($age >= 30 && $age < 60) {
                $sbmr = 8.126 * $weight + 845.6;
                }
                else if ($age >= 60) {
                $sbmr = 9.082 * $weight + 658.5;	
                }
            } else {
                // $hbmr=round(10 * $weight + 6.25 * $height_cm - 5 * $age + 5,2);
                $hbmr=round(88.362 + ( 13.397 * $weight ) + ( 4.799 * $height_cm ) - ( 5.677 * $age ),2);
                $bmr= round((9.99 * $weight) + (6.25 * $height_cm) - (4.92 * $age) + 5,2);
                if ($age >= 18 && $age < 30) {
                $sbmr = 15.057 * $weight + 692.2;
                } 
                else if ($age >= 30 && $age < 60) {
                $sbmr = 11.472 * $weight + 873.1	;
                }
                else if ($age >= 60) {
                $sbmr = 11.711 * $weight + 587.7;	
                }
            }

            $this->param['BMR'] = $bmr;
            $this->param['hbmr'] = $hbmr;
            $this->param['sbmr'] = round($sbmr,2);
            $this->param['RESULT'] = 1;
            return $this->param;
        } else {
            $this->param['error'] = 'Please Fill All Fields.';
            return $this->param;
        }
    }

	// ANC Calculator
	public function anc($request){
		$check=true;
		foreach ($request->toArray() as $key => $value) {
			if ($key!='submit') {
				if (empty($value)) {
					$check=false;
				}
			}
		}

		if (is_numeric($request->wbs) && is_numeric($request->segs) && is_numeric($request->bands)) {
			$anc= $request->wbs * ($request->segs + $request->bands) / 100;
			$this->param['anc'] = $anc;
			$this->param['RESULT'] = 1;
            return $this->param;
		} else {
            $this->param['error'] = 'Please Fill All Fields.';
            return $this->param;
		}
	}

	// ALC Calculator
	public function alc($request){
		if (is_numeric($request->wbc) && is_numeric($request->l)) {
			$alc= round((($request->l / 100) * $request->wbc),3);
			$this->param['alc']=$alc;
			$this->param['RESULT']=1;
            return $this->param;
		} else {
            $this->param['error'] = 'Please Fill All Fields.';
            return $this->param;
		}
	}

    // Reticulocyte Index Calculator
	public function reticulocyte($request){
        if (is_numeric($request->x) && is_numeric($request->y) && is_numeric($request->z)) {
            $r=$request->x;
            $h=$request->y;
            $n=$request->z;
			$x= (($r) * ($h/$n));
			if ($h<20) {
				$m=2.5;
			}elseif ($h==20 || $h<25) {
				$m=2.0;
			}elseif ($h==25 || $h<35) {
				$m=1.5;
			}else{
				$m=1.0;
			}
			$y=$x/$m;
			if ($x<2) {
				$ans="Hypoproliferation";
				$ans_p="Reticulocyte index <2 indicates Hypoproliferation";
			}else{
				$ans="Adequate";
				$ans_p="Reticulocyte index ≥2 indicates Adequate response";
			}
			$this->param['x'] = round($x,2);
			$this->param['y'] = round($y,3);
			$this->param['ans'] = $ans;
			$this->param['ans_p'] = $ans_p;
			$this->param['RESULT'] = 1;
            return $this->param;
		} else {
            $this->param['error'] = 'Please Fill All Fields.';
            return $this->param;
		}	
	}

    // Centor Score Calculator
	public function centor($request){
		$check=true;
		foreach ($request->toArray() as $key => $value) {
			if ($key!='submit') {
				if (empty($value) && $value!=0) {
					$check=false;
				}
			}
		}
		if ($check==true && is_numeric($request->age) && is_numeric($request->temp)) {
			$tonsils=$request->tonsils;
			$cough=$request->cough;
			$lymph=$request->lymph;
			if ($request->age < 15) {
				$age=1;
			} elseif ($request->age > 15 && $request->age < 45) {
				$age=0;
			} else {
				$age=-1;
			}
			if ($request->unit=="°C") {
				if ($request->temp > 38) {
					$temp=1;
				} else {
					$temp=0;
				}
			} else {
				if ($request->temp > 100.4) {
					$temp=1;
				} else {
					$temp=0;
				}
			}
			$ans= $tonsils+$cough+$lymph+$age+$temp;
			if ($ans==0) {
				$per= "(1 - 2.5 %)";
				$text="There is no need for further testing or antibiotics.";
			}elseif ($ans==1) {
				$per="(5 - 10 %)";
				$text="There is no need for further testing or antibiotics.";
			}elseif ($ans==2) {
				$per="(11 - 17 %)";
				$text="At this point, rapid strep testing and/or culture (Optional).";
			}elseif ($ans==3) {
				$per="(28 - 35 %)";
				$text="There is a need to consider rapid strep testing and/or culture.";
			}else{
				$per="(51 - 53 %)";
				$text="There is a need to treat empirically using antibiotics.";
			}
			$this->param['ans'] = $ans.'</b><span class="text-green font-s-25"> Points</span>';
			$this->param['per'] = $per;
			$this->param['text'] = $text;
			$this->param['RESULT'] = 1;
            return $this->param;
			
		} else {
            $this->param['error'] = 'Please Fill All Fields.';
            return $this->param;
		}
	}

    // Child Pugh Score Calculator
	public function child($request){
		$validator = Validator::make($request->all(), [
            'a' => 'required',
            'e' => 'required',
            'b' => 'required',
            'as' => 'required',
            'i' => 'required',
        ]);

		if (!$validator->fails()) {
			$ans= $request->a + $request->e + $request->i + $request->b + $request->as;
			if ($ans==5 || $ans==6) {
				$class="A";
				$ansa="Life Expectancy : 15-20 years";
				$ansb="Abdominal surgery peri-operative mortality: 10%";
				$percent1='100';
				$percent2='85';
			} elseif ($ans>6 && $ans < 10) {
				$class="B";
				$ansa="Indication for transplant evaluation";
				$ansb="Abdominal surgery peri-operative mortality: 30%";
				$percent1='81';
				$percent2='57';
			}else{
				$class="C";
				$ansa="Life Expectancy : 1-3 years";
				$ansb="Abdominal surgery peri-operative mortality: 82%";
				$percent1='45';
				$percent2='35';
			}
			$this->param['ans'] = $ans.'</b><span class="text-green font-s-25"> Points</span>';
			$this->param['class'] = $class;
