	// 6 Minute Walk Test Calculator
	public function walk($request){
        // dd($request->all());
		if (is_numeric($request->age) && is_numeric($request->weight ) && is_numeric($request->distance) || is_numeric($request->{'height-ft'}) || is_numeric($request->{'height-in'}) || is_numeric($request->{'height-cm'})) {
			$age=$request->age;
			$weight=$request->weight;
			$distance=$request->distance;
			$height_ft=$request->{'height-ft'};
			$height_in=$request->{'height-in'};
			$height_cm=$request->{'height-cm'};
			if ($request->unit==="lbs") {
				$weight = $weight / 2.205;
			}
			if ($request->unit_ft_in==='ft/in') {
				$height_cm=$height_ft * 30.48;
				if ($height_in!=null) {
					$height_in= $height_in * 2.54;
					$height_cm=$height_cm + $height_in;
				}
			}
			if ($request->gender==='Male') {
				$ans = round(((7.57 * $height_cm) - (5.02 * $age) - (1.76 * $weight) - 309));
				$limit=$ans-153;
			} else {
				$ans = round(((2.11 * $height_cm) - (5.78 * $age) - (2.29 * $weight) + 667));
				$limit=$ans-139;
			}
			if ($request->dis_unit==='ft') {
				$distance=$distance / 3.281;
			}
			$percent = round($distance / $ans * 100);

			$this->param['Ans'] = $ans;
			$this->param['limit'] = $limit;
			$this->param['Percent'] = $percent;
			$this->param['RESULT'] = 1;
            return $this->param;
		} else {
            $this->param['error'] = 'Please fill All the Required fields.';
            return $this->param;
		}
		
	}

