    // Allele Frequency Calculator
	public function allele($request){
        // dd($request->all());
        $type = $request->type;
        $operations = $request->operations;
        $first = $request->first;
        $second = $request->second;
        $third = $request->third;
        $four = $request->four;

		if ($type == "frst") {
			if (is_numeric($first) && is_numeric($second) && is_numeric($third)) {
				$mul1 = 0.5 * $second;
				$down_add = $first + $second + $third;
				$p = $first + $mul1;
				$q = $third + $mul1;
				$pfreq = $p / $down_add;
				$qfreq = $q / $down_add;
			}else{
                $this->param['error'] = 'Please! Check Your Input.';
                return $this->param;
			}
		}else if ($type == "scnd") {
			if ($operations == 1 || $operations == 2) {
				if (is_numeric($four)) {
					if ($four > 1) {
						$f_ans = 100 / $four;
						$div = 1 / $f_ans;
						$qfreq = sqrt($div);
						$A = 1;
						$B = $qfreq * 2;
						$q_sq = pow($qfreq, 2);
						$C = $q_sq - 1;
						$dis= pow($B, 2) - (4*$A*$C);
		                if ($dis>0) {
		                    $x1= round((($B * (-1)) + sqrt($dis)) / (2*$A),4);
		                    $x2= round((($B * (-1)) - sqrt($dis)) / (2*$A),4);
		                    $pfreq = max($x1,$x2);
		                }
		                if ($dis<0) {
		                    $x1= round(($B * (-1))/(2*$A),4).' + '.round(sqrt(($dis * (-1))) / (2*$A),4);
		                    $x2= round(($B * (-1))/(2*$A),4).' - '.round(sqrt(($dis * (-1))) / (2*$A),4);
		                    $pfreq = max($x1,$x2);
		                }
		                if ($dis==0) {
		                    $x1= round(($B * (-1)) /(2*$A),4);
		                    $pfreq = $x1;
		                }
						$this->param['f_ans'] = $f_ans;
		            }else{
                        $this->param['error'] = 'Occurrence of the disease must be greater than 1 in 1 person.';
                        return $this->param;
					}
				}else{
                    $this->param['error'] = 'Please! Check Your Input.';
                    return $this->param;
				}
			}
		}
		if (!empty($pfreq) && !empty($qfreq)) {
			$p_square = pow($pfreq, 2);
			$q_square = pow($qfreq, 2);
			$p_q = 2 * $pfreq * $qfreq;
		}
		$this->param['pfreq'] = $pfreq;
		$this->param['qfreq'] = $qfreq;
		$this->param['p_square'] = $p_square;						
		$this->param['q_square'] = $q_square;						
		$this->param['p_q'] = $p_q;
		$this->param['request'] = $request;
		$this->param['RESULT'] = 1;
        return $this->param;
	}

