    // Bra Size Calculator
  	public function bra($request){
        $bust=trim($request->bust);
        $unit=trim($request->unit);
        $band=trim($request->band);
        $unit1=trim($request->unit1);

        if(is_numeric($bust) && is_numeric($band)){
            $sizes = [
                '0'=>['AA','AA','AA','AA','AA'],
                '1'=>['A','A','A','A','A'],
                '2'=>['B','B','B','B','B'],
                '3'=>['C','C','C','C','C'],
                '4'=>['D','D','D','E','E'],
                '5'=>['DD/E','DD','DD','F','F'],
                '6'=>['DDD/F','E','E','G','G'],
                '7'=>['DDDD/G','F','F','H','H'],
                '8'=>['H','G','FF','J','J'],
                '9'=>['I','H','G','K','K'],
                '10'=>['J','I','GG','L','L'],
                '11'=>['K','J','H','M','M'],
                '12'=>['L','K','HH','O','O'],
                '13'=>['M','L','J','P','P'],
                '14'=>['N','M','JJ','Q','Q'],
                '15'=>['O','N','K','S','S'],
                '16'=>['P','O','KK','T','T'],
                '17'=>['Q','P','L','U','U'],
                '18'=>['R','Too big bust size','LL','V','V'],
                '19'=>['Too big bust size','Too big bust size','M','X','X'],
                '19'=>['Too big bust size','Too big bust size','Too big bust size','Y','Y'],
                '20'=>['Too big bust size','Too big bust size','Too big bust size','Z','Z'],
            ];
            $main_bust=$bust;
            $main_band=$band;
            if ($unit=='cm') {
                $bust=round($bust/2.54);
            }
            if ($unit1=='cm') {
                $band=round($band/2.54);
            }
            if ($band%2===0) {
                $diff=round($bust)-round($band);
            }else{
                if ($band>$main_band) {
                    $band--;
                }else{
                    $band++;
                }
                $diff=round($bust)-round($band);
            }
            if ($band>$bust) {
                $this->param['error'] = 'Bust size must be greater than Band size.';
                return $this->param;
            }
            if ($band<26) {
                $band='Band too small';
                $aus='Band too small';
                $eu='Band too small';
                $fr='Band too small';
            }else{
                $diff1=$band-26;
                $aus=4+$diff1;
                $eu=55 + ($diff1*2.5);
                $fr=70 + ($diff1*2.5);
            }
            if ($diff>20) {
                $ans=['Too big bust size','Too big bust size','Too big bust size','Too big bust size','Too big bust size'];
            }else{
                $ans=$sizes[$diff];
            }

          $this->param['band'] = $band;
          $this->param['aus'] = $aus;
          $this->param['ans'] = $ans;
          $this->param['eu'] = $eu;
          $this->param['fr'] = $fr;
          $this->param['RESULT'] = 1;
          return $this->param;
      }else{
          $this->param['error'] = 'Please Check Your Input.';
          return $this->param;
      }
    }

	// Body Surface Area Calculator
	public function bsa($request){
        // dd($request->all());
		if (is_numeric($request->weight) && is_numeric($request->{'height-ft'}) || is_numeric($request->{'height-in'}) || is_numeric($request->{'height-cm'})) {
			$height_ft=$request->{'height-ft'};
			$height_in=$request->{'height-in'};
			$height_cm=$request->{'height-cm'};
			$weight=$request->weight;
			if ($request->unit==="lbs") {
				$weight = $weight / 2.205;
			}
			if ($request->unit_ft_in==='ft/in') {
				$height_cm=$height_ft * 30.48;
				if ($height_in!=null) {
					$height_in= $height_in * 2.54;
					$height_cm=$height_cm + $height_in;
				}
			}
			$DuBois=round(0.007184 * pow($weight,0.425) * pow($height_cm,0.725),2);
			$Mosteller=round(0.016667 * pow($weight,0.5) * pow($height_cm,0.5),2);
			$Haycock =round(0.024265 * pow($weight,0.5378 ) * pow($height_cm,0.3964),2);
			$Gehan =round(0.0235 * pow($weight,0.51456) * pow($height_cm,0.42246),2);
			$Boyd =round(0.03330 * pow($weight,(0.6157 - 0.0188 * log10($weight))) * pow($height_cm,0.3),2);
			$Fujimoto =round(0.008883 * pow($weight,0.444) * pow($height_cm,0.663),2);
			$Takahira =round(0.007241 * pow($weight,0.425) * pow($height_cm,0.725),2);
			if ($request->gender==="Male") {
				$Schlich =round(0.000579479 * pow($weight,0.38) * pow($height_cm,1.24),2);
			} else {
				$Schlich =round(0.000975482 * pow($weight,0.46) * pow($height_cm,1.08),2);
			}
			$this->param['DuBois'] = $DuBois;
			$this->param['Mosteller'] = $Mosteller;
			$this->param['Haycock'] = $Haycock;
			$this->param['Gehan'] = $Gehan;
			$this->param['Boyd'] = $Boyd;
			$this->param['Fujimoto'] = $Fujimoto;
			$this->param['Takahira'] = $Takahira;
			$this->param['Schlich'] = $Schlich;
			$this->param['RESULT'] = 1;
            return $this->param;
		}else{
            $this->param['error'] = 'Please fill all fields.';
            return $this->param;
		}
	}

    // Carboplatin Calculator
    public function carboplatin($request){
        //  dd($request->all());
        $type = $request->type;
        $operations = $request->operations;
        $first = $request->first;
        $second = $request->second;
        $s_units = $request->s_units;
        $third = $request->third;
        $t_units = $request->t_units;
        $four = $request->four;
        $five = $request->five;
        $f_units = $request->f_units;


        if($s_units == 'kg'){
            $s_units = 1;
        }else if($s_units == 'lbs'){
            $s_units = 2;
        }else if($s_units == 'stone'){
            $s_units = 3;
        }


        if($t_units == 'mg/dL'){
            $t_units = 1;
        }else if($t_units == 'μmol/L'){
            $t_units = 2;
        }


        if($f_units == 'in'){
            $f_units = 1;
        }else if($f_units == 'cm'){
            $f_units = 2;
        }


		function baby($a,$b){
			if($a=="1"){
				$lve = $b * 1;
			}elseif ($a=="2") {
				$lve = $b * 0.011312;
			}
			return $lve;
		}
		function baby2($a,$b){
			if($a=="1"){
				$lve = $b * 88.4;
			}elseif ($a=="2") {
				$lve = $b * 1;
			}
			return $lve;
		}
		function wazan($a,$b){
			if($a=="1"){
				$kanda = $b * 1;
			}elseif ($a=="2") {
				$kanda = $b * 0.4536;
			}elseif ($a=="3") {
				$kanda = $b * 6.35;
			}
			return $kanda;
		}
		function kad($a,$b){
			if($a == "1"){
				$len = $b * 2.54;
			}elseif ($a == "2") {
				$len = $b * 1;
			}
			return $len;
		}
		function kad2($a,$b){
			if($a == "1"){
				$len2 = $b * 1;
			}elseif ($a == "2") {
				$len2 = $b / 2.54;
			}
			return $len2;
		}
		$five2 = $five;
		$f_units2 = $f_units;
		$third2 = $third;
		$t_units2 = $t_units;
		$third = baby($t_units,$third);
		$second = wazan($s_units,$second);
		$five = kad($f_units,$five);
		$five2 = kad2($f_units2,$five2);
		$third2 = baby2($t_units2,$third2);
		if ($type == "first") {
			if ($first >= 18) {
				$batien = 140 - $first;
				$divi = 72 * $third;
				$dosra = $second / $divi;
				$grf = $batien * $dosra;
				if ($operations == "1") {
					$answer = $grf;
				}else if ($operations == "2") {
					$answer = 0.85 * $grf;
				}
				$max_dos = $four * 150;
				$car_dos = $four * ($answer + 25);
			}else{
                $this->param['error'] = 'This calculator should not be used in patients <18 years old.';
                return $this->param;
	    	}
	    	$this->param['answer'] = $answer;
	        $this->param['max_dos'] = $max_dos;
	        $this->param['car_dos'] = $car_dos;
		}else if ($type == "second") {
			if ($first >= 18) {
				if (is_numeric($second)) {
					if (is_numeric($third)) {
						if (is_numeric($five)) {
							$second_pow = pow($second, 0.425);
							$five_pow = pow($five, 0.725);
							$bsa = 0.007184 * $second_pow * $five_pow;
							if ($operations == 1) {
								$minus = $five2 - 60;
								$multi = 2.3 * $minus;
								$ibw = 50 + $multi;
								// abw and abw alt answer
								$minus2 = $second - $ibw;
								$multi2 = 0.4 * $minus2;
								$abw = $ibw + $multi2;
								$multi3 = 0.3 * $minus2;
								$abw_alt = $ibw + $multi3;
								// jellife first  (ml/min)
								$minus1 = $first - 20;
								$mul1 = 0.8 * $minus1;
								$minus11 = 98 - $mul1;
								$jell_ans1 = $minus11 / $third;
								$jell_ans11 = ($jell_ans1 + 25) * $four;

								// jellife second   (ml/min)
								$bsa_div = $bsa / 1.73;
								$up_sol = $minus11 * $bsa_div;
								$div_sol = $third2 * 0.0113;
								$jell_ans2 = $up_sol / $div_sol;
								$jell_ans22 = ($jell_ans2 + 25) * $four;

								// Cockcroft & Gault actual body weight (ml/min)
								$cg_minus = 140 - 22;
								$cgup_mul = $second * $cg_minus;
								$cglo_mul = 72 * $third;
								$cg_ac_ans = $cgup_mul / $cglo_mul;
								$cg_ac_ans2 = ($cg_ac_ans + 25) * $four;

								// Cockcroft & Gault ideal body weight (ml/min)
								$cgup_mul1 = $ibw * $cg_minus;
								$cg_ibw_ans = $cgup_mul1 / $cglo_mul;
								$cg_ibw_ans2 = ($cg_ibw_ans + 25) * $four;

								// Cockcroft & Gault adjusted body weight (ml/min)
								$cgup_mul2 = $abw * $cg_minus;
								$cg_abw_ans = $cgup_mul2 / $cglo_mul;
								$cg_abw_ans2 = ($cg_abw_ans + 25) * $four;

								// Cockcroft & Gault adjusted body weight alt (ml/min)
								$cgup_mul3 = $abw_alt * $cg_minus;
								$cg_abwalt_ans = $cgup_mul3 / $cglo_mul;
								$cg_abwalt_ans2 = ($cg_abwalt_ans + 25) * $four;
							}else if ($operations == 2) {
								$minus = $five2 - 60;
								$multi = 2.3 * $minus;
								$ibw = 45.5 + $multi;
								// abw and abw alt answer
								$minus2 = $second - $ibw;
								$multi2 = 0.4 * $minus2;
								$abw = $ibw + $multi2;
								$multi3 = 0.3 * $minus2;
								$abw_alt = $ibw + $multi3;
								// jellife first  (ml/min)
								$minus1 = $first - 20;
								$mul1 = 0.8 * $minus1;
								$minus11 = 98 - $mul1;
								$female_jell = $minus11 / $third;
								$jell_ans1 = $female_jell * 0.9;
								$jell_ans11 = ($jell_ans1 + 25) * $four;

								// jellife second  (ml/min)
								$bsa_div = $bsa / 1.73;
								$up_sol = $minus11 * $bsa_div * 0.9;
								$div_sol = $third2 * 0.0113;
								$jell_ans2 = $up_sol / $div_sol;
								$jell_ans22 = ($jell_ans2 + 25) * $four;

								// Cockcroft & Gault actual body weight (ml/min)
								$cg_minus = 140 - 22;
								$cgup_mul = $second * $cg_minus;
								$cglo_mul = 72 * $third;
								$cg_female = $cgup_mul / $cglo_mul;
								$cg_ac_ans = $cg_female * 0.85;
								$cg_ac_ans2 = ($cg_ac_ans + 25) * $four;

								// Cockcroft & Gault ideal body weight (ml/min)
								$cgup_mul1 = $ibw * $cg_minus;
								$cg_ibw_fe = $cgup_mul1 / $cglo_mul;
								$cg_ibw_ans = $cg_ibw_fe * 0.85;
								$cg_ibw_ans2 = ($cg_ibw_ans + 25) * $four;

								// Cockcroft & Gault adjusted body weight (ml/min)
								$cgup_mul2 = $abw * $cg_minus;
								$cg_abw_fe = $cgup_mul2 / $cglo_mul;
								$cg_abw_ans = $cg_abw_fe * 0.85;
								$cg_abw_ans2 = ($cg_abw_ans + 25) * $four;

								// Cockcroft & Gault adjusted body weight alt (ml/min)
								$cgup_mul3 = $abw_alt * $cg_minus;
								$cg_abwalt_fe = $cgup_mul3 / $cglo_mul;
								$cg_abwalt_ans = $cg_abwalt_fe * 0.85;
								$cg_abwalt_ans2 = ($cg_abwalt_ans + 25) * $four;
							}
							// answers
							$bsa = round($bsa, 2);
							$this->param['bsa'] = $bsa;
					        $this->param['ibw'] = $ibw;
					        $this->param['abw'] = $abw;
					        $this->param['abw_alt'] = $abw_alt;
					        $this->param['jell_ans1'] = $jell_ans1;
					        $this->param['jell_ans2'] = $jell_ans2;
					        $this->param['cg_ac_ans'] = $cg_ac_ans;
					        $this->param['cg_ibw_ans'] = $cg_ibw_ans;
					        $this->param['cg_abw_ans'] = $cg_abw_ans;
					        $this->param['cg_abwalt_ans'] = $cg_abwalt_ans;
					        $this->param['jell_ans11'] = $jell_ans11;
					        $this->param['jell_ans22'] = $jell_ans22;
					        $this->param['cg_ac_ans2'] = $cg_ac_ans2;
					        $this->param['cg_ibw_ans2'] = $cg_ibw_ans2;
					        $this->param['cg_abw_ans2'] = $cg_abw_ans2;
					        $this->param['cg_abwalt_ans2'] = $cg_abwalt_ans2;
						}else{
                            $this->param['error'] = 'Please check your input.';
                            return $this->param;
						}
					}else{
                        $this->param['error'] = 'Please check your input.';
                        return $this->param;
					}
				}else{
                    $this->param['error'] = 'Please check your input.';
                    return $this->param;
				}
			}else{
                $this->param['error'] = 'This calculator should not be used in patients <18 years old.';
                return $this->param;
	    	}	
		}
        $this->param['RESULT'] = 1;
        $this->param['request'] = $request;
        return $this->param;
    }

	// Corrected Calcium Calculator
	public function corrected($request){
		if(is_numeric($request->calcium) && is_numeric($request->albumin) && is_numeric($request->normal)){
			$calcium=$request->calcium;
			$albumin=$request->albumin;
			$normal=$request->normal;
			if ($request->unit_c==='mmol/l') {
				$calcium=$calcium * 4.00;
			}
			if ($request->unit_a==='g/L') {
				$albumin=$albumin * 0.10;
			}
			if ($request->unit_n==='g/L') {
				$normal=$normal * 0.10;
			}
			$Calcium_res = round(((0.8 * ($normal - $albumin)) + $calcium),1);
			if ($request->unit_c=='mmol/l') {
				$Calcium_res=($Calcium_res / 4.00);
			}
			$this->param['Calcium_res'] = $Calcium_res;
			$this->param['request'] = $request;
			$this->param['RESULT'] = 1;
			return $this->param;
		}else{
            $this->param['error'] = 'Please fill all fields.';
            return $this->param;
		}
	}

