    // Dosage Calculator
	public function dosage($request){
        // dd($request->all());
		$w=$request->w;
		$w1=$request->w1;
		$d=$request->d;
		$d1=$request->d1;
		$f=$request->f;
		$mc=$request->mc;
		$mc1=$request->mc1;

        if($mc1 == 'g/L'){
            $mc1 = 'gl';
        }else if($mc1 == 'mg/mL'){
            $mc1 = 'mgl';
        }else if($mc1 == 'µg/L'){
            $mc1 = 'ugl';
        }else if($mc1 == 'mg/mL'){
            $mc1 = 'mg-ml';
        }else if($mc1 == 'µg/mL'){
            $mc1 = 'ug-ml';
        }

        if($d1 == 'µg/kg'){
            $d1 = 'u-kg';
        }else if($d1 == 'mg/kg'){
            $d1 = 'mg-kg';
        }else if($d1 == 'g/kg'){
            $d1 = 'g-kg';
        }
        if($w1 == 'kg'){
            $w1 = 'kg';
        }else if($w1 == 'lbs'){
            $w1 = 'lb';
        }
     

		if(is_numeric($w) && is_numeric($d)){
			if($w1=='lb'){
				$w=$w/2.205;
			}
			if($d1=='u-kg'){
				$d=$d/1000;
			}
			if($d1=='g-kg'){
				$d=$d*1000;
			}
			if($mc1=='mgl' || $mc1=='ug-ml'){
				$mc=$mc/1000;
			}
			if($mc1=='ugl'){
				$mc=$mc/1000000;
			}
			$tdose=$w*$d;
			$gr=$tdose/1000;
			$ug=$tdose*1000;
			if($f!=1){
				if($f=='4h'){
					$dose=$tdose/6;
				}elseif($f=='3h'){
					$dose=$tdose/8;
				}elseif($f=='2h'){
					$dose=$tdose/12;
				}elseif($f=='h'){
					$dose=$tdose/24;
				}else{
					$dose=$tdose/$f;
				}
				$this->param['dose'] = $dose;
			}
			if(is_numeric($mc)){
				$lq_dose=$tdose/$mc;
				$g=$lq_dose/1000;
				$this->param['lq_dose'] = round($lq_dose,2);
				$this->param['g'] = round($g,2);
				if($f!=1){
					$lq_dose1=$dose/$mc;
					$this->param['lq_dose1'] = round($lq_dose1,2);
				}
			}
			$this->param['tdose'] = round($tdose,1);
			$this->param['ug'] = round($ug,2);
			$this->param['gr'] = round($gr,2);
			$this->param['RESULT'] = 1;
			return $this->param;
		}else{
            $this->param['error'] = 'Please fill all fields.';
            return $this->param;
		}
	}

    // HCG Calculator
    public function hcg($request){
        // dd($request->all());
        $first = $request->first;
        $second = $request->second;
        $third = $request->third;
        $unit3 = $request->unit3;

		function din($a,$b){
			if($a == "hours"){
				$aja = $b * 0.04167;
			}elseif ($a == "days") {
				$aja = $b * 1;
			}
			return $aja;
		}
        
		$third = din($unit3,$third);
		if (is_numeric($first) && is_numeric($second) && is_numeric($third)) {
			$difference = $second - $first;
			$pos = abs($difference);
			$div1 = $pos / $first;
			$percent = $div1 * 100;
			$div2 = $second / $first;
			$log = log($div2, 2);
			$t2 = $third / $log;
			$hours = $t2 * 24;
			$f_div = 24 / $hours;
			$s_div = 48 / $hours;
			$f_pow = pow(2, $f_div);
			$s_pow = pow(2, $s_div);
			$f_min = $f_pow - 1;
			$s_min = $s_pow - 1;
			$i1 = $f_min * 100;
			$i2 = $s_min * 100;
		}else{
            $this->param['error'] = 'Please! check your input.';
            return $this->param;
		}		        
		$this->param['difference'] = $difference;
		$this->param['percent'] = $percent;
		$this->param['t2'] = $t2;
		$this->param['i1'] = $i1;
		$this->param['i2'] = $i2;
        $this->param['RESULT'] = 1;
        return $this->param;
    }

    // Ideal Body Weight Calculator
	public function ideal($request){
        // dd($request->all());
        $hidden_nameunit =$request->hidden_nameunit ?? 'cm';
		if (is_numeric($request->age) && is_numeric($request->weight) && is_numeric($request->{'height-ft'}) || is_numeric($request->{'height-in'}) || is_numeric($request->{'height-cm'})) {
			$age=$request->age;
			$hidden_nameunit=$request->{'hidden_nameunit'} ?? 'cm';
			$height_ft=$request->{'height-ft'};
			$height_in=$request->{'height-in'};
			$height_cm=$request->{'height-cm'};
			if ($request->unit_ft_in==='ft/in') {
				$height_cm=$height_ft * 30.48;
				if ($height_in!=null) {
					$height_in= $height_in * 2.54;
					$height_cm=$height_cm + $height_in;
				}
			}
			// cm to inches
			$height_in=$height_cm / 2.54;
			$weight_kg=$request->weight;
			if ($request->unit==='lbs') {
				$weight_kg=($request->weight / 2.205);
			}
			// inches to meters
			$height_meters=$height_in / 39.37;
			if ($request->gender==='Female') {
				if ($height_in < 60) {
					$Intuitive=round(45.5 - (2.3*(60 - $height_in)),2);
					$Baseline=round(45.5 - (0.758*(60 - $height_in)),2);
					$this->param['Intuitive'] = $Intuitive;
					$this->param['Baseline'] = $Baseline;
					$ans=round(45.5 - (0.758*(60 - $height_in)),2);
				}else{
					$Robinson=round(49 + (1.7 * ($height_in - 60)),2);
					$Miller=round(53.1 + (1.36 * ($height_in - 60)),2);
					$ans=round(45.5 + (2.3 * ($height_in - 60)),2);
					$Devine=round(45.5 + (2.3 * ($height_in - 60)),2);
					$Hamwi=round(45 + (2.2 * ($height_in - 60)),2);
					$Broca=round(($height_cm - 100) - (($height_cm - 100) * (15/100)),2);
					$Lorentz=round(($height_cm-100) - (($height_cm - 150)/2),2);
					$Peterson=round((2.2 * 22) + ((3.5 * 22) * ($height_meters - 1.5)),2);
					$Lemmens= round(22 * pow($height_meters, 2),2);
					$BMI_Method= round(25 * ($height_meters * $height_meters),2);
					$this->param['Robinson'] = $Robinson;
					$this->param['Miller'] = $Miller;
					$this->param['Devine'] = $Devine;
					$this->param['Hamwi'] = $Hamwi;
					$this->param['Broca'] = $Broca;
					$this->param['Lorentz'] = $Lorentz;
					$this->param['Peterson'] = $Peterson;
					$this->param['Lemmens'] = $Lemmens;
					$this->param['BMI_Method'] = $BMI_Method;
				}
			} else {
				if ($height_in < 60) {
					$Intuitive=round(50 - (2.3*(60 - $height_in)),2);
					$Baseline=round(50 - (0.833*(60 - $height_in)),2);
					$this->param['Intuitive'] = $Intuitive;
					$this->param['Baseline'] = $Baseline;
					$ans=round(50 - (0.833*(60 - $height_in)),2);
				}else{
					$Robinson=round(52 + (1.9 * ($height_in - 60)),2);
					$Miller=round(56.2 + (1.41 * ($height_in - 60)),2);
					$ans=round(50 + (2.3 * ($height_in - 60)),2);
					$Devine=round(50 + (2.3 * ($height_in - 60)),2);
					$Hamwi=round(48 + (2.7 * ($height_in - 60)),2);
					$Broca=round(($height_cm - 100) - (($height_cm - 100) * (10/100)),2);
					$Lorentz=round(($height_cm-100) - (($height_cm - 150)/4),2);
					$Peterson=round((2.2 * 22) + ((3.5 * 22) * ($height_meters - 1.5)),2);
					$Lemmens= round(22 * pow($height_meters, 2),2);
					$BMI_Method= round(25 * ($height_meters * $height_meters),2);
					$this->param['Robinson'] = $Robinson;
					$this->param['Miller'] = $Miller;
					$this->param['Devine'] = $Devine;
					$this->param['Hamwi'] = $Hamwi;
					$this->param['Broca'] = $Broca;
					$this->param['Lorentz'] = $Lorentz;
					$this->param['Peterson'] = $Peterson;
					$this->param['Lemmens'] = $Lemmens;
					$this->param['BMI_Method'] = $BMI_Method;
				}
			}
			$bmi_range1= round(18.5 * ($height_meters * $height_meters),2);
			$bmi_range2= round(25 * ($height_meters * $height_meters),2);
           
			if ($request->unit==='kg') {
				$bsa=round(0.007184 * pow($request->weight,0.425) * pow($height_cm,0.725),2);
				$abw=$ans + (0.4 * ($request->weight-$ans)).' kg';
				$Percent=round((($request->weight - $ans) / $ans) * 100,2).' %';
				$bmi= round($request->weight / pow($height_meters, 2),2);
			}else{
				$bsa=round(0.007184 * pow(($request->weight/2.205),0.425) * pow($height_cm,0.725),2);
				$abw=($ans * 2.205) + (0.4 * ($request->weight - ($ans * 2.205))).' lbs';
				$Percent=round((($request->weight - ($ans*2.205)) / ($ans*2.205)) * 100,2).' %';
               
				$bmi= round(($request->weight / 2.205) / pow($height_meters, 2),2);
                // dd($bmi);
			}
			if ($request->gender==='Female') {
				$lbw=round((9270 * $weight_kg) / (8780 + (244*$bmi)),2);
			}else{
				$lbw=round((9270 * $weight_kg) / (6680 + (216*$bmi)),2);
			}
			// return 
			if ($request->unit==='kg') {
				$this->param['ans'] = "$ans <span class='text-blue font-s-20'>kg</span>";
				$this->param['lbw'] = "$lbw kg";
			}else{
				$this->param['ans'] = round($ans * 2.205,2)." <span class='text-blue font-s-20'>lbs</span>";
				$this->param['lbw'] = round($lbw * 2.205,2)." lbs";
			}
			$this->param['abw'] = $abw;
			$this->param['hidden_nameunit'] = $hidden_nameunit;
			$this->param['Percent'] = $Percent;
			$this->param['bmi'] = $bmi." kg/m<sup>2</sup>";
			$this->param['bsa'] = $bsa." M<sup>2</sup>";
			$this->param['BMI1'] = $bmi_range1." - ".$bmi_range2." kg";
			$this->param['BMI2'] = round($bmi_range1 * 2.205,2)." - ".round($bmi_range2 * 2.205,2)." lbs";
			$this->param['RESULT'] = 1;
			return $this->param;
		} else {
			$this->param['hidden_nameunit'] = $hidden_nameunit;
            $this->param['error'] = 'Please Fill All fields.';
			return $this->param;
		}
	}

