                <td colspan="3" class="text-center border-2 radius-t-10 px-3 py-2">
                    Ovulation Date: "'.$date.'"
                </td>
            </tr>
            <tr class="">
                <td class="radius-bl-10 px-3 py-2">Days Past Ovulation (DPO)</td>
                <td class="px-3">Date</td>
                <td class="radius-br-10 px-3">Probability of Implantation</td>
            </tr>
        </thead>
        <tbody>';
        for($i=0; $i < 17; $i++){
          $imp_date=date('M d, Y', strtotime($date." + $i day"));
          if($i===0){
            $cmnt="Ovulation";
            $clr="clr_0";
          }elseif($i>0 && $i<6){
            $cmnt="Travel inside Fallopian tube";
            $clr="clr_1";
          }elseif($i>5 && $i<9 || $i>9 && $i<13){
            $cmnt="Implantation possible";
            $clr="clr_2";
          }elseif($i===9){
            $cmnt="Implantation very possible";
            $clr="clr_3";
          }elseif($i>12 && $i<15){
            $cmnt="Implantation unlikely";
            $clr="clr_1";
          }else{
            $cmnt="Missed Period: Pregnancy Test?";
            $clr="clr_4";
          }
          $border = '';
          if($i < 16){
            $border = 'border-b';
          }
          $table.="<tr class='$clr'><th class='text-start $border px-3 py-3'>$i DPO</th><td class='$border px-3'>$imp_date</td><td class='$border px-3'>$cmnt</td></tr>";
        }
        $table.="</tbody></table>";
        if(!empty($ivf)){
          $date=date('M d, Y', strtotime($ivf));
          $imp_date=date('M d, Y', strtotime($date." + 5 day"));
          $this->param['ivf'] = $imp_date;
        }
        $this->param['table'] = $table;
        $this->param['RESULT'] = 1;
        return $this->param;
    }

