    // Lean Body Mass Calculator
	public function lean($request){
        // dd($request->all());
		if (is_numeric($request->weight) && (is_numeric($request->{'height-ft'}) || is_numeric($request->{'height-in'}) || is_numeric($request->{'height-cm'}))) {
			$height_ft=$request->{'height-ft'};
			$height_in=$request->{'height-in'};
			$height_cm=$request->{'height-cm'};
			$weight=$request->weight;
			if ($request->unit==="lbs") {
				$weight = $weight / 2.205;
			}
			if ($request->unit_ft_in==='ft/in') {
				$height_cm=$height_ft * 30.48;
				if ($height_in!=null) {
					$height_in= $height_in * 2.54;
					$height_cm=$height_cm + $height_in;
				}
			}
			if ($request->gender==='Female') {
				$Boer=round((0.252 * $weight) + (0.473 * $height_cm) - 48.3,2);
				$Boer_per=round(($Boer / $weight)*100,2);
				$James= round((1.07 * $weight) - 148 * pow(($weight / $height_cm ),2),2);
				$James_per=round(($James / $weight)*100,2);
				$Hume=round((0.29569 * $weight) + (0.41813 * $height_cm) - 43.2933,2);
				$Hume_per=round(($Hume / $weight)*100,2);
			} else {
				$Boer=round((0.407 * $weight) + (0.267 * $height_cm) - 19.2,2);
				$Boer_per=round(($Boer / $weight)*100,2);
				$James= round((1.1 * $weight) - 128 * pow(($weight / $height_cm ),2),2);
				$James_per=round(($James / $weight)*100,2);
				$Hume=round((0.32810 * $weight) + (0.33929 * $height_cm) - 29.5336,2);
				$Hume_per=round(($Hume / $weight)*100,2);
			}
			$Peters=round(0.0817 * (pow(($weight),0.6469) * pow(($height_cm),0.7236)),2);
			$Peters_per=round(($Peters / $weight)*100,2);
			if ($request->unit==="lbs") {
				$Boer = round($Boer * 2.205,2);
				$James = round($James * 2.205,2);
				$Hume = round($Hume * 2.205,2);
				$Peters = round($Peters * 2.205,2);
			}
			if ($request->formula==='Boer') {
				$this->param['Boer_f'] = "bg-gradient text-white";
				$ans=$Boer;
				$ans_per=$Boer_per;
			}
			if ($request->formula==='James') {
				$this->param['James_f'] = "bg-gradient text-white";
				$ans=$James;
				$ans_per=$James_per;
			}
			if ($request->formula==='Hume') {
				$this->param['Hume_f'] = "bg-gradient text-white";
				$ans=$Hume;
				$ans_per=$Hume_per;
			}
			if ($request->formula==='Peters') {
				$this->param['Peters_f'] = "bg-gradient text-white";
				$ans=$Peters;
				$ans_per=$Peters_per;
			}
			$this->param['Boer'] = $Boer." ".$request->unit;
			$this->param['Boer_per'] = $Boer_per;
			$this->param['ans_per'] = $ans_per;
			$this->param['ans'] = $ans;
			$this->param['James'] = $James." ".$request->unit;
			$this->param['James_per'] = $James_per;
			$this->param['Hume'] = $Hume." ".$request->unit;
			$this->param['Hume_per'] = $Hume_per;
			$this->param['Peters'] = $Peters." ".$request->unit;
			$this->param['Peters_per'] = $Peters_per;
			$this->param['RESULT'] = 1;
            return $this->param;
			
		} else {
            $this->param['error'] = 'Please Fill All Fields.';
            return $this->param;
		}
	}

	// Meal Calorie Calculator
	public function meal($request){
		if (is_numeric($request->calorie)) {
			$meal=$request->meals;
			$calorie=$request->calorie;
			if ($meal==='3') {
				$b_f=round((32.5/100) * $calorie);
				$lanch=round((37.5/100) * $calorie);
				$dinner=round((30/100) * $calorie);
				$this->param['b_f'] = $b_f;
				$this->param['lanch'] = $lanch;
				$this->param['dinner'] = $dinner;
				$this->param['RESULT'] = 1;
                return $this->param;
			}
			if ($meal==='4') {
				$b_f=round((27.5/100) * $calorie);
				$m_s=round((7.5/100) * $calorie);
				$lanch=round((37.5/100) * $calorie);
				$dinner=round((27.5/100) * $calorie);
				$this->param['b_f'] = $b_f;
				$this->param['m_s'] = $m_s;
				$this->param['lanch'] = $lanch;
				$this->param['dinner'] = $dinner;
				$this->param['RESULT'] = 1;
                return $this->param;
			}if ($meal==='5') {
				$b_f=round((27.5/100) * $calorie);
				$m_s=round((7.5/100) * $calorie);
				$lanch=round((37.5/100) * $calorie);
				$a_n=round((7.5/100) * $calorie);
				$dinner=round((27.5/100) * $calorie);
				$this->param['b_f'] = $b_f;
				$this->param['m_s'] = $m_s;
				$this->param['lanch'] = $lanch;
				$this->param['a_n'] = $a_n;
				$this->param['dinner'] = $dinner;
				$this->param['RESULT'] = 1;
                return $this->param;
			}
		} else {
            $this->param['error'] = 'Please Fill All Fields.';
            return $this->param;
		}
		
	}

    // Amoxicillin Pediatric Dosage Calculator
	public function amoxicillin($request){
        // dd($request->all());
        
        $age=$request->age;
        $age_unit=$request->age_unit;
        $weight=$request->weight;
        $weight_unit=$request->weight_unit;
        $med_type=$request->med_type;
        $general_dosing=$request->general_dosing;
        $route=$request->route;
        $dosag=$request->dosag;


        if($age_unit == 'Weeks'){
            $age_unit = 0.019165;
        }else if($age_unit == 'Months'){
            $age_unit = 0.08333;
        }else if($age_unit == 'Years'){
            $age_unit = 1;
        }

       if($weight_unit == 'kg'){
            $weight_unit = 1;
        }else if($weight_unit == 'lbs'){
            $weight_unit = 0.453592;
        }else if($weight_unit == 'stone'){
            $weight_unit = 6.35;
        }


		if(is_numeric($weight)){
		  $w_val=$weight*$weight_unit;
			if($age!=""){
				if(is_numeric($age)){
					$age_val=$age*$age_unit;
					if($age_val<=0 || $age_val>18){
                        $this->param['error'] = 'Please Enter Age Between 1 and 18.';
                        return $this->param;
					}
				}else{
                    $this->param['error'] = 'Please! Check your input.';
                    return $this->param;
				}
			}
			if($weight<=0){
                $this->param['error'] = 'Weight must be greater than 0.';
                return $this->param;
			}else if($weight>=100){
                $this->param['error'] = 'Weight cannot exceed 100 kg (220 lb).';
                return $this->param;
			}else{
				if($general_dosing=="1"){
					$in_mm=$w_val*15;
					if($med_type=="1"){
						$in_milli=$in_mm/25;
					}else if($med_type=="2"){
						$in_milli=$in_mm/50;
					}else if($med_type=="3"){
						$in_milli=$in_mm/40;
					}else if($med_type=="4"){
						$in_milli=$in_mm/80;
					}
					if($route=="1"){
						$in_mm=$in_mm;
						$in_milli=$in_milli;
					}else if($route=="2"){
						$in_mm=$in_mm*2;
						$in_milli=$in_milli*2;
					}
				}else if($general_dosing=="2"){
					if($w_val<15){
						$in_mm=$w_val*50;
						$in_milli=$in_mm/25;
					}else if($w_val>=15 && $weight<30){
						$in_mm=750;
						$in_milli=$in_mm/25;
					}else if($weight>=30 && $weight<100){
						$in_mm=1000;
						$in_milli=$in_mm/25;
					}
					if($med_type=="2"){
						$in_milli=$in_mm/50;
					}else if($med_type=="3"){
						$in_milli=$in_mm/40;
					}else if($med_type=="4"){
						$in_milli=$in_mm/80;
					}
				}else if($general_dosing=="3"){
					$in_mm=$w_val*50;
					if($med_type=="1"){
						$in_milli=$in_mm/25;
					}else if($med_type=="2"){
						$in_milli=$in_mm/50;
					}else if($med_type=="3"){
						$in_milli=$in_mm/40;
					}else if($med_type=="4"){
						$in_milli=$in_mm/80;
					}
				}
			}
		}else{
            $this->param['error'] = 'Please! Check your input.';
            return $this->param;
		}
		$this->param['in_mm']=$in_mm;
		$this->param['in_milli']=$in_milli;
		$this->param['general_dosing']=$general_dosing;
		$this->param['route']=$route;
		$this->param['dosag']=$dosag;
		$this->param['w_val']=$w_val;
		$this->param['RESULT'] = 1;
        return $this->param;
	}

