    // Benadryl for Dogs Calculator
	public function benadryl($request){
        $w=$request->w;
        $w_unit=$request->w_unit;

		if(is_numeric($w)){
			if($w<0){
                $this->param['error'] = "Your dog's weight must be greater than 0 🐕.";
                return $this->param;
			}else{
				$w_val=$w*$w_unit;
				$bd=$w_val*1;
				$liquid=$w_val/2.5;
				$this->param['bd']=$bd;
				$this->param['liquid']=$liquid;
				$this->param['RESULT'] = 1;
                return $this->param;
			}
		}else{
            $this->param['error'] = 'Please! Check your input.';
            return $this->param;
		}
	}

    // BUN Creatinine Ratio Calculator
    public function bun($request){
        $bun=$request->bun;
        $bun_unit=$request->bun_unit;
        $serum=$request->serum;
        $serum_unit=$request->serum_unit;

        if($bun_unit == 'mg/dL'){
            $bun_unit = 1;
        }else if($bun_unit == 'mmol/L'){
        $bun_unit = 2.778;
        }

        if($serum_unit == 'mg/dL'){
            $serum_unit = 1;
        }else if($serum_unit == 'μmol/L'){
        $serum_unit = 0.011312;
        }

		if(is_numeric($bun) && is_numeric($serum)){
			if($bun>0 && $serum>0){
				$bv=$bun*$bun_unit;
				$sv=$serum*$serum_unit;
				$ans=$bv/$sv;
				$this->param['ans']=$ans;
				$this->param['RESULT'] = 1;
                return $this->param;
			}else{
                $this->param['error'] = 'Please! Enter Positive Value.';
                return $this->param;
			}
		}else{
            $this->param['error'] = 'Please! Check your input.';
            return $this->param;
		}
	}

