		function power($a,$b){
			if($a=="1"){
				$waqat = $b / 1000;
			}elseif ($a=="2") {
				$waqat = $b * 1;
			}elseif ($a=="3") {
				$waqat = $b * 1000;
			}elseif ($a=="4") {
				$waqat = $b * 0.2931;
			}elseif ($a=="5") {
				$waqat = $b * 745.7;
			}elseif ($a=="6") {
				$waqat = $b * 69.73;
			}elseif ($a=="7") {
				$waqat = $b * 1.1622;
			}
			return $waqat;
		}
		function time2($a,$b){
			if($a=="1"){
				$waqat = $b / 3600;
			}elseif ($a=="2") {
				$waqat = $b / 60;
			}elseif ($a=="3") {
				$waqat = $b * 1;
			}elseif ($a=="4") {
				$waqat = $b * 16;
			}
			return $waqat;
		}
		function weight($a,$b){
			if($a=="1"){
				$wazan = $b / 2.205;
			}elseif ($a=="2") {
				$wazan = $b * 1;
			}elseif ($a=="3") {
				$wazan = $b * 6.35;
			}
			return $wazan;
		}
		$first = power($units1,$first);
		$second = weight($units2,$second);
		$third = time2($units3,$third);
		if (is_numeric($second) || is_numeric($height_ft) || is_numeric($height_in) || is_numeric($height_cm)) {
			if ($unit_h==='ft/in') {
				$height_cm=$height_ft * 30.48;
				if ($height_in!=null) {
					$height_in= $height_in * 2.54;
					$height_cm=$height_cm + $height_in;
				}
			}elseif ($unit_h==='ft') {
				$height_cm = $height_cm * 30.48;
			}elseif ($unit_h==='in') {
				$height_cm = $height_cm * 2.54;
			}elseif ($unit_h==='cm') {
				$height_cm = $height_cm * 1;
			}elseif ($unit_h==='m') {
				$height_cm = $height_cm * 100;
			}
			if ($gender==='female') {
				$bmr_ans = round((665.1+(9.563*$second)+(1.850*$height_cm)-(4.676*$age)));
			}else{
				$bmr_ans = round((66.5+(13.75*$second)+(5.003* $height_cm)-(6.75*$age)));
			}
		}else{
            $this->param['error'] = 'Please! Check your input.';
            return $this->param;
    	}
		if ($operations == "Yes") {
			if (is_numeric($first) && is_numeric($third)) {
				$calories = (($first * $third) / 4.18) / 0.24;
				$w_loss = $calories / 7700;
			}else{
                $this->param['error'] = 'Please! Check your input.';
                return $this->param;
	    	}
		}elseif ($operations == "No") {
			if (is_numeric($second) && is_numeric($met) && is_numeric($third)) {
				$calories = $third * 60 * $met * 3.5 * $second / 200;
				$w_loss = $calories / 7700;
			}else{
                $this->param['error'] = 'Please! Check your input.';
                return $this->param;
	    	}	
		}
		$exercise = $met * $third;
		$this->param['bmr_ans'] = $bmr_ans;
		$this->param['calories'] = $calories;
        $this->param['w_loss'] = $w_loss;
        $this->param['exercise'] = $exercise;
        $this->param['RESULT'] = 1;
        return $this->param;
    }

    // Cholesterol Ratio Calculator
	public function cholesterol($request){
        // dd($request->all());
        $tc=$request->tc;
        $tc_unit=$request->tc_unit;
        $hc=$request->hc;
        $hc_unit=$request->hc_unit;
        $lc=$request->lc;
        $lc_unit=$request->lc_unit;
        $tr=$request->tr;
        $tr_unit=$request->tr_unit;
        $gender=$request->gender;


        if($tc_unit == 'mg/dL'){
            $tc_unit = 1;
        }else if($tc_unit == 'mmol/L'){
            $tc_unit = 38.67;
        }

        if($hc_unit == 'mg/dL'){
            $hc_unit = 1;
        }else if($hc_unit == 'mmol/L'){
            $hc_unit = 38.67;
        }

        if($lc_unit == 'mg/dL'){
            $lc_unit = 1;
        }else if($lc_unit == 'mmol/L'){
            $lc_unit = 38.67;
        }
        if($tr_unit == 'mg/dL'){
            $tr_unit = 1;
        }else if($tr_unit == 'mmol/L'){
            $tr_unit = 88.57;
        }
 

		if(is_numeric($tc) && is_numeric($hc) && is_numeric($lc)){
			if(empty($tr)){
				if($tc>0 && $hc>0 && $lc>0){
					$tc=$tc*$tc_unit;
					$lc=$lc*$lc_unit;
					$hc=$hc*$hc_unit;
					$ans1=$tc/$hc;
					$ans2=$lc/$hc;
					$ans3=$tc;
					$ans4=$hc;
					$ans5=$lc;
					$ans6=($tc-$hc-$lc)*5;	
				}else{
                    $this->param['error'] = 'Please! Enter Positive Value.';
                    return $this->param;
				}
			}else{
                $this->param['error'] = 'Please! Enter Only Three Values.';
                return $this->param;
			}
		}else if(is_numeric($tc) && is_numeric($hc) && is_numeric($tr)){
			if(empty($lc)){
				if($tc>0 && $hc>0 && $tr>0){
					$tc=$tc*$tc_unit;
					$tr=$tr*$tr_unit;
					$hc=$hc*$hc_unit;
					$ans1=$tc/$hc;
					$ans3=$tc;
					$ans4=$hc;
					$ans5=($tc-$hc-(0.2*$tr));
					$ans2=$ans5/$hc;
					$ans6=$tr;
				}else{
                    $this->param['error'] = 'Please! Enter Positive Value.';
                    return $this->param;
				}
			}else{
                $this->param['error'] = 'Please! Enter Only Three Values.';
                return $this->param;
			}
		}else if(is_numeric($hc) && is_numeric($lc) && is_numeric($tr)){
			if(empty($tc)){
				if($hc>0 && $lc>0 && $tr>0){
					$tr=$tr*$tr_unit;
					$lc=$lc*$lc_unit;
					$hc=$hc*$hc_unit;
					$ans3=$hc+$lc+(0.2*$tr);
					$ans1=$ans3/$hc;
					$ans2=$lc/$hc;
					$ans4=$hc;
					$ans5=$lc;
					$ans6=$tr;
				}else{
                    $this->param['error'] = 'Please! Enter Positive Value.';
                    return $this->param;
				}
			}else{
                $this->param['error'] = 'Please! Enter Only Three Values.';
                return $this->param;
			}
		}else if(is_numeric($tc) && is_numeric($tr) && is_numeric($lc)){
			if(empty($hc)){
				if($tc>0 && $tr>0 && $lc>0){
					$tc=$tc*$tc_unit;
					$tr=$tr*$tr_unit;
					$lc=$lc*$lc_unit;
					$ans3=$tc;
					$ans4=$tc-$lc-(0.2*$tr);
					$ans5=$lc;
					$ans6=$tr;
					$ans2=$lc/$ans4;
					$ans1=$tc/$ans4;
				}else{
                    $this->param['error'] = 'Please! Enter Only Three Values.';
                    return $this->param;
				}
			}else{
                $this->param['error'] = 'Please! Enter Only Three Values.';
                return $this->param;
			}
		}else{
            $this->param['error'] = 'Please! Check your input.';
            return $this->param;
		}
		$this->param['ans1']=$ans1;
		$this->param['ans2']=$ans2;
		$this->param['ans3']=$ans3;
		$this->param['ans4']=$ans4;
		$this->param['ans5']=$ans5;
		$this->param['ans6']=$ans6;
		$this->param['gender']=$gender;
		$this->param['RESULT'] = 1;
        return $this->param;
	}

