    // Dress Size Calculator
    function dress($request){
        // dd($request->all());
        $bust=$request->bust;
        $waist=$request->waist;
        $hips=$request->hips;
        function getUSSize($EuroSize) {
            if($EuroSize <= 30){
                return '00';
            }elseif($EuroSize <= 32){
                return '0';
            }elseif($EuroSize <= 34){
                return '2';
            }elseif($EuroSize <= 36){
                return '4';
            }elseif($EuroSize <= 38){
                return '6';
            }elseif($EuroSize <= 40){
                return '8';
            }elseif($EuroSize <= 42){
                return '10';
            }elseif($EuroSize <= 44){
                return '12';
            }elseif($EuroSize <= 46){
                return '14';
            }elseif($EuroSize <= 48){
                return '16';
            }elseif($EuroSize <= 50){
                return '18';
            }elseif($EuroSize <= 52){
                return '20';
            }elseif($EuroSize <= 54){
                return '22';
            }else{
                return 'Not strictly determined';
            }
        }
        function getUKSize($EuroSize) {
            if($EuroSize <= 30){
                return '2';
            }elseif($EuroSize <= 32){
                return '4';
            }elseif($EuroSize <= 34){
                return '6';
            }elseif($EuroSize <= 36){
                return '8';
            }elseif($EuroSize <= 38){
                return '10';
            }elseif($EuroSize <= 40){
                return '12';
            }elseif($EuroSize <= 42){
                return '14';
            }elseif($EuroSize <= 44){
                return '16';
            }elseif($EuroSize <= 46){
                return '18';
            }elseif($EuroSize <= 48){
                return '20';
            }elseif($EuroSize <= 50){
                return '22';
            }elseif($EuroSize <= 52){
                return '24';
            }elseif($EuroSize <= 54){
                return '26';
            }else{
                return 'Not strictly determined';
            }
        }
        function getInternationalSize($EuroSize) {
            if($EuroSize <= 30){
                return 'XXS';
            }elseif($EuroSize <= 32){
                return 'XS';
            }elseif($EuroSize <= 34){
                return 'XS';
            }elseif($EuroSize <= 36){
                return 'S';
            }elseif($EuroSize <= 38){
                return 'S';
            }elseif($EuroSize <= 40){
                return 'M';
            }elseif($EuroSize <= 42){
                return 'M';
            }elseif($EuroSize <= 44){
                return 'L';
            }elseif($EuroSize <= 46){
                return 'L';
            }elseif($EuroSize <= 48){
                return 'XL';
            }elseif($EuroSize <= 50){
                return 'XL';
            }elseif($EuroSize <= 52){
                return 'XXL';
            }elseif($EuroSize <= 54){
                return 'XXL';
            }else{
                return 'Not strictly determined';
            }
        }
        if(!empty($bust) && !empty($waist) && !empty($hips)){
            if ($bust == 30 && $waist == 30 && $hips == 30) {
                $usaSize = '00';
                $ukSize = '2';
                $euroSize = '30';
                $internationalSize = 'XXS';
            }elseif($bust == 32 && $waist == 32 && $hips == 32){
                $usaSize = '0';
                $ukSize = '4';
                $euroSize = '32';
                $internationalSize = 'XS';
            }elseif($bust == 34 && $waist == 34 && $hips == 34){
                $usaSize = '2';
                $ukSize = '6';
                $euroSize = '34';
                $internationalSize = 'XS';
            }elseif($bust == 36 && $waist == 36 && $hips == 36){
                $usaSize = '4';
                $ukSize = '8';
                $euroSize = '36';
                $internationalSize = 'S';
            }elseif($bust == 38 && $waist == 38 && $hips == 38){
                $usaSize = '6';
                $ukSize = '10';
                $euroSize = '38';
                $internationalSize = 'S';
            }elseif($bust == 40 && $waist == 40 && $hips == 40){
                $usaSize = '8';
                $ukSize = '12';
                $euroSize = '40';
                $internationalSize = 'M';
            }elseif($bust == 42 && $waist == 42 && $hips == 42){
                $usaSize = '10';
                $ukSize = '14';
                $euroSize = '42';
                $internationalSize = 'M';
            }elseif($bust == 44 && $waist == 44 && $hips == 44){
                $usaSize = '12';
                $ukSize = '16';
                $euroSize = '44';
                $internationalSize = 'L';
            }elseif($bust == 46 && $waist == 46 && $hips == 46){
                $usaSize = '14';
                $ukSize = '18';
                $euroSize = '46';
                $internationalSize = 'L';
            }elseif($bust == 48 && $waist == 48 && $hips == 48){
                $usaSize = '16';
                $ukSize = '20';
                $euroSize = '48';
                $internationalSize = 'XL';
            }elseif($bust == 50 && $waist == 50 && $hips == 50){
                $usaSize = '18';
                $ukSize = '22';
                $euroSize = '50';
                $internationalSize = 'XL';
            }elseif($bust == 52 && $waist == 52 && $hips == 52){
                $usaSize = '20';
                $ukSize = '24';
                $euroSize = '52';
                $internationalSize = 'XXL';
            }elseif($bust == 54 && $waist == 54 && $hips == 54){
                $usaSize = '22';
                $ukSize = '26';
                $euroSize = '54';
                $internationalSize = 'XXL';
            }elseif($bust == 56 && $waist == 56 && $hips == 56) {
                $firstText = "Sorry, we couldn't calculate a dress size based on your measurements. Check the catalog or manufacturer before buying your dress, or try it on if you can";
                $this->param['firstText']=$firstText;
                $this->param['RESULT'] = 1;
                return $this->param;
            }else if ($bust != $waist || $bust != $hips || $hips != $waist) {
                if ($bust >= 56 || $waist >= 56 || $hips >= 56){
                    $firstText = "Sorry, we couldn't calculate a dress size based on your measurements. Check the catalog or manufacturer before buying your dress, or try it on if you can";
                    $this->param['firstText']=$firstText;
                    $this->param['RESULT'] = 1;
                    return $this->param;
                }else{
                    $secondText = "Looks like your measurements fall into different size categories (as shown in the table below). Check the <b>detailed dress size chart</b> in the article to assess which size should fit you best.')";
                    $usBust = getUSSize($bust);
                    $usHips = getUSSize($hips);
                    $usWaist = getUSSize($waist);
                    $ukBust = getUKSize($bust);
                    $ukHips = getUKSize($hips);
                    $ukWaist = getUKSize($waist);
                    $euBust = $bust;
                    $euHips = $hips;
                    $euWaist = $waist;
                    $internationalBust = getInternationalSize($bust);
                    $internationalHips = getInternationalSize($hips);
                    $internationalWaist = getInternationalSize($waist);
                    $this->param['secondText']=$secondText;
                    $this->param['usBust']=$usBust;
                    $this->param['usHips']=$usHips;
                    $this->param['usWaist']=$usWaist;
                    $this->param['ukBust']=$ukBust;
                    $this->param['ukHips']=$ukHips;
                    $this->param['ukWaist']=$ukWaist;
                    $this->param['euBust']=$euBust;
                    $this->param['euHips']=$euHips;
                    $this->param['euWaist']=$euWaist;
                    $this->param['internationalBust']=$internationalBust;
                    $this->param['internationalHips']=$internationalHips;
                    $this->param['internationalWaist']=$internationalWaist;
                    $this->param['RESULT'] = 1;
                    return $this->param;
                }
            }
            if (isset($usaSize) && isset($ukSize) && isset($euroSize) && isset($internationalSize)){
                $this->param['usaSize']=$usaSize;
                $this->param['ukSize']=$ukSize;
                $this->param['euroSize']=$euroSize;
                $this->param['internationalSize']=$internationalSize;
                $this->param['RESULT'] = 1;

                return $this->param;
            }
        }else{
            $this->param['error'] = 'Please Check Your Input.';
            return $this->param;
        }
    }

    // EER Calculator - Estimated Energy Requirement
	public function eer($request){
        // dd($request->all());
		if ($request->gender==='Male' || $request->gender==='Female' || $request->gender==='pergnant' || $request->gender==='lac') {
			if (is_numeric($request->age) && is_numeric($request->weight) && is_numeric($request->{'height-ft'}) || is_numeric($request->{'height-in'}) || is_numeric($request->{'height-cm'})) {
				$age=$request->age;
				$height_ft=$request->{'height-ft'};
				$height_in=$request->{'height-in'};
				$height_cm=$request->{'height-cm'};
				$weight=$request->weight;
				if ($request->unit==="lbs") {
					$weight = $weight / 2.205;
				}
				if ($request->unit_ft_in==='ft/in') {
					$height_cm=$height_ft * 30.48;
					if ($height_in!=null) {
						$height_in= $height_in * 2.54;
						$height_cm=$height_cm + $height_in;
					}
				}
				if ($request->activity==="Sedentary") {
					$pa=1.0;
					$stand='bg-gradient text-white';
					$this->param['stand'] = $stand;
				}elseif ($request->activity==="Lightly Active") {
					$pa=1.11;
					$light='bg-gradient text-white';
					$this->param['light'] = $light;
				}elseif ($request->activity==="Moderately Active") {
					$pa=1.25;
					$mod='bg-gradient text-white';
					$this->param['mod'] = $mod;
				}else {
					$pa=1.48;
					$very='bg-gradient text-white';
					$this->param['very'] = $very;
				}
				if ($request->gender==='Female') {
					$bmr= round((9.99 * $weight) + (6.25 * $height_cm) - (4.92 * $age) - 161,2);
