    // Grams To Calories Calculator
    public function grams_to_calories($request){
        $carbohydrate=$request->carbohydrate;
        $carbo_unit=$request->carbo_unit;
        $protein=$request->protein;
        $protein_unit=$request->protein_unit;
        $fat=$request->fat;
        $fat_unit=$request->fat_unit;

        if($carbo_unit  == 'g'){
            $carbo_unit = 1;
        }else if($carbo_unit  == 'dag'){
            $carbo_unit = 10;

        }else if($carbo_unit == 'oz'){
            $carbo_unit = 28.35;
        }

        if($protein_unit == 'g'){
            $protein_unit = 1;
        }else if($protein_unit  == 'dag'){
            $protein_unit = 10;

        }else if($protein_unit  == 'oz'){
            $protein_unit = 28.35;
        }

        if($fat_unit == 'g'){
            $fat_unit = 1;
        }else if($fat_unit == 'dag'){
            $fat_unit = 10;

        }else if($fat_unit == 'oz'){
            $fat_unit = 28.35;
        }


		if(is_numeric($carbohydrate) && is_numeric($protein) && is_numeric($fat)){
			$cv=$carbohydrate*$carbo_unit;
			$pv=$protein*$protein_unit;
			$fv=$fat*$fat_unit;
			$carbs=$cv*4;
			$pr=$pv*4;
			$cf=$fv*9;
			$tc=$carbs+$pr+$cf;
			$this->param['cv']=$cv;
			$this->param['pv']=$pv;
			$this->param['fv']=$fv;
			$this->param['carbs']=$carbs;
			$this->param['pr']=$pr;
			$this->param['cf']=$cf;
			$this->param['tc']=$tc;
			$this->param['RESULT'] = 1;
            // dd($this->param);
            return $this->param;
		}else{
            $this->param['error'] = 'Please! Check your input.';
            return $this->param;
		}
	}

    // Harris Benedict Equation Calculator
    public function harris($request){
        // dd($request->all());
        $age = $request->age;
        $weight = $request->weight;
        $height_ft = $request->height_ft;
        $height_in = $request->height_in;
        $height_cm = $request->height_cm;
        $unit = $request->unit;
        $unit_h = $request->unit_ft_in;
        $gender = $request->gender;
        $activity = $request->activity;

		if (is_numeric($age) && is_numeric($weight) || is_numeric($height_ft) || is_numeric($height_in) || is_numeric($height_cm)) {
			if ($unit==="lbs") {
				$weight = $weight / 2.205;
			}elseif ($unit==="stone") {
				$weight = $weight * 6.35;
			}elseif ($unit==="kg") {
				$weight = $weight * 1;
			}
			if ($unit_h==='ft/in') {
				$height_cm=$height_ft * 30.48;
				if ($height_in!=null) {
					$height_in= $height_in * 2.54;
					$height_cm=$height_cm + $height_in;
				}
			}elseif ($unit_h==='ft') {
				$height_cm = $height_cm * 30.48;
			}elseif ($unit_h==='in') {
				$height_cm = $height_cm * 2.54;
			}elseif ($unit_h==='cm') {
				$height_cm = $height_cm * 1;
			}elseif ($unit_h==='m') {
				$height_cm = $height_cm * 100;
			}
			if ($gender==='female') {
				$bmr_ans = round((665.1+(9.563*$weight)+(1.850*$height_cm)-(4.676*$age)));
			}else{
				$bmr_ans = round((66.5+(13.75*$weight)+(5.003* $height_cm)-(6.75*$age)));
			}
			$pro = 15;
			$fats = 30;
			$carb = 55;
			$tee = $activity * $bmr_ans;
			$cal_gram = $tee *  0.129598;
			$pro_gram = (($pro/100) * $tee) / 4;
			$pro_gram_ans = round($pro_gram);
			$carb_gram = (($carb/100) * $tee) / 4;
			$carb_gram_ans = round($carb_gram);
			$fats_gram = (($fats/100) * $tee) / 4;
			$fats_gram_ans = round($fats_gram);
			$sum = $pro_gram_ans + $carb_gram_ans + $fats_gram_ans;
			$pro_per = round(($pro_gram_ans/$sum)*100);
			$carb_per = round(($carb_gram_ans/$sum)*100);
			$fats_per = round(($fats_gram_ans/$sum)*100);
		}else{
            $this->param['error'] = 'Please! Check your input.';
            return $this->param;
		}
		$this->param['bmr_ans'] = $bmr_ans;
		$this->param['tee'] = $tee;
		$this->param['pro_gram_ans'] = $pro_gram_ans;
		$this->param['carb_gram_ans'] = $carb_gram_ans;
		$this->param['fats_gram_ans'] = $fats_gram_ans;
		$this->param['pro_per'] = $pro_per;
		$this->param['carb_per'] = $carb_per;
		$this->param['fats_per'] = $fats_per;
		$this->param['RESULT'] = 1;
        return $this->param;
    }

    // FFMI Calculator
	public function ffmi($request){
        // dd($request->all());
		if (is_numeric($request->weight) && is_numeric($request->percent) && (is_numeric($request->height_ft) || is_numeric($request->height_in) || is_numeric($request->height_cm))) {
			$height_ft=$request->height_ft;
			$height_in=$request->height_in;
			$height_cm=$request->height_cm;
			$percent=$request->percent;
			$weight=$request->weight;
			if ($request->unit==="lbs") {
				$weight = $weight / 2.205;
			}
			if ($request->unit_ft_in==='ft/in') {
				$height_cm=$height_ft * 30.48;
				if ($height_in!=null) {
					$height_in= $height_in * 2.54;
					$height_cm=$height_cm + $height_in;
				}
			}
			// cm to in
			$height_inch=$height_cm / 2.54;
			$height_m=$height_inch / 39.37;
			$body_fat=round($weight * ($percent / 100),2);
			$lean=round($weight * (1 - ($percent / 100)),2);
			$ffmi=round($lean/ pow($height_m, 2),2);
			$nffmi=round($ffmi + 6.1 * (1.8 - $height_m),2);
			$bmi=round($weight/pow($height_m, 2),2);
            // dd($ffmi);
			if ($ffmi<18) {
				$this->param['skinny']="purple text-white";
				$cat="Below Average";
			}elseif ($ffmi>=18 && $ffmi<20) {
				$this->param['average']="cyan text-white";
				$cat="Average";
			}elseif ($ffmi>=20 && $ffmi<22) {
				$this->param['fat']="red text-white";
				$cat="Above Average";
			}elseif ($ffmi>=22 && $ffmi<23) {
				$this->param['athlete']="orange text-white";
				$cat="Excellent";
			}elseif ($ffmi>=23 && $ffmi<26) {
				$this->param['gym']="orange text-white";
				$cat="Superior";
			}elseif ($ffmi>=26 && $ffmi<28) {
				$this->param['body']="bg-gradient text-white";
				$cat="Suspicion of steroid use";
			}else{
				$this->param['unlikely']="bg-gradient text-white";
				$cat="Unlikely";
			}
			$this->param['body_fat'] = $body_fat;
			$this->param['lean'] = $lean;
			$this->param['ffmi'] = $ffmi;
			$this->param['cat'] = $cat;
			$this->param['nffmi'] = $nffmi;
			$this->param['bmi'] = $bmi;
			$this->param['RESULT'] = 1;
            return $this->param;
		} else {
            $this->param['error'] = 'Please Fill All Fields.';
            return $this->param;
		}
	}

    // Height Percentile Calculator
    public function height($request){
        // dd($request->all());
