    public function jump($request){

        $operations = $request->operations;
        $age = $request->age;
        $gender = $request->gender;
        $first = $request->first;
        $units1 = $request->units1;
        $second = $request->second;
        $units2 = $request->units2;
        $height_ft = $request->height_ft;
        $height_in = $request->height_in;
        $height_cm = $request->height_cm;
        $h_unit = $request->unit_ft_in;

        if($units1 == 'kg'){
            $units1 = 1;
        }else if($units1 == 'lbs'){
            $units1 = 2;
        }else if($units1 == 'stone'){
            $units1 = 3;
        }
        if($units2 == 'sec'){
            $units2 = 1;
        }else if($units2 == 'min'){
            $units2 = 2;
        }else if($units2 == 'hrs'){
            $units2 = 3;
        }


		function time2($a,$b){
			if($a=="1"){
				$waqat = $b * 0.016667;
			}elseif ($a=="2") {
				$waqat = $b * 1;
			}elseif ($a=="3") {
				$waqat = $b * 60;
			}
			return $waqat;
		}
		function weight($a,$b){
			if($a=="1"){
				$wazan = $b * 1;
			}elseif ($a=="2") {
				$wazan = $b * 0.4536;
			}elseif ($a=="3") {
				$wazan = $b * 6.35;
			}
			return $wazan;
		}
		$first = weight($units1,$first);
		$second = time2($units2,$second);
      
		if (is_numeric($first) && is_numeric($second)) {
			if ($first > 30) {
				if ($first < 300) {
					if ($second > 0) {
						if ($h_unit == 'cm') {
							$height_in = 0;
							$height_ft = ($height_cm / 30.48);
							$height_in = $height_ft * 12 + $height_in;							
						}
                        // dd($height_in);

						$height_in = $height_ft * 12 + $height_in;
						$cbr_ans = ($operations * $first * 7) / 400;
						$cb_ans = $cbr_ans * $second;
						if($gender == '1'){
							$BMR = (13.397 * $first) + (4.799 * $height_in * 2.54) - (5.677 * $age) + 88.362;
						}else{
							$BMR = (9.247 * $first) + (3.098 * $height_in * 2.54) - (4.330 * $age) + 447.593;
						}
					}else{
                        $this->param['error'] = 'Time must be more than zero.';
