    }


    // Map Calculator
    public function map($request){
        $sbp=$request->sbp;
        $dbp=$request->dbp;

		if(is_numeric($sbp) && is_numeric($dbp)){
			if($sbp<70){
                $this->param['error'] = 'Systolic Blood Pressure> 70 For Normal Person.Contact your doctor for further description.';
                return $this->param;
			}else if($dbp<40){
                $this->param['error'] = 'Diastolic blood pressure> 40 for Normal persons.Contact your doctor for further description.';
                return $this->param;
			}
			else if($dbp>=$sbp){
                $this->param['error'] = 'Diastolic blood pressure cannot be higher than systolic blood pressure.';
                return $this->param;
			}else{
				$map=(1/3*$sbp+2/3*$dbp);
				$pr=$sbp-$dbp;
				$this->param['dbp']=$dbp;
				$this->param['sbp']=$sbp;
				$this->param['map']=$map;
				$this->param['pr']=$pr;
				$this->param['RESULT'] = 1;
                // dd($this->param);
                return $this->param;
			}
		}else{
            $this->param['error'] = 'Please! Check your input.';
            return $this->param;
		}
	}

