    // One Rep Max Calculator
  	public function one($request){
        $weight=trim($request->weight);
        $weight_unit=trim($request->weight_unit);
        $rep=trim($request->rep);

        if(is_numeric($weight) && is_numeric($rep)){
            if ($weight_unit=='lbs') {
                $weight=$weight*0.4536;
            }
            $ans=($weight*$rep*0.0333)+$weight;
            if ($weight_unit=='lbs') {
                $ans=$ans*2.2046;
            }
            $this->param['ans'] = $ans;
            $this->param['request'] = $request;
            $this->param['RESULT'] = 1;
            return $this->param;
        }else{
            $this->param['error'] = 'Please! Check your input.';
            return $this->param;
        }
    }

    // Pace Calculator
	public function pace($request){
        
		function gethours($total_sec=''){
			return str_pad(floor($total_sec/3600), 2, "0", STR_PAD_LEFT);
		}
		function getmins($total_sec=''){
			$mins=$total_sec-(gethours($total_sec)*3600);
			return str_pad(floor($mins/60), 2, "0", STR_PAD_LEFT);
		}
		function getsecs($value=''){
			return str_pad(round($value-(gethours($value)*3600)-(getmins($value)*60)), 2, "0", STR_PAD_LEFT);
		}
		function gettime($seconds){
			$hour=gethours($seconds);
			$mins=getmins($seconds);
			$sec=getsecs($seconds);
			return "$hour : $mins : $sec";
		}

        $type=$request->type;
        $time=$request->time;
        $dis=$request->dis;
        $dis_unit=$request->dis_unit;
        $event=$request->event;
        $pace=$request->pace;
        $per=$request->per;

		if ($request->calculator_name=='calculator3') {
			if (!empty($request->from)) {
				$per=$request->fromu;
				$pace=$request->from;
				$to=$request->to;
