                            $pace=$ptsec;
                        }else{
                            $dis_km=round($tsec / $ptsec,3);
                            $dis_mi=round($dis_km*0.621371,3);
                            $dis_m=round($dis_km*1000,3);
                            $dis_yd=round($dis_km*1093.613,3);
                            $pace=$ptsec*1.6093444;
                            $pacekm=$ptsec;
                        }
                    }else{
                        if (($pace<0 && $pace==0) || !is_numeric($pace)) {
                            $this->param['error'] = 'Please! Enter positive value of pace.';
                            return $this->param;
                        }
                        if ($per==='3') {
                            $dis_mi=$pace*$thour;
                            $dis_km=$dis_mi*1.609344;
                            $dis_m=$dis_mi*1609.344;
                            $dis_yd=$dis_mi*1760;
                            $pace=$tsec/$dis_mi;
                            $pacekm=$pace * 0.621371;
                        }elseif ($per==='4') {
                            $dis_km=$pace*$thour;
                            $dis_mi=$dis_km*0.621371;
                            $dis_m=$dis_km*1000;
                            $dis_yd=$dis_km*1093.613;
                            $pacekm=$tsec/$dis_km;
                            $pace=$pacekm * 1.609344;
                        }elseif($per==='5'){
                            $dis_m=$pace*$tmin;
                            $dis_mi=$dis_m*0.000621371;
                            $dis_km=$dis_m/1000;
                            $dis_yd=$dis_m*1.093613;
                            $pacekm=$tsec/$dis_km;
                            $pace=$pacekm * 1.609344;
                        }elseif($per==='6'){
                            $dis_m=$pace*$tsec;
                            $dis_mi=$dis_m*0.000621371;
                            $dis_km=$dis_m/1000;
                            $dis_yd=$dis_m*1.093613;
                            $pacekm=$tsec/$dis_km;
                            $pace=$pacekm * 1.609344;
                        }elseif($per==='7'){
                            $dis_yd=$pace*$tmin;
                            $dis_mi=$dis_yd*0.000568182;
                            $dis_km=$dis_yd*0.0009144;
                            $dis_m=$dis_yd*0.9144;
                            $pacekm=$tsec/$dis_km;
                            $pace=$pacekm * 1.609344;
                        }elseif($per==='8'){
                            $dis_yd=$pace*$tsec;
                            $dis_mi=$dis_yd*0.000568182;
                            $dis_km=$dis_yd*0.0009144;
                            $dis_m=$dis_yd*0.9144;
                            $pacekm=$tsec/$dis_km;
                            $pace=$pacekm * 1.609344;
                        }
                    }
                    $this->param['dis_km'] = $dis_km;
                    $this->param['dis_m'] = $dis_m;
                    $this->param['dis_mi'] = $dis_mi;
                    $this->param['dis_yd'] = $dis_yd;
                    $this->param['pacekm'] = $pacekm;
                    $this->param['pace'] = $pace;
                    $this->param['share'] = $pace;
                    $this->param['request'] = $request;
                    $this->param['RESULT'] = 1;
                    return $this->param;
                }else{
                    $this->param['error'] = 'Please! Check your input.';
                    return $this->param;
                }
            }
        }
	}

	// Macro Calculator
	public function macro($request){
        // dd($request->all());
		$check=true;
		foreach ($request->toArray() as $key => $value) {
			if ($key!='height-ft' && $key!='height-in' && $key!='height-cm' && $key!='submit' && $key!='percent' && $key!="/macro-calculator/") {
				if (empty($value)) {
					$check=false;
				}
			}
		}
		if (!is_numeric($request->{'height-ft'}) && !is_numeric($request->{'height-in'}) && !is_numeric($request->{'height-cm'})) {
			$check=false;
		}
		if ($check==true) {
			$age=$request->age;
			$height_ft=$request->{'height-ft'};
			$height_in=$request->{'height-in'};
			$height_cm=$request->{'height-cm'};
			$weight=$request->weight;
			if ($request->unit==="lbs") {
				$weight = $weight / 2.205;
			}
			if ($request->unit_ft_in==='ft/in') {
				$height_cm=$height_ft * 30.48;
				if ($height_in!=null) {
					$height_in= $height_in * 2.54;
					$height_cm=$height_cm + $height_in;
				}
			}
			if ($request->gender==='Female') {
				$sugar=25;
				if ($request->formula==='first') {
					$BMR= round((10 * $weight) + (6.25 * $height_cm) - (5 * $age) - 161);
				}elseif ($request->formula==='2nd') {
					$BMR = round((9.247 * $weight) + (3.098 * $height_cm) - (4.330 * $age) + 447.593);
				}else{
					if (empty($request->percent)) {
                        $this->param['error'] = 'Please fill required fields.';
                        return $this->param;
					}
					$BMR = round(370 + 21.6 * (1 - ($request->percent / 100)) * $weight);
				}
			} else {
				$sugar=37.5;
				if ($request->formula==='first') {
					$BMR= round((10 * $weight) + (6.25 * $height_cm) - (5 * $age) + 5);
				}elseif ($request->formula=='2nd') {
					$BMR = round((13.397 * $weight) + (4.799 * $height_cm) - (5.677 * $age) + 88.362);
				}else{
					if (empty($request->percent)) {
                        $this->param['error'] = 'Please fill required fields.';
                        return $this->param;
					}
					$BMR = round(370 + 21.6 * (1 - ($request->percent / 100)) * $weight);
				}
			}
			if ($request->activity == "Sedentary") {
				$tdee=round($BMR * (1.2));
			}elseif ($request->activity == "Lightly Active") {
				$tdee=round($BMR * (1.375));
			}elseif ($request->activity == "Moderately Active") {
				$tdee=round($BMR * (1.465));
			}elseif ($request->activity == "Very Active") {
				$tdee=round($BMR * (1.725));
			}else {
				$tdee=round($BMR * (1.9));
			}
			if ($request->goal==="Fat Loss") {
				$tdee=$tdee - 500;
			}elseif ($request->goal==="Loss 10%") {
				$tdee=$tdee * 0.10;
			}elseif ($request->goal==="Maintain") {
				$tdee=$tdee * 1;
			}else{
				$tdee=$tdee * 1.1;
			}
			if ($request->meal!=='all') {
				$tdee=round($tdee/$request->meal);
				$sugar=round($sugar/$request->meal);
			}
			$stand_fat= round(($tdee * 0.10) / 9);
			// return 
			$this->param['calories'] = $tdee;
			$this->param['Sugar'] = $sugar;
			$this->param['stand_fat'] = $stand_fat;
			$this->param['RESULT'] = 1;
            return $this->param;
		} else {
            $this->param['error'] = 'Please fill All fields.';
            return $this->param;
		}
	}

