    // Calorie Deficit Calculator
    public function cal_deficit($request){
        // dd($request->all());
        $submit = $request->unit_type;
        $gender = $request->gender;
        $age = $request->age;
        $ft_in=$request->ft_in;
        $height_cm = $request->height_cm;
        $weight = $request->weight;
        $target = $request->target;
        $activity = $request->activity;

        function customRound($num) {
            if ($num >= 50) {
                return ceil($num/100)*100;
            } else {
                return ceil($num/50)*50;
            }
        }
        if (is_numeric($age) && is_numeric($weight) && is_numeric($target) && !empty($gender) && !empty($activity)){
            if ($submit === "lbs") {
                if(empty($ft_in)) {
                    $this->param['error'] = 'Please Select Height.';
                    return $this->param;
                }
                $weight_kg = $weight / 2.205;
                $target_kg = $target / 2.205;
                $height_cm = $ft_in * 2.54;
            }else{
                if(empty($height_cm)) {
                    $this->param['error'] = 'Please Enter Height.';
                    return $this->param;
                }
                $weight_kg = $weight;
                $target_kg = $target;
                $height_cm = $height_cm;
            }
            if($target > $weight){
                $this->param['error'] = 'Your target weight must be lower than your current weight.';
                return $this->param;
            }
            $height_m = $height_cm / 100;
            $height_in = $height_cm / 2.54;
            $weight_lbs = $weight_kg * 2.205;
            $target_lbs = $target_kg * 2.205;
            if($gender=='Male'){
                $RMR = round(66 + (13.7 * $weight_kg) + (5 * $height_cm) - (6.8 * $age));
                $BMR = round(($height_cm * 6.25) + ($weight_kg * 10) - ($age * 5) + 5);
                $LBM = round((0.32810 * $weight) + (0.33929 * $height_cm) - 29.5336);
                $RMR_target = round(66 + (13.7 * $target_kg) + (5 * $height_cm) - (6.8 * $age));
                $BMR_target = round(($height_cm * 6.25) + ($target_kg * 10) - ($age * 5) + 5);
                $LBM_target = round((0.32810 * $target_kg) + (0.33929 * $height_cm) - 29.5336);
                $Robinson=round(52 + (1.9 * ($height_in - 60)));
                $Miller=round(56.2 + (1.41 * ($height_in - 60)));
                $Devine=round(50 + (2.3 * ($height_in - 60)));
                $Hamwi=round(48 + (2.7 * ($height_in - 60)));
            }else{
                $RMR = round(655 + (9.6 * $weight_kg) + (1.8 * $height_cm) - (4.7 * $age));
                $BMR = round(($height_cm * 6.25) + ($weight_kg * 10) - ($age * 5) - 161);
                $LBM = round((0.29569 * $weight) + (0.41813 * $height_cm) - 43.2933);
                $RMR_target = round(655 + (9.6 * $target_kg) + (1.8 * $height_cm) - (4.7 * $age));
                $BMR_target = round(($height_cm * 6.25) + ($target_kg * 10) - ($age * 5) - 161);
                $LBM_target = round((0.29569 * $target_kg) + (0.41813 * $height_cm) - 43.2933);
                $Robinson=round(49 + (1.7 * ($height_in - 60)));
                $Miller=round(53.1 + (1.36 * ($height_in - 60)));
                $Devine=round(45.5 + (2.3 * ($height_in - 60)));
                $Hamwi=round(45 + (2.2 * ($height_in - 60)));
            }
            $BMI = round($weight_kg / ($height_m * $height_m),2);
            $BMI_target = round($target_kg / ($height_m * $height_m),2);
            if ($Hamwi >= $Miller) {
                $ibw= $Miller.' - '.$Hamwi;
            } else {
                $ibw= $Hamwi.' - '.$Miller;
            }
            if ($submit === "lbs") {
                $Miller= $Miller * 2.205;
                $Hamwi= $Hamwi * 2.205;
                if ($Hamwi >= $Miller) {
                    $ibw = round($Miller).'-'.round($Hamwi);
                } else {
                    $ibw = round($Hamwi).'-'.round($Miller);
                }
            }
            $tdee = round($BMR * $activity);
            $tdee_target = round($BMR_target * $activity);
            $first_num = substr($tdee, 0, 2);
            $last_num = substr($tdee, -2);
            if ($last_num < 50) {
                $table_cal = $first_num."00";
            }else{
                $table_cal = $first_num."50";
            }
            $x = $table_cal;
            $main_cal_less = $tdee - $table_cal;
            $jama = 50;
            while($x >= 1000) {
                $intake_cal = $x;
                $calories_less = $jama + $main_cal_less;
                $calories_daily = $intake_cal - $calories_less;
                $pounds_daily = round($calories_less/3500,3);
                $days = round(($weight_lbs - $target_lbs) / $pounds_daily);
                // $yrs = round($days / 365, 2);
                $start_date = new \DateTime();
                $end_date = (new $start_date)->add(new \DateInterval("P{$days}D") );
                $dd = date_diff($start_date,$end_date);
                if ($dd->y > 0) {
                    $yrs = $dd->y." years ".$dd->m." months ".$dd->d." days";
                }else{
                    $yrs = $dd->m." months ".$dd->d." days";
                }
                $NewDate = Date('d-M-Y', strtotime("+".$days." days"));
                $intake_cal_array[] = $intake_cal."@@".$yrs."@@".$NewDate."@@".$calories_less;
                $x-=50;
                $jama = $jama + 50;
            }
            $weight_loss_cal = round(0.8 * $tdee);
            $calorie_def_cal = round($tdee - $weight_loss_cal);
            $this->param = array (
                "height_in" => $height_in,
                "tdee" => $tdee,
                "RMR" => $RMR,
                "LBM" => $LBM,
                "tdee_target" => $tdee_target,
                "RMR_target" => $RMR_target,
                "LBM_target" => $LBM_target,
                "BMI" => $BMI,
                "BMI_target" => $BMI_target,
                "intake_cal_array" => $intake_cal_array,
                "age" => $age,
                "gender" => $gender,
                "weight" => $weight,
                "submit" => $submit,
                "target" => $target,
                "activity" => $activity,
                "days" => $days,
                "pounds_daily" => $pounds_daily,
                "BMR" => $BMR,
                "ibw" => $ibw,
                "weight_loss_cal" => $weight_loss_cal,
                "calorie_def_cal" => $calorie_def_cal,
                "RESULT" => 1
            );
            // dd($this->param);
            return $this->param;
        }else{
            $this->param['error'] = 'Please! Check your input.';
            return $this->param;
        }
    }

    // Biological Age Calculator
	public function biological($request){
    // dd($request->all());
        $m1=$request->m1;
        $m2=$request->m2;
        $m3=$request->m3;
        $m5=$request->m5;
        $m6=$request->m6;
        $m7=$request->m7;
        $m8=$request->m8;
        $m11=$request->m11;
        $m12=$request->m12;
        $m13=$request->m13;
        $m14=$request->m14;
        $m16=$request->m16;
        $m17=$request->m17;
        $m18=$request->m18;
        $m19=$request->m19;
        $m20=$request->m20;
        $m21=$request->m21;
        $m22=$request->m22;
        $m23=$request->m23;
        $m24=$request->m24;
        $m27=$request->m27;
        $m28=$request->m28;
        $m30=$request->m30;
        $m31=$request->m31;
        $m34=$request->m34;
        $m35=$request->m35;
        $m36=$request->m36;
        $age=$request->age;

		if($age==""){
			$age=0;
		}
		$M = 75.4140596125 + 0.0618445029 * $age - 0.0013020249 * pow($age,2) + 0.0000231775 * pow($age,3) + 0.0000001066 * pow($age,4);
		$F = 80.6705634463 + 0.0374221292 * $age - 0.0005304983 * pow($age,2) - 0.0000008558 * pow($age,3) + 0.0000002442 * pow($age,4);
		$typ= round(10 *(78.0916570818 + 0.0525689171 * $age - 0.0009946587 * pow($age,2) + 0.0000124103 * pow($age,3) + 0.0000001689 * pow($age,4))) / 10;
		if (($m1 == "male" || $m1=="m") && $m2 == "white") {
		     $RaceAge = $M + 0.55 - 0.009964 * $age - 0.000027 * pow($age,2);
		}
		if (($m1 == "male" || $m1=="m") && $m2 == "black") {
		     $RaceAge = $M - 5.592857 - 0.016250 * $age + 0.001732 * pow($age,2) - 0.000009 * pow($age,3);
		}
		  if (($m1 == "male" || $m1=="m") && $m2 == "hispanic") {
		     $RaceAge = $M + 3.1 - 0.069750 * $age + 0.000338 * pow($age,2);
		}
		  if (($m1 == "male" || $m1=="m") && $m2 == "asian") {
		     $RaceAge = $M + 6.8 - 0.153000 * $age + 0.000850 * pow($age,2);
		}
		  if (($m1 == "male" || $m1=="m") && $m2 == "amindian") {
		     $RaceAge = $M - 1.2 + 0.007 * $age + 0.0001 * pow($age,2);
		}
		  if (($m1 == "male" || $m1=="m") && ($m2 == "other" || $m2=="oth")) {
		     $RaceAge = $M + 0;
		}
		  if ($m1 == "female" && $m2 == "white") {
		     $RaceAge = $F + 0.396429 - 0.003946 * $age - 0.000013 * pow($age,2);
		}
		  if ($m1 == "female" && $m2 == "black") {
		     $RaceAge = $F - 3.815873 - 0.022566 * $age + 0.001428 * pow($age,2) - 0.000008 * pow($age,3);
		}
		  if ($m1 == "female" && $m2 == "hispanic") {
		     $RaceAge = $F + 3.9 - 0.087750 * $age + 0.000488 * pow($age,2);
		}
		  if ($m1 == "female" && $m2 == "asian") {
		     $RaceAge = $F + 6.7 - 0.150750 * $age + 0.000838 * pow($age,2);
		}
		  if ($m1 == "female" && $m2 == "amindian") {
		     $RaceAge = $F + 2.2 - 0.069500 * $age + 0.000525 * pow($age,2);
		}
		  if ($m1 == "female" && ($m2 == "other" || $m2=="oth")) {
		     $RaceAge = $F+0;
		}
		$RaceAdj = $RaceAge-$typ;
		$personalT =round(10 *(1 * $RaceAdj + 1 * $m3 + 1 * $m5)) / 10 ;
		$cadT=1 * $m6 + 1 * $m7 + 1 * $m8 + 1 * $m11 + 1 * $m12;
		$medicalIT=1 * $m13 + 1 * $m14 + 1 * $m16 + 1 * $m17 + 1 * $m18 + 1 * $m19 + 1 * $m20;
		$dietT= 1 * $m21 + 1 * $m22 + 1 * $m23 + 1 * $m24;
		$psychT = 1 * $m27 + 1 * $m28 + 1 * $m30 + 1 * $m31;
		$safetyT = 1 * $m34 + 1 * $m35 + 1 * $m36;
		$total_value = 1 * $personalT + 1 * $cadT + 1 * $medicalIT + 1 * $dietT + 1 * $psychT + 1 * $safetyT;
		$expectancy = round(10 *(1 * $typ + 1 * $total_value)) /  10;
		$esperanza = round(10 *(1 * $typ + 1 * $total_value)) /  10;
		$healthage_value = $age - $total_value;
		$edad_biologica =$healthage_value;
		$this->param['typ']=$typ;
		$this->param['exp']=$expectancy;
		$this->param['bio']=$healthage_value;
		$this->param['per']=$personalT;
		$this->param['med']=$medicalIT;
		$this->param['saf']=$safetyT;
		$this->param['tot']=$total_value;
		$this->param['psychT']=$psychT;	
		$this->param['nut']=$dietT;
		$this->param['cad']=$cadT;
		$this->param['RESULT'] = 1;
        return $this->param;
	}

