                    $this->param['error'] = "Please check child's weight input.";
                    return $this->param;
                }
                $c_weight = $c_weight_lbs;
            } else {
                if (!isset($c_weight_kg) || !is_numeric($c_weight_kg)) {
                    $this->param['error'] = "Please check child's weight input.";
                    return $this->param;
                }
                $c_weight = $c_weight_kg * 2.20462; // Corrected: kg to lbs
            }
        
            // Validation
            if ($m_height <= 0) {
                $this->param['error'] = "Mother's height must be greater than zero.";
                return $this->param;
            }
            if ($f_height <= 0) {
                $this->param['error'] = "Father's height must be greater than zero.";
                return $this->param;
            }
            if ($c_weight <= 0) {
                $this->param['error'] = "Child's weight must be greater than zero.";
                return $this->param;
            }
            if ($c_height <= 0) {
                $this->param['error'] = "Child's height must be greater than zero.";
                return $this->param;
            }
        
            // Calculate Khamis-Roche height (in inches)
            $d = $data[$gender][$age];
            $khamis_height = $d[0] * $c_weight + $d[1] * $c_height + ($d[2] * ($m_height + $f_height)) / 2 + $d[3];
            $f_ans = ($khamis_height < $c_height) ? $c_height : $khamis_height;
            $final_ans_inches = round($f_ans);
        
            // Determine output format based on child's height unit
            $output_unit = ($c_unit_h === 'ft/in') ? 'imperial' : 'metric';
            if ($output_unit === 'imperial') {
                $final_ans_in = round($final_ans_inches % 12);
                $final_ans_feet = floor($final_ans_inches / 12);
                $final_ans = $final_ans_feet . 'ft ' . $final_ans_in . 'in';
            } else {
                $final_ans = round($final_ans_inches * 2.54) . ' cm';
            }
        
            // Gender and margin setup
            if ($gender == 0) {
                $sex = "boys";
                $margin = 2.1; // inches
            } else {
                $sex = "girls";
                $margin = 1.7; // inches
            }
        
            // Calculate min and max height
            if ($output_unit === 'imperial') {
                $minHeight = round($f_ans - $margin);
                $minHeight_in = round($minHeight % 12);
                $minHeight_feet = floor($minHeight / 12);
                $minHeight = $minHeight_feet . 'ft ' . $minHeight_in . 'in';
        
                $maxHeight = round($f_ans + $margin);
                $maxHeight_in = round($maxHeight % 12);
                $maxHeight_feet = floor($maxHeight / 12);
                $maxHeight = $maxHeight_feet . 'ft ' . $maxHeight_in . 'in';
            } else {
                $minHeight = round(($f_ans - $margin) * 2.54, 2) . ' cm';
                $maxHeight = round(($f_ans + $margin) * 2.54, 2) . ' cm';
                $margin = round($margin * 2.54, 2); // Convert margin to cm for output
            }
        
            // Set response parameters
            $this->param['click_val'] = $output_unit;
            $this->param['submit'] = $submit;
            $this->param['final_ans'] = $final_ans;
            $this->param['minHeight'] = $minHeight;
            $this->param['maxHeight'] = $maxHeight;
            $this->param['sex'] = $sex;
            $this->param['mother_h'] = $m_height_cm ?? ($m_height * 2.54); // Return in cm if provided, else convert
            $this->param['father_h'] = $f_height_cm ?? ($f_height * 2.54); // Return in cm if provided, else convert
            $this->param['gender'] = $gender;
            $this->param['margin'] = $margin;
            $this->param['disable'] = "disable";
            $this->param['RESULT'] = 1;
        
            return $this->param;
        }else{
            
            $submit = $request->calculator_name;
            $m_height_ft = $request->input('m-height-ft');
            $m_height_in = $request->input('m-height-in');
            $f_height_ft = $request->input('f-height-ft');
            $f_height_in = $request->input('f-height-in');
            $m_height_cm = $request->input('height-cm');
            $f_height_cm = $request->input('f-height-cm');
            $mother_entry_unit = $request->input('mother_entry_unit'); // New field for mother's unit
            $father_entry_unit = $request->input('father_entry_unit'); // New field for father's unit
            

            function ft_and_in_to_cm($ft, $in) {
                return ($ft * 30.48) + ($in * 2.54);
            }
        
            function cm_to_ft_and_in($cm) {
                $inches = $cm / 2.54;
                $feet = floor($inches / 12);
                $inches = $inches % 12;
                return $feet . 'ft ' . round($inches) . 'in';
            }

        
            if ($mother_entry_unit === 'ft/in') {
                if (empty($m_height_ft) || empty($m_height_in)) {
                    $this->param['error'] = 'Please! Check your input for mother\'s height.';
                    return $this->param;
                }
                $m_height = ft_and_in_to_cm($m_height_ft, $m_height_in);
            } else { 
                if (empty($m_height_cm)) {
                    $this->param['error'] = 'Please! Check your input for mother\'s height.';
                    return $this->param;
                }

                $m_height = $m_height_cm;
            }
        
            // Process father's height based on the unit selected
            if ($father_entry_unit === 'ft/in') {
                if (empty($f_height_ft) || empty($f_height_in)) {
                    $this->param['error'] = 'Please! Check your input for father\'s height.';
                    return $this->param;
                }
                $f_height = ft_and_in_to_cm($f_height_ft, $f_height_in);
            } else { // cm
                if (empty($f_height_cm)) {
                    $this->param['error'] = 'Please! Check your input for father\'s height.';
                    return $this->param;
                }

                $f_height = $f_height_cm;
            }


            $new_m_height = $m_height;
            $new_f_height = $f_height;

            $boy_mph = ($new_f_height + $new_m_height + 13)/2 ;
            $girl_mph = ($new_f_height + $new_m_height - 13)/2 ;


            $final_ans_boy = $boy_mph;
            $final_ans_girl = $girl_mph;

            if($father_entry_unit == 'ft/in'){
                $final_ans_boy = cm_to_ft_and_in($final_ans_boy);
                $final_ans_girl = cm_to_ft_and_in($final_ans_girl);
            }


        
            if (is_numeric($m_height) && is_numeric($f_height)) {
                if ($m_height > 0) {
                    if ($f_height > 0) {
                        $margin = 4; // Margin in cm
                        $midparental_height = (($m_height) + ($f_height)) / 2;
                        $girls_height = $midparental_height - 6.5; // Subtract 6.5 cm for girls
                        $boys_height = $midparental_height + 6.5; // Add 6.5 cm for boys
        
                        $minHeightGirl = $girls_height - $margin;
                        $maxHeightGirl = $girls_height + $margin;
                        $minHeightBoy = $boys_height - $margin;
                        $maxHeightBoy = $boys_height + $margin;
        
                        // Determine output format based on mother's unit (or father's, depending on preference)
                        $output_unit = $mother_entry_unit; // You can change this to $father_entry_unit if preferred
                        if ($output_unit === 'ft/in') {
                            $girls_height = cm_to_ft_and_in($girls_height);
                            $boys_height = cm_to_ft_and_in($boys_height);
                            $minHeightGirl = cm_to_ft_and_in($minHeightGirl);
                            $maxHeightGirl = cm_to_ft_and_in($maxHeightGirl);
                            $minHeightBoy = cm_to_ft_and_in($minHeightBoy);
                            $maxHeightBoy = cm_to_ft_and_in($maxHeightBoy);
                        } else {
                            $girls_height = round($girls_height, 2);
                            $boys_height = round($boys_height, 2);
                            $minHeightGirl = round($minHeightGirl, 2);
                            $maxHeightGirl = round($maxHeightGirl, 2);
                            $minHeightBoy = round($minHeightBoy, 2);
                            $maxHeightBoy = round($maxHeightBoy, 2);
                        }
                    } else {
                        $this->param['error'] = "Father's height must be greater than zero.";
                        return $this->param;
                    }
                } else {
                    $this->param['error'] = "Mother's height must be greater than zero.";
                    return $this->param;
                }
            } else {
                $this->param['error'] = 'Please! Check your input.';
                return $this->param;
            }
        


            $this->param['margin'] = $margin;
            $this->param['submit'] = $submit;
            $this->param['final_ans_boy'] = $final_ans_boy;
            $this->param['final_ans_girl'] = $final_ans_girl;
            $this->param['girls_height'] = $girl_mph;
            $this->param['boys_height'] = $boy_mph;
            $this->param['minHeightGirl'] = $minHeightGirl;
            $this->param['maxHeightGirl'] = $maxHeightGirl;
            $this->param['minHeightBoy'] = $minHeightBoy;
            $this->param['maxHeightBoy'] = $maxHeightBoy;
            $this->param['mother_height'] = $new_m_height;
            $this->param['father_height'] = $new_f_height;
            $this->param['mother_entry_unit'] = $mother_entry_unit; // Optional: Store unit for reference
            $this->param['father_entry_unit'] = $father_entry_unit; // Optional: Store unit for reference
            $this->param['disable'] = "disable";
        
            $this->param['RESULT'] = 1;
            return $this->param;
        }
	}
 



    

    // Body Fat Calculator
	 public function body($request){
        if ($request->calculator_type==='simple') {
