						elseif($body_fat > 1 &&$body_fat<=5){
							$category= "Essential fat";
							$this->param['Essential'] = "blue text-white";
							$color="#0D47A1";
							$left="2%";
						}elseif ($body_fat>5 && $body_fat<=13) {
							$category= "Athletes";
							$this->param['Athletes'] = "teal text-white";
							$color="#00897B";
							$left="20%";
						}elseif ($body_fat > 13 && $body_fat<=17) {
							$category= "Fitness";
							$this->param['Fitness'] = "green text-white";
							$color="#00C853";
							$left="40%";
						}elseif ($body_fat > 17 && $body_fat<=24) {
							$category= "Average";
							$this->param['Average'] = "yellow text-white";
							$color="#FFEA00";
							$left="60%";
						}else{
							$category= "Obese";
							$this->param['Obese'] = "red text-white";
							$color="#FF1744";
							$left="80%";
						}
					}else{
						if ($age<17) {
							$body_den=1.1369 - (0.0598 * $l);
						}elseif ($age>=17 && $age<=19) {
							$body_den=1.1549 - (0.0678 * $l);
						}elseif ($age>=20 && $age<=29) {
							$body_den=1.1599 - (0.0717 * $l);
						}elseif ($age>=30 && $age<=39) {
							$body_den=1.1423 - (0.0632 * $l);
						}elseif ($age>=40 && $age<=49) {
							$body_den=1.1333 - (0.0612 * $l);
						}elseif ($age>=50) {
							$body_den=1.1339 - (0.0645 * $l);
						}
						$body_fat=round((495/$body_den)-450,2);
						if ($body_fat<0 && $body_fat<=9) {
							$category= "N/A";
							$color="red";
							$left="-2%";
						}
						elseif($body_fat > 9 &&$body_fat<=13){
							$category= "Essential fat";
							$this->param['Essential'] = "blue text-white";
							$color="#0D47A1";
							$left="2%";
						}elseif ($body_fat>13 && $body_fat<=20) {
							$category= "Athletes";
							$this->param['Athletes'] = "teal text-white";
							$color="#00897B";
							$left="20%";
						}elseif ($body_fat > 20 && $body_fat<=24) {
							$category= "Fitness";
							$this->param['Fitness'] = "green text-white";
							$color="#00C853";
							$left="40%";
						}elseif ($body_fat > 24 && $body_fat<=31) {
							$category= "Average";
							$this->param['Average'] = "yellow text-white";
							$color="#FFEA00";
							$left="60%";
						}else{
							$category= "Obese";
							$this->param['Obese'] = "red text-white";
							$color="#FF1744";
							$left="80%";
						}
					}
					$body_fat_w=round($body_fat/100*$weight,2);
					$lbm=round($weight-$body_fat_w,2);
                    $fat_weight = $weight * ($body_fat / 100); // Fat weight in kg
                    $fat_weight_lbs = $fat_weight * 2.205; // Convert to lbs if needed
                    
                    if ($request->unit == 'kg') {
                        $fat_weight_result = $fat_weight; // Keep in kg
                    } else {
                        $fat_weight_result = $fat_weight_lbs; // Convert to lbs
                    }
                    $this->param['fat_weight'] = $fat_weight;
                    $this->param['fat_weight_unit'] = $request->unit;
					$this->param['body_fat'] = $body_fat;
					$this->param['color'] = $color;
					$this->param['left'] = $left;
					$this->param['category'] = $category;
					$this->param['lbm'] = $lbm." ".$request->unit;
					$this->param['body_fat_w'] = $body_fat_w." ".$request->unit;
					$this->param['RESULT'] = 1;
                   
                    return $this->param;
				}else{
                    $this->param['error'] = 'Please fill all fields.';
                    return $this->param;
				}
			}elseif ($request->method === '7') { // Assuming method '7' is for BMI
                if (is_numeric($request->weight) && (is_numeric($request->{'height-ft'}) || is_numeric($request->{'height-cm'})) && is_numeric($request->age) && !empty($request->gender)) {
                    $weight = $request->weight;
                    if ($request->unit === 'lbs') {
                        $weight = $weight * 0.453592; // 1 lb = 0.453592 kg
                    }
                
                    // Handle height input
                    $height = 0;
                    if ($request->hightUnit === 'ft/in') {
                        // Convert height from feet/inches to meters
                        $feet = $request->{'height-ft'};
                        $inches = $request->{'height-in'};
                        $height = ($feet * 12 + $inches) * 0.0254; // 1 inch = 0.0254 meters
                    } elseif ($request->hightUnit === 'cm') {
                        $height = $request->{'height-cm'} / 100;
                    }
                
                    $bmi = round($weight / ($height * $height), 2);
                    $age = $request->age;
                    $gender = strtolower($request->gender);
                    if ($gender === 'male') {
                        if( $age <= 18){
                            $bfp = round((1.51 * $bmi) + (0.70 * $age) - 2.2, 2);
                        }else{
                            $bfp = round((1.20 * $bmi) + (0.23 * $age) - 16.2, 2);
                        }
                    } elseif ($gender === 'female') {
                        if( $age <= 18){
                            $bfp = round((1.51 * $bmi) + (0.70 * $age) - 1.4, 2);   
                        }else{
                            $bfp = round((1.20 * $bmi) + (0.23 * $age) - 5.4, 2);
                        }
                    } else {
                        $bfp = 0; // Invalid gender input
                    }
                    
                    if ($request->gender=='Male') {
						if ($bfp<2) {
							$category= "N/A";
							$color="red";
							$left="0%";
						}
						elseif($bfp > 1 &&$bfp<=5){
							$category= "Essential fat";
							$this->param['Essential'] = "blue text-white";
							$color="#0D47A1";
							$left="2%";
						}elseif ($bfp>5 && $bfp<=13) {
							$category= "Athletes";
							$this->param['Athletes'] = "teal text-white";
							$color="#00897B";
							$left="20%";
						}elseif ($bfp > 13 && $bfp<=17) {
							$category= "Fitness";
							$this->param['Fitness'] = "green text-white";
							$color="#00C853";
							$left="40%";
						}elseif ($bfp > 17 && $bfp<=24) {
							$category= "Average";
							$this->param['Average'] = "yellow text-white";
							$color="#FFEA00";
							$left="60%";
						}else{
							$category= "Obese";
							$this->param['Obese'] = "red text-white";
							$color="#FF1744";
							$left="80%";
						}
					}else{
						if ($bfp<0 && $bfp<=9) {
							$category= "N/A";
							$color="red";
							$left="-2%";
						}
						elseif($bfp > 9 &&$bfp<=13){
							$category= "Essential fat";
							$this->param['Essential'] = "blue text-white";
							$color="#0D47A1";
							$left="2%";
						}elseif ($bfp>13 && $bfp<=20) {
							$category= "Athletes";
							$this->param['Athletes'] = "teal text-white";
							$color="#00897B";
							$left="20%";
						}elseif ($bfp > 20 && $bfp<=24) {
							$category= "Fitness";
							$this->param['Fitness'] = "green text-white";
							$color="#00C853";
							$left="40%";
						}elseif ($bfp > 24 && $bfp<=31) {
							$category= "Average";
							$this->param['Average'] = "yellow text-white";
							$color="#FFEA00";
							$left="60%";
						}else{
							$category= "Obese";
							$this->param['Obese'] = "red text-white";
							$color="#FF1744";
							$left="80%";
						}
					}

                
                    // Calculate Fat Weight & Lean Body Mass (LBM)
                    $body_fat_w = round(($bfp / 100) * $weight, 2);
                    $lbm = round($weight - $body_fat_w, 2);

                    $fat_weight_kg = $weight * ($bfp / 100); 
                    $fat_weight_lbs = $fat_weight_kg * 2.205; // Convert to lbs

                    if ($request->unit == 'kg') {
                        $this->param['fat_weight'] =   $fat_weight_kg;
                    } else {
                        $this->param['fat_weight'] =    $fat_weight_lbs;
                    }
                    $this->param['fat_weight_unit'] = $request->unit;
                    $this->param['body_fat'] = $bfp; 
                    $this->param['color'] = $color;
                    $this->param['left'] = $left;
                    $this->param['category'] = $category;
                    $this->param['lbm'] = $lbm . " kg";
                    $this->param['body_fat_w'] = $body_fat_w . " kg";
                    $this->param['RESULT'] = 1;
                    return $this->param;
                } else {
                    $this->param['error'] = 'Please fill all fields.';
                    return $this->param;
                }
                
            }
		}
	}
    // Paracetamol Dosage Calculator
    public function paracetamol($request){
        // dd($request->all());
        $age = $request->age;
        $age_unit = $request->age_unit;
        $weight = $request->weight;
        $weight_unit = $request->weight_unit;
        $med_type = $request->med_type;
        $ss = $request->ss;


        if($age_unit == 'weeks'){
            $age_unit = 0.0191651;
        }else  if($age_unit == 'months'){
            $age_unit = 0.08333;
        }else  if($age_unit == 'years'){
            $age_unit = 1;
        }

 
        if($weight_unit == 'kg'){
            $weight_unit = 1;
        }else  if($weight_unit == 'lbs'){
            $weight_unit = 0.453592;
        }



		if($med_type=="1" || $med_type=="2" || $med_type=="3"){
			if(is_numeric($weight)){
				$weight_val=$weight*$weight_unit;
				if($med_type=="1" || $med_type=="2"){
					if($weight_val>=5 && $weight_val<=7){
					$dose=4;
					}else if($weight_val>=8 && $weight_val<10){
						$dose=5;
					}else if($weight_val>=11 && $weight_val<=14){
						$dose=6;
					}else if($weight_val>=15 && $weight_val<=19){
						$dose=9;
					}else if($weight_val>=20 && $weight_val<=24){
						$dose=12;
					}else if($weight_val>=25 && $weight_val<=29){
						$dose=15;
					}else if($weight_val>=30 && $weight_val<=34){
						$dose=18;
					}else if($weight_val>=35 && $weight_val<=39){
						$dose=21;
					}else if($weight_val>=40 && $weight_val<=44){
						$dose=25;
					}else if($weight_val<=0){
                        $this->param['error'] = 'Child weight should be a positive number.';
                        return $this->param;
					}else if($weight_val>100){
                        $this->param['error'] = 'The maximum value for a child weight is 100 kg or 220 lb.';
                        return $this->param;
					}
				}else if($med_type=="3"){
					if($weight_val>=35 && $weight_val<=49){
						$dose=1;
					}else if($weight_val>=50 && $weight_val<=64){
						$dose=1.5;
					}else if($weight_val>=65 && $weight_val<=100){
						$dose=2;
					}else if($weight_val<=0){
                        $this->param['error'] = 'Child weight should be a positive number.';
                        return $this->param;
					}else if($weight_val>100){
                        $this->param['error'] = 'The maximum value for a child weight is 100 kg or 220 lb.';
                        return $this->param;
					}
				}
				if($age!=""){
					if(is_numeric($age)){
						$age_val=$age*$age_unit;
						if($med_type=="1"){
							if($age_val<1){
                                $this->param['error'] = 'Infant syrup is not suitable for children under the age of 2 months. Consult a doctor for individualised dosing scheme.';
                                return $this->param;
							}else if($age_val>6){
                                $this->param['error'] = 'For children older than 6 years, try <i>Six plus syrup</i>.';
                                return $this->param;
							}
						}else if($med_type=="2"){
							if($age_val<1 && $age_val<6){
                                $this->param['error'] = 'Six plus syrup is not suitable for children under the age of 6 years. Try Infant syrup.';
                                return $this->param;
							}
						}else if($med_type=="3"){
							if($age_val<1 || $age_val<6){
                                $this->param['error'] = 'Tablets not suitable for children under the age of 6 years. Try Infant syrup.';
                                return $this->param;
							}
						}
					}else{
                        $this->param['error'] = 'Please! Check your input.';
                        return $this->param;
					}
				}
				if($med_type=="1" || $med_type=="2"){
					if(($weight_val>=45 && $weight_val<=100) || ($weight_val>=1 && $weight_val<=4)){
					$this->param['line']="The form of medication is not suitable for chosen weight. Try a different type or consult a physician.";	
					}else{
						if($med_type=="1"){
							$this->param['dose']=$dose;
						}else if($med_type=="2"){
							$this->param['dose']=$dose/2;
						}			
					}	
				}else if($med_type=="3"){
					if($weight_val<=34){
						$this->param['line']="The form of medication is not suitable for chosen weight. Try a different type or consult a physician.";	
					}else{
						$this->param['dose']=$dose;
					}
				}
				$fifteen=$weight_val*15;
				$sixty=$weight_val*60;
				if($fifteen>1000){
					$this->param['fifteen']="1000";
				}else{
					$this->param['fifteen']=$weight_val*15;
				}
				if($sixty>4000){
					$this->param['sixty']="4000";
				}else{
					$this->param['sixty']=$weight_val*60;
				}
			}else{
                $this->param['error'] = 'Please! Check your input.';
                return $this->param;
			}
		}else if($med_type=="4"){
			if(is_numeric($weight) && is_numeric($ss)){
				$weight_val=$weight*$weight_unit;
				if($weight<0){
                    $this->param['error'] = 'Child weight should be a positive number.';
                    return $this->param;
				}
				if($weight>100){
                    $this->param['error'] = 'The maximum value for a child weight is 100 kg or 220 lb.';
                    return $this->param;
				}
				if($ss<0){
                    $this->param['error'] = 'Solution strength should be a positive number.';
                    return $this->param;
				}else{
					if($age!=""){
						if($age<0){
                            $this->param['error'] = 'The Infant/Child Age should be a whole (integer) number!';
                            return $this->param;
						}else if($age>=18){
                            $this->param['error'] = 'Please note the infant/child age you specified is over 18 years. This calculator is suitable for infant/child age below 18 years of age.';
                            return $this->param;
						}else{
							$this->param['fifteen']=$weight_val*15;
							$this->param['sixty']=$weight_val*60;
							$this->param['solution_amount']=$this->param['fifteen']/$ss;
						}
					}
				}
			}else{
                $this->param['error'] = 'Please! Check your input.';
                return $this->param;
			}
		}
		$this->param['med_type']=$med_type;
		$this->param['RESULT'] = 1;
        return $this->param;
	}

    // Pediatric Dose Calculator
    public function pediatric($request){
        $dose=$request->dose;
        $dose_unit=$request->dose_unit;
        $dose_unit2=$request->dose_unit2;
        $dose_unit3=$request->dose_unit3;
        $bsa=$request->bsa;
        $weight=$request->weight;
        $weight_unit=$request->weight_unit;
        $mass=$request->mass;
        $mass_unit=$request->mass_unit;
        $per=$request->per;
        $per_unit=$request->per_unit;
        $dose_frequency=$request->dose_frequency;
        $type=$request->type;
        $child_age=$request->child_age;

		function quarter($unit,$value){
			if($unit=="qD"){
				$val1=$value*1;
			}else if($unit=="BID"){
				$val1=$value*2;
			}else if($unit=="TID"){
				$val1=$value*3;
			}else if($unit=="QID"){
				$val1=$value*4;
			}else if($unit=="q8 hr"){
				$val1=$value*3;
			}else if($unit=="q6 hr"){
				$val1=$value*4;
			}else if($unit=="q4 hr"){
				$val1=$value*6;
			}else if($unit=="q3 hr"){
				$val1=$value*8;
			}else if($unit=="q2 hr"){
				$val1=$value*12;
			}else if($unit=="q1 hr"){
				$val1=$value*24;
			}
			return $val1;
		}
		function quarter2($unit,$value){
			if($unit=="qD"){
				$val1=$value/1;
			}else if($unit=="BID"){
				$val1=$value/2;
			}else if($unit=="TID"){
				$val1=$value/3;
			}else if($unit=="QID"){
				$val1=$value/4;
			}else if($unit=="q8 hr"){
				$val1=$value/3;
			}else if($unit=="q6 hr"){
				$val1=$value/4;
			}else if($unit=="q4 hr"){
				$val1=$value/6;
			}else if($unit=="q3 hr"){
				$val1=$value/8;
			}else if($unit=="q2 hr"){
				$val1=$value/12;
			}else if($unit=="q1 hr"){
				$val1=$value/24;
			}
			return $val1;
		}
		function mass_convert($unit2,$value2){
			if($unit2=="mg"){
				$val2=$value2*1;
			}else if($unit2=="µg"){
				$val2=$value2*0.001;
			}else if($unit2=="g"){
				$val2=$value2*1000;
			}
			return $val2;	
		}
		function milli_convert($unit3,$value3){
			if($unit3=="ml"){
				$val3=$value3*1;
			}else if($unit3=="mm³"){
				$val3=$value3*0.001;
			}else if($unit3=="cm³"){
				$val3=$value3*1;
			}else if($unit3=="cu in"){
				$val3=$value3*16.387;
			}else if($unit3=="ml"){
				$val3=$value3*1;
			}else if($unit3=="cl"){
				$val3=$value3*10;
			}else if($unit3=="cc"){
				$val3=$value3*0.1;
			}
			return $val3;
		}
		function weil($unit4,$value4){
			if($unit4=="kg"){
				$val3=$value4*1;
			}else if($unit4=="lbs"){
				$val3=$value4*0.4536;
			}else if($unit4=="g"){
				$val3=$value4*0.001;
			}else if($unit4=="dag"){
				$val3=$value4*0.01;
			}else if($unit4=="oz"){
				$val3=$value4*0.02835;
			}
			return $val3;
		}
		function weil2($unit5,$value5){
			if($unit5=="kg"){
				$val5=$value5*2.2046;
			}else if($unit5=="lbs"){
				$val5=$value5*1;
			}else if($unit5=="g"){
				$val5=$value5*0.001;
			}else if($unit5=="dag"){
				$val5=$value5*0.01;
			}else if($unit5=="oz"){
				$val5=$value5*0.02835;
			}
			return $val5;
		}
		if($type=="first"){
			if(is_numeric($dose) && is_numeric($weight) && is_numeric($mass) && is_numeric($per) && $dose > 0 && $weight > 0 && $mass > 0 && $per > 0){
				$wv=weil($weight_unit,$weight);
				$mv=mass_convert($mass_unit,$mass);
				$perv=milli_convert($per_unit,$per);
				if($dose_unit=="mg/kg" || $dose_unit=="mg/kg/day"){
					$main_answer1=$dose*$wv;
				}else if($dose_unit=="mg/kg/dose"){
					$s1=$dose*$wv;
					$main_answer1=quarter($dose_frequency,$s1);
				}else if($dose_unit=="mcg/kg" || $dose_unit=="mcg/kg/day"){
					$main_answer1=($dose*$wv)/1000;
				}else if($dose_unit=="mcg/kg/dose"){
					$s1=($dose*$wv)/1000;
					$main_answer1=quarter($dose_frequency,$s1);
				}
			}else{
                $this->param['error'] = 'Please! Check your input.';
                return $this->param;
			}
		}else if($type=="second"){
			if(is_numeric($dose) && is_numeric($bsa) && is_numeric($mass) && is_numeric($per) && $dose>0 && $bsa>0 && $mass>0 && $per>0){
			    $mv=mass_convert($mass_unit,$mass);
				$perv=milli_convert($per_unit,$per);
				if($dose_unit2=="mg/m²"){
					$main_answer1=$dose*$bsa;	
				}else if($dose_unit2=="mg/day"){
					$main_answer1=($dose*$bsa)/1.73;	
				}else if($dose_unit2=="mg/dose"){
					$v1=($dose*$bsa)/1.73;
					$main_answer1=quarter($dose_frequency,$v1);	
				}else if($dose_unit2=="mcg/m²"){
					$main_answer1=($dose*$bsa)/1000;	
				}else if($dose_unit2=="mcg/day"){
					$main_answer1=(($dose*$bsa)/1.73)/1000;		
				}else if($dose_unit2=="mcg/dose"){
					$v1=(($dose*$bsa)/1.73)/1000;
					$main_answer1=quarter($dose_frequency,$v1);	
				}
			}else{
                $this->param['error'] = 'Please! Check your input.';
                return $this->param;
			}
		}else if($type=="third"){
			if(is_numeric($dose) && is_numeric($child_age) && is_numeric($mass) && is_numeric($per) && $dose>0 && $child_age>0 && $mass>0 && $per>0){
				$mv=mass_convert($mass_unit,$mass);
				$perv=milli_convert($per_unit,$per);
				if($dose_unit3=="mg/day"){
					$main_answer1=$dose*($child_age/($child_age+12));
				}else if($dose_unit3=="mg/dose"){
					$riz=$dose*($child_age/($child_age+12));
					$main_answer1=quarter($dose_frequency,$riz);	
				}else if($dose_unit3=="mcg/day"){
					$main_answer1=$dose*(($child_age/($child_age+12))/1000);
				}else if($dose_unit3=="mcg/dose"){
					$riz=$dose*($child_age/($child_age+12)/1000);
					$main_answer1=quarter($dose_frequency,$riz);
				}
			}else{
                $this->param['error'] = 'Please! Check your input.';
                return $this->param;
			}
		}else if($type=="fourth"){
			if(is_numeric($dose) && is_numeric($weight) && is_numeric($mass) && is_numeric($per) && $dose>0 && $weight>0 && $mass>0 && $per>0){
				$wv=weil2($weight_unit,$weight);
				$mv=mass_convert($mass_unit,$mass);
				$perv=milli_convert($per_unit,$per);
				if($dose_unit3=="mg/day"){
					$main_answer1=$dose*($wv/150);
				}else if($dose_unit3=="mg/dose"){
					$riz=$dose*($wv/150);
					$main_answer1=quarter($dose_frequency,$riz);
				}else if($dose_unit3=="mcg/day"){
					$riz=$dose*(($wv/150)/1000);
				}else if($dose_unit3=="mcg/dose"){
					$riz=$dose*(($wv/150)/1000);
					$main_answer1=quarter($dose_frequency,$riz);
				}
			}else{
                $this->param['error'] = 'Please! Check your input.';
                return $this->param;
			}
		}
		$ans1=quarter2($dose_frequency,$main_answer1);
		$main_answer3=$mv/$perv;
		$l=$main_answer1/$main_answer3;
		$main_answer4=quarter2($dose_frequency,$l);
		$this->param['mass']=$mass;
		$this->param['mass_unit']=$mass_unit;
		$this->param['per']=$per;
		$this->param['per_unit']=$per_unit;
		$this->param['ans1']=$ans1;
		$this->param['dose_frequency']=$dose_frequency;
		$this->param['main_answer1']=$main_answer1;
		$this->param['main_answer3']=$main_answer3;
		$this->param['main_answer4']=$main_answer4;
		$this->param['RESULT'] = 1;

        return $this->param;
	}

