                    $days = 0;
        
                }else if($days =='Conception'){
                    $days = 266;
        
                }else if($days =='IVF'){
                    $days = 266;
        
                }else if($days =='Ultrasound'){
                    $days = 250;
                }



                // dd($request->ivf);
				$days=266 - $days;
				$due_date=date('Y-m-d', strtotime($year."-".$month."-".$day. '+ '.$days.' days'));
				$modi_ageEsimated=strtotime($year."-".$month."-".$day. '+ '.$days.' days');
				$ovu_date=date('M d, Y', strtotime($due_date."- 38 weeks"));
				$modi_ageEsimated = date("m/d/Y", $modi_ageEsimated);
				$bday = new \DateTime(date('d.M.Y', strtotime($modi_ageEsimated. '- 280 days'))); // Your date of birth
