					}
					if (isset($request->days)) {
						$days=$request->days;
					} else {
						$days=0;
					}
					$preglenght= 40 * 7;
					$days= ($weeks * 7) + $days;
					$preg=date('Y-m-d',strtotime($year."-".$month."-".$day. '- '.$days.' days'));
