					}
					$days=($months * 30.417) + $diff->d;
					$weeksRemaining= floor($days / 7);
					$daysRemaining= floor(($days % 7));

				} else {
                    $this->param['error'] = 'Please enter weeks or days.';
                    return $this->param;
				}
				
			}
		$today=date('m/d/Y');
		if (strtotime($today)>strtotime($modi_ageEsimated)) {
            $this->param['error'] = 'You are not pregnant yet.';
            return $this->param;
		}
		// alerts
		if(empty($fieldsDone))
		{
            $this->param['error'] = 'Please Fill All Fields.';
            return $this->param;
		}
		if ($weeksRemaining>=0 && $weeksRemaining<5) {
