			$min_weight_gain = round($min_weight/2.205, 1);
			$max_weight_ans = $max_weight_gain + $weight;
			$min_weight_ans = $min_weight_gain + $weight;
			foreach ($data[$activity] as $value) {
				$min = $value[$offset];
	    		$max = $value[$offset + 1];
	    		$min_w = $weight + $min;
	    		$max_w = $weight + $max;
	    		$gain[] = $min." - ".$max." kg";
	    		$all[] = $min_w." - ".$max_w." kg";
			}
