		$this->param['min_weight_gain'] = $min_weight_gain;
		$this->param['max_weight_gain'] = $max_weight_gain;
        $this->param['BMI'] = $BMI;
        $this->param['you_are'] = $you_are;
        $this->param['gain'] = $gain;
        $this->param['all'] = $all;
        $this->param['RESULT'] = 1;
        return $this->param;
    }

    // Prostate Volume Calculator
    public function prostate($request){
        // dd($request->all());
        $length = $request->length;
        $length_unit = $request->length_unit;
        $width = $request->width;
        $width_unit = $request->width_unit;
        $height = $request->height;
        $height_unit = $request->height_unit;
        $psa = $request->psa;
        

        if($length_unit == 'mm'){
            $length_unit = 10;
        }else if($length_unit == 'cm'){
            $length_unit = 1;
        }else if($length_unit == 'dm'){
            $length_unit = 0.1;
        }else if($length_unit == 'm'){
            $length_unit = 0.01;
        }else if($length_unit == 'km'){
            $length_unit = 0.00001;
        }else if($length_unit == 'mi'){
