    // Protein Caluclator
    public function protein($request){
        //  dd($request->all());
        $age = $request->age;
        $gender = $request->gender;
        $weight = $request->weight;
        $weight_unit = $request->weight_unit;
        $activity_level = $request->activity_level;
        $protein_for = $request->protein_for;
        $height_ft = $request->height_ft;
        $height_in = $request->height_in;
        $height_cm = $request->height_cm;
        $h_unit = $request->unit_ft_in;

        function convert_to_cm($unit, $value){
            if ($unit === 'cm') {
                $ans = $value;
            }elseif ($unit === 'in') {
                $ans = $value * 2.54;
            }elseif ($unit === 'm') {
                $ans = $value * 100;
            }elseif ($unit === 'ft') {
                $ans = $value * 30.48;
            }
            return $ans;
        }

        function convert_to_kg($unit, $value){
            if ($unit == 'g') {
                $ans = $value / 1000;
            }elseif ($unit == 'kg') {
                $ans = $value;
            }elseif ($unit == 'lb') {
                $ans = $value /  2.205;
            }elseif ($unit == 'stone') {
                $ans = $value * 6.35;
            }
            return $ans;
        } 
        if($h_unit == 'ft/in'){
            if(is_numeric($height_ft) && is_numeric($height_in)){
                $ft_to_cm  = $height_ft * 30.48;
                $in_to_cm  = $height_in * 2.54;
                $height_cm = $ft_to_cm + $in_to_cm;
            }else{
                $this->param['error'] = 'Please! Check your input.';
                return $this->param;
            }
        }else{
            if(is_numeric($height_cm)){
                $height_cm = convert_to_cm($h_unit, $height_cm);
            }else{
                $this->param['error'] = 'Please! Check your input.';
                return $this->param;
            }
        }
        

        if(is_numeric($age) && is_numeric($weight)){
            $weight_kg = convert_to_kg($weight_unit, $weight);
            if($gender == 'male'){
                $BMR = (10 * $weight_kg) + (6.25 * $height_cm) - (5 * $age) + 5;
            }else{
                $BMR = (10 * $weight_kg) + (6.25 * $height_cm) - (5 * $age) - 161;
            }

            if($activity_level == 'sedentary'){
                $calories = $BMR * 1.2;
            }else if($activity_level == 'light'){
                $calories = $BMR * 1.375;
            }else if($activity_level == 'moderate'){
                $calories = $BMR * 1.550;
            }else if($activity_level == 'very_active'){
                $calories = $BMR * 1.725;
            }else{
                $calories = $BMR * 1.9;
            }
            $this->param['calories'] = $calories;
            $this->param['weight_kg'] = $weight_kg;
            $this->param['RESULT'] = 1;
            return $this->param;
        }else{
            $this->param['error'] = 'Please! Check your input.';
            return $this->param;
        }
    }

	// RMR Calculator
	public function rmr($request){
        // dd($request->all(),$request->weight);
		if (is_numeric($request->age) && is_numeric($request->weight ) || is_numeric($request->height_ft) || is_numeric($request->height_in) || is_numeric($request->height_cm)) {
			$age=$request->age;
			$weight=$request->weight;
			$height_ft=$request->height_ft;
			$height_in=$request->height_in;
			$height_cm=$request->height_cm;
			if ($request->unit==="lbs") {
				$weight = $weight / 2.205;
			}
			if ($request->unit_h==='ft/in') {
				$height_cm=$height_ft * 30.48;
				if ($height_in!=null) {
					$height_in= $height_in * 2.54;
					$height_cm=$height_cm + $height_in;
				}
			}
			if ($request->gender==='Female') {
				// $rmr= round((9.99 * $weight) + (6.25 * $height_cm) - (4.92 * $age) - 161,2);
				$rmr=round( 655 + (9.6 * $weight) + (1.8 * $height_cm) - (4.7 * $age),2);
			} else {
				// $rmr= round((9.99 * $weight) + (6.25 * $height_cm) - (4.92 * $age) + 5,2);
				$rmr=round( 66 + (13.7 * $weight) + (5 * $height_cm) - (6.8 * $age),2);
			}
			// return 
			$this->param['RMR'] = $rmr;
			$this->param['RESULT'] = 1;
            // dd($this->param);
            return $this->param;
		} else {
            $this->param['error'] = 'Please fill All fields.';
            return $this->param;
		}
	}

