    // Target Heart Rate Calculator
	public function target($request){
        // dd($request->all());
		if ($request->method!='3' && is_numeric($request->age)) {
			$age=$request->age;
			if ($request->formula==1) {
				$mhr=220 - $age;
			}elseif ($request->formula==2) {
				$mhr=226 - $age;
			}elseif ($request->formula==3) {
				$mhr=205.8 - (0.685 *$age);
			}elseif ($request->formula==4) {
				$mhr=206.3 - (0.711 * $age);
			}elseif ($request->formula==5) {
				$mhr=217 - (0.85 * $age);
			}elseif ($request->formula==6) {
				$mhr=208 - (0.7 * $age);
			}elseif ($request->formula==7) {
				$mhr=206.9 - (0.67 * $age);
			}elseif ($request->formula==8) {
				$mhr=211 - (0.64 * $age);
			}elseif ($request->formula==9) {
				$mhr=203.7 / (1 + pow(2.718281828459045235360,(0.033 * ($age - 104.3))));
			}elseif ($request->formula==10) {
				$mhr=190.2 / (1 + pow(2.718281828459045235360,(0.0453 * ($age - 107.5))));
			}elseif ($request->formula==11) {
				$mhr=206 - (0.88 * $age);
			}
		}else{
			$age=$request->age;
			$mhr=220 - $age;
		}
		if ($request->method==='1') {
			if (is_numeric($request->age) && is_numeric($request->percent)) {
				$this->param['mhr'] = $mhr;
				$this->param['RESULT'] = 1;

                return $this->param;
			} else {
                $this->param['error'] = 'Please fill All fields.';
                return $this->param;
			}
		}elseif ($request->method==='2') {
			if (is_numeric($request->age) && is_numeric($request->rhr) && is_numeric($request->percent)) {
				$rhr=$request->rhr;
				$this->param['mhr'] = $mhr;
				$this->param['rhr'] = $rhr;
				$this->param['RESULT'] = 1;
                return $this->param;
			} else {
                $this->param['error'] = 'Please fill All fields.';
                return $this->param;
			}
		}elseif ($request->method==='3') {
			if (is_numeric($request->mhr) && is_numeric($request->rhrm) && is_numeric($request->percent)) {
				$mhr=$request->mhr;
				$rhr=$request->rhr;
				$this->param['mhr'] = $mhr;
				$this->param['rhr'] = $rhr;
				$this->param['RESULT'] = 1;
                return $this->param;
			} else {
                $this->param['error'] = 'Please fill All fields.';
                return $this->param;
			}
		}elseif ($request->method==='4') {
			if (is_numeric($request->age) && is_numeric($request->hrr) && is_numeric($request->percent)) {
				$hrr=$request->hrr;
				$rhr=$mhr - $hrr;
				$this->param['mhr'] = $mhr;
				$this->param['rhr'] = $rhr;
				$this->param['RESULT'] = 1;
                return $this->param;
			} else {
                $this->param['error'] = 'Please fill All fields.';
                return $this->param;
			}
		}
	}

