            $bw_unit =  0.4536;

        }else if($bw_unit == 'stone'){
            $bw_unit =  6.35;
        }


            if($bv_unit == 'ml'){
            $bv_unit =  1;
        }else if($bv_unit == 'cl'){
            $bv_unit =  10;
        }else if($bv_unit == 'l'){
            $bv_unit =  1000;
        }

        if($drug_unit == 'µg'){
            $drug_unit =  0.001;
        }else if($drug_unit == 'mg'){
            $drug_unit =  1;
        }else if($drug_unit == 'g'){
            $drug_unit =  1000;

        }

           if($dp_unit == 'gtts/mm³'){
            $dp_unit =  1000;
        }else if($dp_unit == 'gtts/cm³'){
            $dp_unit =  1;
        }else if($dp_unit == 'gtts/ml'){
            $dp_unit =  1;

        }



		if($type=="first"){
			if(is_numeric($v) && is_numeric($t) && is_numeric($dp) && $v>0 && $t>0 && $dp>0){
				$v_val=$v*$v_unit;
				$t_val=$t*$t_unit;
				$dp_val=$dp*$dp_unit;
				$dpm=($v_val*$dp_val)/($t_val);
				$dph=($v_val*$dp_val)/($t_val/60);
				$dr=$dph/$dp_val;
				$this->param['dpm']=$dpm;
				$this->param['dph']=$dph;
			}else{
                $this->param['error'] = 'Please! Check Your Input.';
                return $this->param;
			}
		}else if($type=="second"){
			if(is_numeric($d) && is_numeric($bw) && is_numeric($bv) && is_numeric($drug) && is_numeric($dp) && $d>0 && $bw>0 && $bv>0 && $drug>0 && $dp>0){
				$d_val=$d*$d_unit;
				$bw_val=$bw*$bw_unit;
				$bv_val=$bv*$bv_unit;
				$drug_val=$drug*$drug_unit;
				$dp_val=$dp*$dp_unit;
				if($bw_val>0 && $bw_val<300){
					$dr=(60*$d_val/1000*$bw_val*$bv_val)/(1000*$drug_val)*1000000;
					$concentration=($drug_val/$bv_val)*1000;
					$time_to_bag=(($d_val*$bw_val)*60)/$drug_val;
					$flow_rate=$dr*$dp_val;
					$this->param['concentration']=$concentration;
					$this->param['time_to_bag']=$time_to_bag;
					$this->param['flow_rate']=$dr*$dp_val;
				}else{
                    $this->param['error'] = 'Body weight great than 0 and less than 300 kg.';
                    return $this->param;
				}
			}else{
                $this->param['error'] = 'Please! Check Your Input.';
                return $this->param;
			}
		}
		$this->param['dr']=$dr;
		$this->param['type']=$type;
		$this->param['RESULT'] = 1;
        return $this->param;
	}

    // VO2 Max calculator
	public function vo2($request){
        //  dd($request->all());
        $methods = $request->methods;
        $operations1 = $request->operations1;
        $operations2 = $request->operations2;
        $first = $request->first;
        $second = $request->second;
        $units2 = $request->units2;
        $third = $request->third;
        $units3 = $request->units3;
        $four = $request->four;


        if($units2 == 'kg'){
            $units2 = 1;
        }else if($units2 == 'lbs'){
            $units2 = 2;
        }

        if($units3 == 'sec'){
            $units3 = 1;
        }else if($units3 == 'min'){
            $units3 = 2;
        }

	    function kilo($a,$b){
	    	if($a == "1"){
				$wazan = $b * 2.205;
			}elseif ($a == "2") {
				$wazan = $b * 1;
			}
			return $wazan;
	    }
	    function secint($a,$b){
	    	if($a == "1"){
				$convert2 = $b / 60;
			}elseif ($a == "2") {
				$convert2 = $b * 1;
			}
			return $convert2;
	    }
	    $second = kilo($units2,$second);
	    $third = secint($units3,$third);
	    if ($methods == "1") {
	    	if (is_numeric($first) && is_numeric($four)) {
	    		$mul1 = 0.7 * $first;
	    		$mhr = 208 - $mul1;
	    		$rhr = $four * 3;
	    		$divide = $mhr / $rhr;
	    		$answer = 15.3 * $divide;
	    	}else{
                $this->param['error'] = 'Please! Check Your Input.';
                return $this->param;
			}
	    }else if ($methods == "2") {
	    	if (is_numeric($first) && is_numeric($second) && is_numeric($third) && is_numeric($four)) {
	    		if($operations1 == 1){
					$answer = 132.853-(0.0769*$second)-(0.3877*$first)+(6.315*1)-(3.2649*$third)- (0.1565*$four*6);
				}else if($operations1 == 0){
					$answer = 132.853-(0.0769*$second)-(0.3877*$first)-(3.2649*$third)- (0.1565*$four*6);
				}
	    	}else{
                $this->param['error'] = 'Please! Check Your Input.';
                return $this->param;
			}
	    }else if ($methods == "3") {
	    	if (is_numeric($four)) {
	    		if($operations1 == 1){
					$answer = 111.33 - (0.42 * $four * 4);
				}else if($operations1 == 0){
					$answer = 65.81 - (0.1847 * $four * 4);
				}
	    	}else{
                $this->param['error'] = 'Please! Check Your Input.';
                return $this->param;
			}
	    }else if ($methods == "4") {
	    	if (is_numeric($third)) {
				$answer = (483 / $third) + 3.5;
	    	}else{
                $this->param['error'] = 'Please! Check Your Input.';
                return $this->param;
			}
	    }else if ($methods == "5") {
	    	if (is_numeric($second) && is_numeric($third)) {
	    		$second = $second * 0.45359237; //lb -> kg
				if($operations1 == 1){
					if($operations2 == 2){
						if($second <= 75.0){
							$answer = ((15.1 - (1.5 * $third)) * 1000) / $second;
						}else if($second > 75.0){
							$answer = ((15.7 - (1.5 * $third)) * 1000) / $second;
						}
					}else if($operations2 == 1){
						$answer = ((10.7 - (0.9 * $third)) * 1000) / $second;
					}
				}else if($operations1 == 0){
					if($operations2 == 2){
						if($second <= 61.36){
							$answer = ((14.6 - (1.5 * $third)) * 1000) / $second;
						}else if($second > 61.36){
							$answer = ((14.9 - (1.5 * $third)) * 1000) / $second;
						}
					}else if($operations2 == 1){
						$answer = ((10.26 - (0.93 * $third)) * 1000) / $second;
					}
				}
	    	}else{
                $this->param['error'] = 'Please! Check Your Input.';
                return $this->param;
	    	}
	    }
		$this->param['answer'] = $answer;						
		$this->param['RESULT'] = 1;
        return $this->param;
	}

    // Weight Loss Percentage Calculator
	public function weight($request){
        $inw=$request->inw;
        $crw=$request->crw;
        $unit1=$request->unit1;
        $unit=$request->unit;

     

		if (is_numeric($inw) && is_numeric($crw)){
			if ($unit == "lbs") {
				$inw_lbs = $inw;
				$inw_kg =$inw / 2.20462;
			}else{
				$inw_lbs =$inw * 2.20462;
				$inw_kg = $inw;
			}
			if ($unit1 == "lb") {
				$crw_lbs = $crw;
				$crw_kg =$crw / 2.20462;
			}else{
				$crw_lbs =$crw * 2.20462;
				$crw_kg = $crw;
			}
			if ($unit == $unit1) {
				$pw=round(($inw-$crw)/$inw*100,2);
				$wg=$crw-$inw."  ".$unit1;
			}else{
				if ($unit=='kg') {
					$inw=$inw*2.20462;
				}
				if ($unit1=='lbs') {
					$crw=$crw*2.20462;
				}
				$pw=round(($inw-$crw)/$inw*100,2);
				$wg=$crw-$inw." "."lbs";
			}
			$this->param['pw']=$pw;
			$this->param['wg']=$wg;
			$this->param['inw_lbs']=number_format($inw_lbs, 2);
			$this->param['inw_kg']=number_format($inw_kg, 2);
			$this->param['crw_lbs']=number_format($crw_lbs, 2);
			$this->param['crw_kg']=number_format($crw_kg, 2);
			$this->param['RESULT'] = 1;
            return $this->param;
		}else{
            $this->param['error'] = 'Please! Check Your Input.';
            return $this->param;
		}
	}

	// Wilks Calculator
	public function wilks($request){
        // dd($request->all());
        $sex=$request->sex;
        $method=$request->method;
        $bw=$request->bw;
        $unit=$request->unit;
        $bp=$request->bp;
        $bp_reps=$request->bp_reps;
        $bs=$request->bs;
        $bs_reps=$request->bs_reps;
        $dl=$request->dl;
        $dl_reps=$request->dl_reps;
        $wl=$request->wl;

        if(is_numeric($bw) && is_numeric($bp) && is_numeric($bs) && is_numeric($dl) && is_numeric($wl) && is_numeric($bp_reps) && is_numeric($bs_reps) && is_numeric($dl_reps) && !empty($sex) && !empty($method) && !empty($unit)){
			if($method==='au'){
                if($unit==='lbs'){
					$bw=$bw*0.4536;
					$wl=$wl*0.4536;
					$this->param['lb'] = round($bw,2);
					$this->param['lb1'] = round($wl,2);
				}
				if(is_numeric($bw) && is_numeric($wl)){
					if($sex==='male'){
						$ws_cal=500/((-216.0475144)+16.2606339*pow($bw,1)+(-0.002388645)*pow($bw,2)+(-0.00113732)* pow($bw,3)+0.00000701863*pow($bw,4)+(-1.291e-8)*pow($bw,5));
						$ws=$wl*$ws_cal;
					}elseif($sex==='female'){
						$ws_cal=500/(594.31747775582+(-27.23842536447)*pow($bw,1)+0.82112226871*pow($bw,2)+(-0.00930733913)* pow($bw,3)+0.00004731582*pow($bw,4)+(-9.054e-8)*pow($bw,5));
						$ws=$wl*$ws_cal;
					}
					$this->param['ws_cal'] = round($ws_cal,3);
					$this->param['ws'] = round($ws,2);
					$this->param['RESULT'] = 1;
                    return $this->param;
				}else{
                    $this->param['error'] = 'Please Fill All The Fields.';
                    return $this->param;
				}
			}elseif($method==='sep'){
				if($unit==='lbs'){
					$bw=$bw*0.4536;
					$bp=$bp*0.4536;
					$bs=$bs*0.4536;
					$dl=$dl*0.4536;
					$this->param['lb'] = round($bw,2);
				}
				if(is_numeric($bw) && is_numeric($bp) && is_numeric($bs) && is_numeric($dl)){
					if($sex==='male'){
					 	$bpw=$bp*(1+($bp_reps/30));
					 	$bsw=$bs*(1+($bs_reps/30));
					 	$dlw=$dl*(1+($dl_reps/30));
					 	$fw=$bpw+$bsw+$dlw;
						$ws_cal=500/((-216.0475144)+16.2606339*pow($bw,1)+(-0.002388645)*pow($bw,2)+(-0.00113732)* pow($bw,3)+0.00000701863*pow($bw,4)+(-1.291e-8)*pow($bw,5));
						$ws=$fw*$ws_cal;
					}elseif($sex==='female'){
					 	$bpw=$bp*(1+($bp_reps/30));
					 	$bsw=$bs*(1+($bs_reps/30));
					 	$dlw=$dl*(1+($dl_reps/30));
					 	$fw=$bpw+$bsw+$dlw;
						$ws_cal=500/(594.31747775582+(-27.23842536447)*pow($bw,1)+0.82112226871*pow($bw,2)+(-0.00930733913)* pow($bw,3)+0.00004731582*pow($bw,4)+(-9.054e-8)*pow($bw,5));
						$ws=$fw*$ws_cal;
					}
					$this->param['lb1'] = round($fw,2);
					if($unit==='lbs'){
						$fw=$fw/0.4536;
					}
					$this->param['ws_cal'] = round($ws_cal,3);
					$this->param['ws'] = round($ws,2);
					$this->param['fw'] = round($fw,2);
					$this->param['RESULT'] = 1;
                    return $this->param;
				}else{
                    $this->param['error'] = 'Please Fill All The Fields.';
                    return $this->param;
				}
			}
		}else{
            $this->param['error'] = 'Please! Check Your Input.';
            return $this->param;
		}
	}

    // Weight Watchers Points Calculator
    public function weight_watchers($request){
        //  dd($request->all());
        $fe=trim($request->fe);
        $fe_unit=trim($request->fe_unit);
        $sf=trim($request->sf);
        $sf_unit=trim($request->sf_unit);
        $sgr=trim($request->sgr);
        $sgr_unit=trim($request->sgr_unit);
        $ptn=trim($request->ptn);
        $ptn_unit=trim($request->ptn_unit);
        $ptn2=trim($request->ptn2);
        $ptn2_unit=trim($request->ptn2_unit);
        $carbo=trim($request->carbo);
        $carbo_unit=trim($request->carbo_unit);
        $fat=trim($request->fat);
        $fat_unit=trim($request->fat_unit);
        $fiber=trim($request->fiber);
        $fiber_unit=trim($request->fiber_unit);
        $fat2=trim($request->fat2);
        $fat2_unit=trim($request->fat2_unit);
        $fiber2=trim($request->fiber2);
        $fiber2_unit=trim($request->fiber2_unit);
        $call2=trim($request->call2);
        $call2_unit=trim($request->call2_unit);
        $selection=trim($request->selection);
        $weight=trim($request->weight);
        $weight_unit=trim($request->weight_unit);
        $height=trim($request->height);
        $height_unit=trim($request->height_unit);
        $age=trim($request->age);
        $gender=trim($request->gender);
        $activity=trim($request->activity);


        if($fe_unit=="cal"){
            $fe_unit = 1;
        }else if($fe_unit=="kJ"){
            $fe_unit = 0.239006;
        }else if($fe_unit=="J"){
            $fe_unit = 0.1434;
        }

        if($call2_unit=="cal"){
            $call2_unit = 1;
        }else if($call2_unit=="kJ"){
            $call2_unit = 0.239006;
        }else if($call2_unit=="J"){
            $call2_unit = 0.1434;
        }
        if($weight_unit=="kg"){
            $weight_unit = 1;
        }else if($weight_unit=="lbs"){
            $weight_unit = 0.453592;
        }

        if($height_unit=="in"){
            $height_unit = 0.0254;
        }else if($height_unit=="cm"){
            $height_unit = 1;
        }

        function convert_grams($unit,$value){
            if($unit=="mg"){
                $val=$value/1000;
            }else if($unit=="g"){
                $val=$value/1;
            }else if($unit=="kg"){
                $val=$value/0.001;
            }else if($unit=="oz"){
                $val=$value/0.03527396194958;
            }else if($unit=="lbs"){
                $val=$value/0.002204622621849;
            }else if($unit=="dr"){
                $val=$value/0.5643833911933;
            }else if($unit=="gr"){
                $val=$value/15.43235835294;
            }
            return $val;
        }
        if($selection=="1"){
            if(is_numeric($fe) && is_numeric($sf) && is_numeric($sgr) && is_numeric($ptn) && $fe>0 && $sf>0 && $sgr>0 && $sgr>0){
            $fev=$fe_unit*$fe;
            $sfv=convert_grams($sf_unit,$sf);
            $sgrv=convert_grams($sgr_unit,$sgr);
            $ptnv=convert_grams($ptn_unit,$ptn);
            $ans=round(($fev*0.0305+$sfv*0.275+$sgrv*0.12-$ptnv*0.098));
            }else{
                $this->param['error'] = 'Please! Check Your Input.';
                return $this->param;
            }	
        }else if($selection=="2"){
            if(is_numeric($ptn2) && is_numeric($fat) && is_numeric($fiber) && is_numeric($carbo) && $ptn2>0 && $fat>0 && $fiber>0 && $carbo>0){
            $ptn2_val=convert_grams($ptn2_unit,$ptn2);
            $fatv=convert_grams($fat_unit,$fat);
            $fiberv=convert_grams($fiber_unit,$fiber);
            $carbov=convert_grams($carbo_unit,$carbo);
            $ans=round(($fatv/3.8889) + ($carbov/ 9.2105) + ($ptn2_val/ 10.9375) - ($fiberv / 12.5));
            }else{
                $this->param['error'] = 'Please! Check Your Input.';
                return $this->param;
            }
        }else if($selection=="3"){
            if(is_numeric($fat2) && is_numeric($fiber2) && is_numeric($call2) && $fat2>0 && $fiber2>0 && $call2>0){
            $fat2v=convert_grams($fat2_unit,$fat2);
            $fiber2v=convert_grams($fiber2_unit,$fiber2);
            $call2v=$call2_unit*$call2;
            if($fiber2v > 4)
            {
                $fiber2v = 4;
            }
            $ans =round(($call2v / 50) +($fat2v / 12) - ($fiber2v / 5));
            }else{
                $this->param['error'] = 'Please! Check Your Input.';
                return $this->param;
            }
        }else if($selection=="4"){
            if(is_numeric($height) && is_numeric($weight) && is_numeric($age)){
                if($age>=19){
                    if($gender== "male"){
                        $base = 864; 
                        $agefact = 9.72; 
                        $actfact = 1.12; 
                        $wgtfact = 14.2; 
                        $hgtfact = 503; 
                    }else{
                        $base = 387; 
                        $agefact = 7.31; 
                        $actfact = 1.14; 
                        $wgtfact = 10.9; 
                        $hgtfact = 660.7;
                    }
                    $totage=($age * $agefact);
                    $wgtKG = ($weight * $weight_unit);
                    $totwgt = ($wgtKG * $wgtfact);
                    $hgtCM = ($height * $height_unit);
                    $tothgt = ($hgtCM * $hgtfact);
                    $tee1 = (($totwgt + $tothgt)* ($actfact));
                    $tee2 = ($base - $totage + $tee1);
                    $atee1 = (($tee2 * 0.1) - 200);
                    $atee2 = ($tee2 - $atee1);
                    $targ1 = (($atee2 - 1000) / 35);
                    $ans=round($targ1 -11);
                    if ($ans <= 26) {
                        $ans=26;
                    }else if ($ans>=71){
                        $ans=71;
                    }else{
                        $ans;
                    }
                    if($activity=="1"){
                        $ans=$ans+0;
                    }else if($activity=="2"){
                        $ans=$ans+3;
                    }else if($activity=="3"){
                        $ans=$ans+6;
                    }else if($activity=="4"){
                        $ans=$ans+9;
                    }
                }else{
                    $this->param['error'] = 'This calculator is for people aged 19 or older.';
                    return $this->param;
                }
            }else{
                $this->param['error'] = 'Please! Check Your Input.';
                return $this->param;
            }
        }
        $this->param['method']=$selection;
        $this->param['ans']=$ans;
        $this->param['RESULT'] = 1;
        return $this->param;
    }

	// Water Intake Calculator
	public function water($request){
        $gender = $request->gender;
        $weight = $request->weight;
        $weather = $request->weather;
        $unit = $request->unit;
        $activity = $request->activity;

		if (is_numeric($weight)) {
			if ($unit==="kg") {
				$weight = $weight * 2.205;
			}
			if ($gender==='Female') {
				$tdee=round($weight * 0.45,1);
			} elseif($gender=='Male') {
				$tdee=round(($weight * 0.5),1);
			}
			$add=0;
			if ($activity !='0') {
				$plus=round($tdee * $activity ,1);
				$add+=$plus;
			}
			if ($weather!='0') {
				$plus=round($tdee * $weather,1);
				$add+=$plus;
			}
			$tdee=round($tdee + $add,1);
			$im_ounce= round($tdee * 1.04084,1);
			$us_ounce= $tdee;
			$tdee = round($tdee * 29.5735,1);
			$cups= round($tdee / 237,1);
			$liter= round($tdee / 1000,1);
			// return 
			$this->param['water'] = $tdee;
			$this->param['us_ounce'] = $us_ounce + 1;
			$this->param['im_ounce'] = $im_ounce;
			$this->param['cups'] = $cups + 1;
			$this->param['liter'] = $liter;
			$this->param['RESULT'] = 1;
            return $this->param;
		} else {
            $this->param['error'] = 'Please Fill All The Fields.';
            return $this->param;
		}
		
	}

