                    ["70-73","71-74","71-75","72-76","72-75","70-73"],
                    ["74-81","75-81","76-62","77-83","76-81","74-79"],
                    ["82+","82+","83+","84+","82+","80+"]];
                } else {
                    $NHR = [["54-60","54-59","54-59","54-60","54-59","54-59"],
                    ["61-65","60-64","60-64","61-65","60-64","60-64"],
                    ["66-69","65-68","65-69","66-69","65-68","65-68"],
                    ["70-73","69-72","70-73","70-73","69-73","69-72"],
                    ["74-78","73-76","74-78","74-77","74-77","73-76"],
                    ["79-84","77-82","79-84","78-83","78-83","77-84"],
                    ["85+","83+","85+","84+","84+","84+"]];	
                } 
                if($age<18){
                    $res_normal = "Normal Heart Rate Cannot be calculated under age 18";
                    $res = [];
                    $res[0] ="";
                    $res[1] ="";
                    $res[2] ="";
                    $res[3] ="";
                    $res[4] ="";
                    $res[5] ="";
                    $res[6] ="";
                } else if($age >=18 && $age<=25){
                    for($i=0;$i<7;$i++){
                        $res[$i] = $NHR[$i][0];
                    }
                    $res_normal="";
                } else if($age >=26 && $age<=35){
                    for($i=0;$i<7;$i++){
                        $res[$i] = $NHR[$i][1];
                    }
                    $res_normal="";
                } else if($age >=36 && $age<=45){
                    for($i=0;$i<7;$i++){
                        $res[$i] = $NHR[$i][2];
                    }
                    $res_normal ="";
                } else if($age >=46 && $age<=55){
                    for($i=0;$i<7;$i++){
                        $res[$i] = $NHR[$i][3];
                    }
                    $res_normal="";
                } else if($age >=56 && $age<=65){
                    for($i=0;$i<7;$i++){
                        $res[$i] = $NHR[$i][4];
                    }
                    $res_normal="";
                } else if($age >=66){
                    for($i=0;$i<7;$i++){
                        $res[$i] = $NHR[$i][5];
                    }
                    $res_normal="";
                } else{
                    $res_normal = "Invalid Age";
                    $res[] ="";
                }
                if(is_numeric($RHR)){
                    $HRR = $MHR - $RHR;
                }else{
                    $RHR ="";
                    $HRR ="";
                }
                // -----60-80% method----------
                $percent_lower = ($MHR*60)/100;
                $percent_upper = ($MHR*80)/100;
                // ----------------------------
                // -----Zoladz method----------
                $zoladz_lower = $MHR - 50 - 5;
                $zoladz_upper = $MHR - 40 + 5; 
                // ----------------------------
                if(is_numeric($RHR)){
                    $karvonen_lower = (($HRR*60)/100) + $RHR;
                    $karvonen_upper = (($HRR*80)/100) + $RHR;
                }else{
                    $karvonen_lower ="";
                    $karvonen_upper ="";
                }
            }else{
                $this->param['error'] = 'Age Must be less then 150.';
                return $this->param;
            }

            $this->param['percent_lower'] = round($percent_lower,4);
            $this->param['percent_upper'] = round($percent_upper,4);
            $this->param['MHR'] = $MHR;
            $this->param['HRR'] = $HRR;
            $this->param['zoladz_lower'] = $zoladz_lower;
            $this->param['zoladz_upper'] = $zoladz_upper;
            $this->param['karvonen_lower'] = $karvonen_lower;
            $this->param['karvonen_upper'] = $karvonen_upper;
            // $this->param['flag'] = $flag;
            $this->param['res_normal'] = $res_normal;
            $this->param['res0'] = $res[0];
            $this->param['res1'] = $res[1];
            $this->param['res2'] = $res[2];
            $this->param['res3'] = $res[3];
            $this->param['res4'] = $res[4];
            $this->param['res5'] = $res[5];
            $this->param['res6'] = $res[6];
            $this->param['RESULT'] = 1;
            return $this->param;
        }else{
            $this->param['error'] = 'Please! Check Your Input.';
            return $this->param;
        }
	}

    // LDL Calculator
    public function ldl($request){
        $total = $request->total;
        $total_unit = $request->total_unit;
        $high = $request->high;
        $high_unit = $request->high_unit;
        $triglycerides = $request->triglycerides;
        $triglycerides_unit = $request->triglycerides_unit;

		function unit_convert($a,$b){
			if($a == "mg/dL"){
				$result = $b * 0.02586;
			}elseif ($a == "mmol/L") {
				$result = $b;
			}
			return $result;
		}
		$total = unit_convert($total_unit,$total);
		$high = unit_convert($high_unit,$high);
		$triglycerides = unit_convert($triglycerides_unit,$triglycerides);
		if(is_numeric($total) && is_numeric($high) && is_numeric($triglycerides)) {
			$ldl_mmoll = $total - $high - 0.2 * $triglycerides;
			$ldl_mgdL = $ldl_mmoll * 38.7;
		}else{
            $this->param['error'] = 'Please! Check Your Input.';
            return $this->param;
		}
		$this->param['ldl_mmoll'] = $ldl_mmoll;
		$this->param['ldl_mgdL'] = $ldl_mgdL;
        $this->param['RESULT'] = 1;
        return $this->param;
    }
    
    // A1C Calculator
    public function a1c($request){

        // dd($request->all());
        $solve = $request->solve;
        $input = $request->input;
        $unit1 = $request->unit1;
        $unit2 = $request->unit2;

        if($unit1 == '%'){
            $unit1 = "1";
        }else if($unit1 == 'mmol/mol'){
            $unit1 = "2";
        }
        if($unit2 == 'mmol/L'){
            $unit2 = "1";
        }else if($unit2 == 'mg/dL'){
            $unit2 = "2";
        }
        function ac_unit($unit, $value){
            if ($unit === '1') {
                $ans = $value * 1;
            }else{
                $ans = $value * 0.09148 + 2.152;
            }
            return $ans;
        }
        function blood_unit($unit, $value){
            if ($unit === '1') {
                $ans = $value * 18.016;
            }else{
                $ans = $value * 1;
            }
            return $ans;
        }
        if(is_numeric($input)){
            if ($solve === "1") {
                $input = ac_unit($unit1,$input);
                $jawab = (28.7 * $input) - 46.7;
                $percent = $input;
            } else {
                $input = blood_unit($unit2,$input);
                $jawab = ($input + 46.7) / 28.7;
                $percent = $jawab;
            }
        }else{
            $this->param['error'] = 'Please! Check Your Input.';
            return $this->param;
        }
        $this->param['percent'] = $percent;
        $this->param['jawab'] = round($jawab, 2);
        $this->param['RESULT'] = 1;
        // dd($this->param);
        return $this->param;
    }

    // Adjusted Body Weight Calculator
    public function adjusted($request){
        // dd($request->all());
        $weight  = $request->weight;
        $weight_unit = $request->weight_unit;
        $gender = $request->gender;
        $height = $request->height_cm;
        $height_unit = $request->unit_ft_in;
        $height_ft = $request->height_ft;
        $height_in = $request->height_in;

        if (isset($height_unit)) {
            if ($height_unit === 'ft/in') {
                $feet_to_inches = $height_ft * 12; 
                $height = $feet_to_inches + $height_in; 
            } elseif ($height_unit === 'cm') {
                $height = $height *0.393701; 
            } elseif ($height_unit === 'm') {
                $height = $height * 39.3701; 
            } elseif ($height_unit === 'ft') {
                $height = $height * 12; 
            } elseif ($height_unit === 'in') {
                $height = $height;
            }
        }
        if (isset($weight_unit)) {
            if ($weight_unit === 'kg') {
                $weight = $weight;
            } elseif ($height_unit === 'lbs') {
                $weight = $weight * 0.45359237;
            }
        }
        if(is_numeric($height) && is_numeric($weight)){
            function calculateIdealBodyWeight($gender, $height) {
                if ($gender == "male") {
                    $idealWeight = 52 + 1.9 * ($height - 60);
                } elseif ($gender == "female") {
                    $idealWeight = 49 + 1.7 * ($height - 60);
                }
                return $idealWeight;
            }
            // Function to calculate adjusted body weight
            function calculateAdjustedBodyWeight($idealBodyWeight, $weight) {
                $adjustedBodyWeight = $idealBodyWeight + 0.4 * ($weight - $idealBodyWeight);
                return $adjustedBodyWeight;
            }
            // Calculate ideal body weight
            $idealBodyWeight = calculateIdealBodyWeight($gender, $height);
            // Calculate adjusted body weight
            $adjustedBodyWeight = calculateAdjustedBodyWeight($idealBodyWeight, $weight);
        }else{
            $this->param['error'] = 'Please! Check Your Input.';
            return $this->param;
        }
        $this->param['idealBodyWeight'] =  round($idealBodyWeight,2);
        $this->param['adjustedBodyWeight'] = round($adjustedBodyWeight,2);	
        $this->param['RESULT'] = 1;
        return $this->param;
    }

    // Army Body Fat Calculator
	public function army($request){
        // dd($request->all());
        $activeDuty  = $request->activeDuty;
        $age  = $request->age;
        $gender = $request->gender;
        $height = $request->height_cm;
        $height_unit = $request->unit_ft_in;
        $height_ft = $request->height_ft;
        $height_in = $request->height_in;
        $neck  = $request->neck_cm;
        $neck_unit  = $request->unit_ft_in1;
        $neck_ft = $request->neck_ft;
        $neck_in = $request->neck_in;
        $waist  = $request->waist_cm;
        $waist_unit = $request->unit_ft_in2;
        $waist_ft = $request->waist_ft;
        $waist_in = $request->waist_in;
        $hip_unit = $request->unit_ft_in3;
        $hip_ft = $request->hip_ft;
        $hip_in = $request->hip_in;

		// Check if hip input is provided for females
        if ($gender == 'female') {
            $hip = isset($request->hip_cm) ? $request->hip_cm : null;
        } else {
            $hip = null;
        }
		if (isset($height_unit)) {
			if ($height_unit === 'ft/in') {
				$inches = $height_ft * 12;
				$height = $inches + $height_in;
			} elseif ($height_unit === 'cm') {
				$height = $height * 0.393701; 
			} elseif ($height_unit === 'm') {
				$height = $height * 39.3701; 
			} elseif ($height_unit === 'ft') {
				$height = $height * 12; 
			} elseif ($height_unit === 'in') {
				$height = $height;
			}
		}
		if (isset($waist_unit)) {
			if ($waist_unit === 'ft/in') {
				$inches = $waist_ft * 12;
				$waist = $inches + $waist_in;
			} elseif ($waist_unit === 'cm') {
				$waist = $waist * 0.393701;
			} elseif ($waist_unit === 'm') {
				$waist = $waist * 39.3701; 
			} elseif ($waist_unit === 'ft') {
				$waist = $waist * 12; 
			} elseif ($waist_unit === 'in') {
				$waist = $waist;
			}
		}
		if (isset($neck_unit)) {
			if ($neck_unit === 'ft/in') {
				$inches = $neck_ft * 12;
				$neck = $inches + $neck_in;
			} elseif ($neck_unit === 'cm') {
				$neck = $neck * 0.393701; 
			} elseif ($neck_unit === 'm') {
				$neck = $neck * 39.3701; 
			} elseif ($neck_unit === 'ft') {
				$neck = $neck * 12; 
			} elseif ($neck_unit === 'in') {
				$neck = $neck;
			}
		}
		if (isset($hip_unit)) {
			if ($hip_unit === 'ft/in') {
				$inches = $hip_ft * 12;
				$hip = $inches + $hip_in;
			} elseif ($hip_unit === 'cm') {
				$hip = $hip * 0.393701; 
			} elseif ($hip_unit === 'm') {
				$hip = $hip * 39.3701; 
			} elseif ($hip_unit === 'ft') {
				$hip = $hip * 12; 
			} elseif ($hip_unit === 'in') {
				$hip = $hip;
			}
		}
		if(is_numeric($height) && is_numeric($waist) && is_numeric($neck) || is_numeric($hip)){
        // Function to calculate body fat percentage for males
        function calculateMaleBodyFat($height, $neck, $waist) {
            return (86.010 * log10($waist - $neck)) - (70.041 * log10($height)) + 36.76;
        }
        // Function to calculate body fat percentage for females
        function calculateFemaleBodyFat($height, $neck, $waist, $hip) {
            return (163.205 * log10($waist + $hip - $neck)) - (97.684 * log10($height)) - 78.387;
        }
        // Determine body fat category
        if ($gender == 'male') {
            $bodyFatPercentage = calculateMaleBodyFat($height, $neck, $waist);
        } elseif ($gender == 'female' && isset($hip)) {
            $bodyFatPercentage = calculateFemaleBodyFat($height, $neck, $waist, $hip);
        }
        // Function to determine body fat category (same as before)
        function determineBodyFatCategory($age, $gender, $activeDuty, $bodyFatPercentage) {
            if ($gender == 'male') {
                if ($age >= 17 && $age <= 20) {
                    $maxBodyFat = ($activeDuty) ? 20 : 24;
                } elseif ($age >= 21 && $age <= 27) {
                    $maxBodyFat = ($activeDuty) ? 22 : 26;
                } elseif ($age >= 28 && $age <= 39) {
                    $maxBodyFat = ($activeDuty) ? 24 : 28;
                } else {
                    $maxBodyFat = ($activeDuty) ? 26 : 30;
                }
            } elseif ($gender == 'female') {
                if ($age >= 17 && $age <= 20) {
                    $maxBodyFat = ($activeDuty) ? 30 : 30;
                } elseif ($age >= 21 && $age <= 27) {
                    $maxBodyFat = ($activeDuty) ? 32 : 32;
                } elseif ($age >= 28 && $age <= 39) {
                    $maxBodyFat = ($activeDuty) ? 34 : 34;
                } else {
                    $maxBodyFat = ($activeDuty) ? 36 : 36;
                }
            }
            // Determine body fat category
            if ($bodyFatPercentage <= $maxBodyFat) {
                return 'Congratulations! You meet the US Army body fat standards!';
            } else {
                return 'Sorry, you are not fit enough to join the US Army. Keep on training!';
            }
        }
        // Determine body fat category
        $bodyFatCategory = determineBodyFatCategory($age, $gender, $activeDuty, $bodyFatPercentage);
		$this->param['bodyFatPercentage'] = $bodyFatPercentage;
		$this->param['bodyFatCategory'] = $bodyFatCategory;
		}else{
            $this->param['error'] = 'Please! Check Your Input.';
            return $this->param;
		}
		$this->param['RESULT'] = 1;
        return $this->param;
	}

	// Ast Alt Ratio Calculator
	public function ast($request){
        // dd($request->all());
        $ast = trim($request->ast);
        $ast_unit = str_replace('U / ', '', trim($request->ast_unit));
        $alt = trim($request->alt);
        $alt_unit = str_replace('U / ', '', trim($request->alt_unit));

        function sigFig($value,$digits){
            if($value !== ''){
                if($value===0){
                    $decimalPlaces=$digits-1;
                }elseif($value<0){
                    $decimalPlaces=$digits-floor(log10($value*-1))-1;
                }else{
                    $decimalPlaces=$digits-floor(log10($value))-1;
                }
                $answer=round($value,$decimalPlaces);
                return $answer;
            }
            
        }

        if(is_numeric($ast) && !empty($ast_unit) && is_numeric($alt) && !empty($alt_unit)){
            // Unit Conversion
            if($ast_unit === 'mm³'){
                $ast = $ast / 0.000001;
            }elseif($ast_unit === 'cm³'){
                $ast = $ast / 0.001;
            }elseif($ast_unit === 'cu in'){
                $ast = $ast / 0.016387;
            }elseif($ast_unit === 'cu ft'){
                $ast = $ast / 28.317;
            }elseif($ast_unit === 'ml'){
                $ast = $ast / 0.001;
            }elseif($ast_unit === 'cl'){
                $ast = $ast / 0.01;
            }
            if($alt_unit === 'mm³'){
                $alt = $alt / 0.000001;
            }elseif($alt_unit === 'cm³'){
                $alt = $alt / 0.001;
            }elseif($alt_unit === 'cu in'){
                $alt = $alt / 0.016387;
            }elseif($alt_unit === 'cu ft'){
                $alt = $alt / 28.317;
            }elseif($alt_unit === 'ml'){
                $alt = $alt / 0.001;
            }elseif($alt_unit === 'cl'){
                $alt = $alt / 0.01;
            }

            if($ast >= 2000){
                $this->param['error'] = 'AST cannot be greater than or equal to 2000.';
                return $this->param;
            }
            if($alt >= 2000){
                $this->param['error'] = 'ALT cannot be greater than or equal to 2000.';
                return $this->param;
            }

            $ratio = $ast / $alt;
            $m1 = $m2 = $m3 = '';

            if($ast < 8){
                $m1 = "Lower than the average";
            }elseif($ast >= 8 && $ast <= 48){
                $m1 = "Within normal range";
            }elseif($ast > 48){
                $m1 = "Higher than the average";
            }

            if($alt < 7){
                $m2 = "Lower than the average";
            }elseif($alt >= 7 && $alt <= 55){
                $m2 = "Within normal range";
            }elseif($alt > 55){
                $m2 = "Higher than the average";
            }

            if($ratio < 0.6){
                $m3 = "Lower than the average";
            }elseif($ratio >= 0.6 && $ratio <= 1){
                $m3 = "Within normal range";
            }elseif($ratio > 1){
                $m3 = "Too high - indicative of cirrhosis";
            }
        }else{
            $this->param['error'] = 'Please! Check Your Input.';
            return $this->param;
        }

		$this->param['ratio'] = sigFig($ratio, 3);
		$this->param['ast'] = $ast;
		$this->param['alt'] = $alt;
		$this->param['m1'] = $m1;
		$this->param['m2'] = $m2;
		$this->param['m3'] = $m3;
		$this->param['RESULT'] = 1;
        return $this->param;
	}

    // Bishop Score Calculator
	public function bishop($request){
