        $effacement  = $request->effacement;
        $consistency  = $request->consistency;
        $fetal_station = $request->fetal_station;
        $head_position = $request->head_position;
        $dilation  = $request->dilation;

		if(isset($effacement) && isset($consistency) && isset($fetal_station) && isset($head_position) && isset($dilation)){
			$bishopScore = $dilation + $effacement + $consistency + $fetal_station + $head_position;
			$result = "";
			if ($bishopScore <= 6) {
				$result = "You are not expected to go into labor in the upcoming weeks. If induction is needed, consider adding a cervical ripening agents.";
			} elseif ($bishopScore >= 8) {
				$result = "You are expected to go into labor within a few days. If induction is needed, it's likely to be successful.";
			} else {
				$result = "Consider further evaluation.";
			}		
		}else{
            $this->param['error'] = 'Please! Check Your Input.';
            return $this->param;
		}
		$this->param['bishopScore'] = $bishopScore;
		$this->param['result'] = $result;	
		$this->param['RESULT'] = 1;
        return $this->param;
	}

	// Breastfeeding Calorie Calculator
	public function breastfeeding($request){

        $submit = trim($request->unit_type);
        $age = trim($request->age);
        $h_ft_in = trim($request->ft_in);
        $h_cm = trim($request->height_cm);
        $weight = trim($request->weight);
        $activity = trim($request->activity);
        $bf = trim($request->bf);
        $pregnant = trim($request->pregnant);
		$check = false;

		if($submit === 'lbs' && is_numeric($age) && is_numeric($weight)){
			$check = true;
		}elseif($submit === 'kg' && is_numeric($age) && is_numeric($h_cm) && is_numeric($weight)){
			$check = true;
		}

		if($check === true){
			if($submit === 'lbs'){
				$weight = $weight * 0.45359237;
				$h_cm = ($h_ft_in) * 2.54;
			}
	
			$maintain = round(((10 * $weight) + (6.25 * $h_cm) - (5 * $age) - 161) * $activity + $bf + $pregnant);
			$lose = $maintain - 300;
			$supply = $maintain - 500;
		}else{
            $this->param['error'] = 'Please! Check Your Input.';
            return $this->param;
		}

		$this->param['maintain'] = $maintain;
		$this->param['lose'] = $lose;
		$this->param['supply'] = $supply;
		$this->param['carbos1'] = round(($maintain * 0.44) / 4);
		$this->param['carbos2'] = round(($lose * 0.44) / 4);
		$this->param['proteins1'] = round(($maintain * .26) / 4);
		$this->param['proteins2'] = round(($lose * .26) / 4);
		$this->param['fats1'] = round(($maintain * .25) / 9);
		$this->param['fats2'] = round(($lose * .25) / 9);
		$this->param['RESULT'] = 1;

        return $this->param;
	}

