                if ($activity === "sedentary") {
                    $tdee=round($BMR * (1.1));
                }elseif ($activity === "Lightly_Active") {
                    $tdee=round($BMR * (1.2));
                }elseif ($activity === "Moderately_Active") {
                    $tdee=round($BMR * (1.4));
                }elseif ($activity === "Very_Active") {
                    $tdee=round($BMR * (1.6));
                }else {
                    $tdee=round($BMR * (1.8));
                }

                $Robinson=round(52 + (1.9 * ($height_in - 60)));
                $Miller=round(56.2 + (1.41 * ($height_in - 60)));
                $Devine=round(50 + (2.3 * ($height_in - 60)));
                $Hamwi=round(48 + (2.7 * ($height_in - 60)));
            
            }
            if (!empty($percent)) {
                $lbm= ($weight * (100 - $percent))/100;
                $BMR=round(370 + (21.6 * $lbm));
            }
            $height_m=$height_in / 39.37;
            $BMI= round($weight / ($height_m * $height_m),2);
            if ($BMI<=18.5) {
                $you_are='Underweight';
            }
            if ($BMI>18.5 && $BMI<=24.9) {
                $you_are='Normal Weight';
            }
            if ($BMI>24.9 && $BMI<=29.9) {
                $you_are='Overweight';
            }
            if ($BMI>29.9 && $BMI<=35) {
                $you_are='Obesity';
            }
            if ($BMI>35) {
                $you_are='Severe Obesity';
            }
            if($submit=='imperial'){
                $ibw= round($Robinson * 2.205).'-'.round($Hamwi * 2.205).'</b><sub> lbs</sub>';
            }else{

                $ibw= $Robinson.'-'.$Hamwi.'</b><sub> kg</sub>';
            }
            $calories=$tdee ;
            $start = new Datetime($start);
            $target = new Datetime($target);
            if (empty($start) && empty($target)) {
                $this->param['error'] = 'Please Enter Start and Target Date.';
                return $this->param;
            }
            if ($start >=$target) {
                $this->param['error'] = 'Target Date must be later than start date.';
                return $this->param;
            }
            $diff = $start->diff($target);
            $days=$diff->days;
            $pounds_daily=round($weight1/$days,2);

            if($pounds_daily>0.3) $high_risk_weight=true;
            else $high_risk_weight=false;
            if($surplus == 'custom'){
                if($stype == 'Incal'){
                    $calories_gain=$kal_day;
                }else{
                    $per_cal=$per_cal/100;
                    $calories_gain=$calories*$per_cal; 
                }
            }else{
                if($surplus == '0.10'){
                    $calories_gain=$calories*0.1;
                }elseif($surplus == '0.15'){
                    $calories_gain=$calories*0.15;
                }else{
                    $calories_gain=$calories*0.20;
                }
            }	
            $calories_daily=$calories+$calories_gain;
            $calories_daily=round($calories_daily);
            if($calories_daily<1200) $high_risk_calories=true;
            else $high_risk_calories=false;
            if($submit == "imperial"){
                $goal=round($weight + $weight1,2);
            }else{
                $goal=round($weight + $weight1,2)/2.205;
            }
            $fat = round(($calories_daily /9)* 0.2,);
            $po = round(($calories_daily / 4)* 0.3,);
            $cb = round(($calories_daily / 4)* 0.5,);
            //return values
            $this->param = array (
                "HighRiskWeight" 	=> @$high_risk_weight,
                "PoundsDaily" 		=> @$pounds_daily,
                "HighRiskCalories" 	=> @$high_risk_calories,
                "CaloriesDaily" 	=> $calories_daily,
                "CaloriesLess"		=> round($calories_gain),
                "Calories" 			=> $calories,
                "Goal" 				=> $goal,
                "days" 				=> $days,
                "BMR" 				=> $BMR,
                "BMI" 				=> $BMI,
                "you_are" 			=> $you_are,
                "lbm" 				=> @$lbm,
                "ibw" 				=> $ibw,
                "fat" 				=> $fat,
                "po" 				=> $po,
                "cb" 				=> $cb,
                "want" 				=> $want,
                "unit" 			=> $unit,
                "RESULT" 			=> 1
            );
            return $this->param;
        }else{
            $this->param['error'] = 'Please fill All Fields.';
            return $this->param;
        }
    }

    // Elliptical Calorie Calculator
    public function elliptical($request){
        $weight = trim($request->weight);
        $weight_unit = trim($request->weight_unit);
        $hour = trim($request->hour);
        $time_unit = trim($request->unit_hrs_min);
        $min = trim($request->min);
        $time = trim($request->time);
        $effort_unit = trim($request->effort_unit);
        $effort = trim($request->effort);

        if (empty($hour) && empty($min)) {
            $this->param['error'] = 'Please! Check Your Input.';
            return $this->param;
        }
        if (empty($hour)) {
            $hour = 0;
        }
        if (empty($min)) {
            $min = 0;
        }

        if($weight_unit === "kg"){
            $weight = $weight;
        }else if($weight_unit === "lbs"){
            $weight = $weight * 2.205;
        }else if($weight_unit === "stone"){
            $weight = $weight / 6.35;
        }

        if($time_unit === "sec"){
            $time = $time;
        }else if($time_unit === "min"){
            $time = $time * 60;
        }else if($time_unit === "hrs"){
            $time = $time * 3600;
        }else if($time_unit === "hrs/min"){
            $time = ($hour * 3600) +($min * 60);
        }

        if($effort_unit === "Light (MET = 4.6)"){
            $effort = 4.6;
        }else if($effort_unit === "Moderate (MET = 4.9)"){
            $effort = 4.9;
        }else if($effort_unit === "Vigorous (MET = 5.7)"){
            $effort = 5.7;
        }else if($effort_unit === "Custom (enter MET value)"){
            $effort = $effort;
        }

        if (is_numeric($weight) && is_numeric($time) && is_numeric($effort)) {
            $answer = $time * $effort * 3.5 * $weight / (200 * 60);
            $sub_answer = 60 * $effort * 3.5 * $weight / 200;
        }else{
            $this->param['error'] = 'Please! Check Your Input.';
            return $this->param;
        }
        $this->param['weight'] = $weight;
        $this->param['time'] = $time;
        $this->param['answer'] = $answer;
        $this->param['sub_answer'] = $sub_answer;
        $this->param[ 'RESULT' ] = 1;
        return $this->param;
    }

    // Incidence Rate Calculator
	public function incidence($request){
        // dd($request->all());
        $cases = trim($request->cases);
        $risk = trim($request->risk);
        $different_unit = trim($request->different_unit);
        $population = trim($request->population);
        $per = trim($request->per);

	  	if ($different_unit == "Yes") {
			if (is_numeric($cases) && is_numeric($risk) && is_numeric($population)) {
				$answer = $cases / $risk * $population;
			} else {
                $this->param['error'] = 'Please! Check Your Input.';
                return $this->param;
			}
		} elseif ($different_unit == "No") {
			if (is_numeric($cases) && is_numeric($risk) && is_numeric($per)) {
				$answer = $cases / $risk * $per;
			} else {
                $this->param['error'] = 'Please! Check Your Input.';
                return $this->param;
			}
		}
		$this->param['answer'] = $answer;
		$this->param[ 'RESULT' ] = 1;
        return $this->param;
	}

