    // Max Heart Rate Calculator
	public function max($request){
        $formula = $request->formula;
        $age = $request->age;

		if (is_numeric($age)){
			if ($formula === "1") {
				$answer = 205.8 - (0.685 * $age);
			}else if ($formula === "2"){
				$answer = 220 - $age;
			}else if ($formula === "3"){
				$answer = 211 - (0.64 * $age);
			}else if ($formula === "4"){
				$answer = 192 - (0.007 * pow($age, "2"));
			}else if ($formula === "5"){
				$answer = 208 - (0.07 * $age);
			}
			$this->param = array (
				"answer" 			=> $answer,
				"RESULT" 			=> 1
			);
            return $this->param;
		}else{
            $this->param['error'] = 'Please! Check Your Input.';
            return $this->param;
		}
	}

    // Navy Body Fat Calculator
	public function navy($request){
        // dd($request->all());
        $weight = $request->weight;
        $weight_unit = $request->weight_unit;
        $age = $request->age;
        $gender = $request->gender;
        $height = $request->height_cm;
        $height_unit = $request->unit_ft_in;
        $height_ft = $request->height_ft;
        $height_in = $request->height_in;
        $neck = $request->neck_cm;
        $neck_unit  = $request->unit_ft_in1;
        $neck_ft = $request->neck_ft;
        $neck_in = $request->neck_in;
        $waist = $request->waist_cm;
        $waist_unit = $request->unit_ft_in2;
        $waist_ft = $request->waist_ft;
        $waist_in = $request->waist_in;
        $hip_unit = $request->unit_ft_in3;
        $hip_ft = $request->hip_ft;
        $hip_in = $request->hip_in;

		// Check if hip input is provided for females
        if ($gender == 'female') {
            $hip = isset($request->hip_cm) ? $request->hip_cm : null;
        } else {
            $hip = null;
        }
		if (isset($height_unit)) {
			if ($height_unit === 'ft/in') {
				$feet_to_cm = $height_ft *  30.48;
				$inches_to_cm = $height_in * 2.54;
				$height = $feet_to_cm + $inches_to_cm;
			} elseif ($height_unit === 'cm') {
				$height = $height;
			} elseif ($height_unit === 'm') {
				$height = $height * 100; // 1 meter = 100 cm
			} elseif ($height_unit === 'ft') {
				$height = $height * 30.48; // 1 foot = 30.48 cm
			} elseif ($height_unit === 'in') {
				$height = $height * 2.54; // 1 inch = 2.54 cm
			}
		}
		if (isset($weight_unit)) {
			if ($weight_unit === 'lbs') {
				$weight = $weight;
			} elseif ($height_unit === 'kg') {
				$weight = $weight * 2.20462;
			}
		}
		if (isset($waist_unit)) {
			if ($waist_unit === 'ft/in') {
				$feet_to_cm = $waist_ft *  30.48;
				$inches_to_cm = $waist_in * 2.54;
				$waist = $feet_to_cm + $inches_to_cm;
			} elseif ($waist_unit === 'cm') {
				$waist = $waist;
			} elseif ($waist_unit === 'm') {
				$waist = $waist * 100; 
			} elseif ($waist_unit === 'ft') {
				$waist = $waist * 30.48; 
			} elseif ($waist_unit === 'in') {
				$waist = $waist * 2.54;
			}
		}
		if (isset($neck_unit)) {
			if ($neck_unit === 'ft/in') {
				$feet_to_cm = $neck_ft *  30.48;
				$inches_to_cm = $neck_in * 2.54;
				$neck = $feet_to_cm + $inches_to_cm;
			} elseif ($neck_unit === 'cm') {
				$neck = $neck; 
			} elseif ($neck_unit === 'm') {
				$neck = $neck * 100; 
			} elseif ($neck_unit === 'ft') {
				$neck = $neck * 30.48; 
			} elseif ($neck_unit === 'in') {
				$neck = $neck * 2.54;
			}
		}
		if (isset($hip_unit)) {
			if ($hip_unit === 'ft/in') {
				$feet_to_cm = $hip_ft *  30.48;
				$inches_to_cm = $hip_in * 2.54;
				$hip = $feet_to_cm + $inches_to_cm;
			} elseif ($hip_unit === 'cm') {
				$hip = $hip; 
			} elseif ($hip_unit === 'm') {
				$hip = $hip * 100; 
			} elseif ($hip_unit === 'ft') {
				$hip = $hip * 30.48; 
			} elseif ($hip_unit === 'in') {
				$hip = $hip * 2.54;
			}
		}
		if(is_numeric($height) && is_numeric($waist) && is_numeric($neck) && is_numeric($weight) || is_numeric($hip)){
        // Calculate body fat percentage for males and females
        if ($gender === 'male') {
            $bodyFat = 495 / (1.0324 - 0.19077 * log10($waist - $neck) + 0.15456 * log10($height)) - 450;
        } else {
            $bodyFat =  495 / (1.29579 - 0.35004 * log10($waist + $hip - $neck) + 0.22100 * log10($height)) - 450; 
        }
        // Calculate Fat Mass and Lean Mass
        $fatMass = $weight * ($bodyFat / 100);
        $leanMass = $weight- $fatMass;
        // Determine Body Fat Category
        if ($gender === 'male') {
            if ($age >= 17 && $age <= 26) {
                if ($bodyFat < 6) {
                    $bodyFatCategory = 'Essential Fat';
                } elseif ($bodyFat >= 6 && $bodyFat < 16) {
                    $bodyFatCategory = 'Athletic';
                } elseif ($bodyFat >= 16 && $bodyFat < 20) {
                    $bodyFatCategory = 'Fit';
                } else {
                    $bodyFatCategory = 'Acceptable';
                }
            } else {
                if ($bodyFat < 10) {
                    $bodyFatCategory = 'Essential Fat';
                } elseif ($bodyFat >= 10 && $bodyFat < 20) {
                    $bodyFatCategory = 'Athletic';
                } elseif ($bodyFat >= 20 && $bodyFat < 24) {
                    $bodyFatCategory = 'Fit';
                } else {
                    $bodyFatCategory = 'Acceptable';
                }
            }
        } else {
            if ($age >= 17 && $age <= 26) {
                if ($bodyFat < 16) {
                    $bodyFatCategory = 'Essential Fat';
                } elseif ($bodyFat >= 16 && $bodyFat < 24) {
                    $bodyFatCategory = 'Athletic';
                } elseif ($bodyFat >= 24 && $bodyFat < 30) {
                    $bodyFatCategory = 'Fit';
                } else {
                    $bodyFatCategory = 'Acceptable';
                }
            } else {
                if ($bodyFat < 20) {
                    $bodyFatCategory = 'Essential Fat';
                } elseif ($bodyFat >= 20 && $bodyFat < 28) {
                    $bodyFatCategory = 'Athletic';
                } elseif ($bodyFat >= 28 && $bodyFat < 34) {
                    $bodyFatCategory = 'Fit';
                } else {
                    $bodyFatCategory = 'Acceptable';
                }
            }
        }
		$this->param['bodyFat'] =  number_format($bodyFat,2);
		$this->param['fatMass'] = abs(number_format($fatMass,2)) + 0;
		$this->param['leanMass'] =  number_format($leanMass,2);
		$this->param['bodyFatCategory'] = $bodyFatCategory;
		}else{
            $this->param['error'] = 'Please! Check Your Input.';
            return $this->param;
		}
		$this->param['RESULT'] = 1;
        return $this->param;
	}

    // Net Carbs Calculator
	public function net($request){
        // DD($request->all());
        $serving = $request->serving;
        $location = $request->location;
        $carbohydrates = $request->carbohydrates;
        $fiber = $request->fiber;
        $alcohol = $request->alcohol;
        $contains = $request->contains;

		if($location == 'yes'){
			if(is_numeric($carbohydrates) && is_numeric($fiber) && is_numeric($alcohol) ) {
				if($contains == 'no'){
					$Net_carbs = $carbohydrates - $fiber - $alcohol / 2;
					$this->param['Net_carbs'] = $Net_carbs;	
				}else if($contains == 'yes'){
					$Net_carbs = ($carbohydrates - $fiber -$alcohol);
					$this->param['Net_carbs'] = $Net_carbs;
				}
			}else{
                $this->param['error'] = 'Please! Check Your Input.';
                return $this->param;
			}
		}else if($location == 'no'){
			if($contains == 'yes'){
				$Net_carbs = ($carbohydrates - $alcohol);
				$this->param['Net_carbs'] = $Net_carbs;
			}else if($contains == 'no'){
				$Net_carbs = ($carbohydrates - ( $alcohol/2)) ;
				$this->param['Net_carbs'] = $Net_carbs;
			}
		}else{
            $this->param['error'] = 'Please! Check Your Input.';
            return $this->param;
		}
		$this->param['carbohydrates'] = $carbohydrates;
		$this->param['fiber'] = $fiber;
		$this->param['alcohol'] = $alcohol;
		$this->param['Net_carbs'] = $Net_carbs;
		$this->param['RESULT'] = 1;
        return $this->param;
	}

    // NNT Calculator
	public function nnt($request){
        // dd($request->all());
        $outcome = $request->outcome;
        $first = $request->first;
        $second = $request->second;
        $third = $request->third;

		if ($outcome == "per") {
			if (is_numeric($second) && is_numeric($third)) {
				if ($second > 0 && $third > 0) {
					$minus = $second - $third;
					$arr = $minus / 100;
					$nnt = 1 / $arr;
				}else{
                    $this->param['error'] = "This value can't be negative.";
                    return $this->param;
				}	
			}else{
                $this->param['error'] = 'Please! Check Your Input.';
                return $this->param;
			}
		}else{
			if (is_numeric($first) && is_numeric($second) && is_numeric($third)) {
				if ($first > 0 && $second > 0 && $third > 0) {
					$f_div = (-1 * $second) / $first;
					$s_div = (-1 * $third) / $first;
					$r0 = 1 - exp($f_div);
					$r1 = 1 - exp($s_div);
					$arr = $r0 - $r1;
					$nnt = 1 / $arr;
				}else{
                    $this->param['error'] = "This value can't be negative.";
                    return $this->param;
				}
			}else{
                $this->param['error'] = 'Please! Check Your Input.';
                return $this->param;
			}
		}
		$this->param['arr'] = $arr;
		$this->param['nnt'] = $nnt;
		$this->param['RESULT'] = 1;
        return $this->param;
	}

    // Pack Year Calculator
	public function pack($request){
        $cigarettes = $request->cigarettes;
        $size = $request->size;
        $years = $request->years;

		if (is_numeric($cigarettes) && is_numeric($size) && is_numeric($years)){
			$PY = ($cigarettes / $size) * $years;
			$PL = $cigarettes * 365.24 * $years;
			$CL = ($cigarettes / $size) * 365.24 * $years;
			$this->param = array (
				"PY" 			=> $PY,
				"PL" 			=> $PL,
				"CL" 			=> $CL,
				"RESULT" 			=> 1
			);
            return $this->param;
		}else{
            $this->param['error'] = 'Please! Check Your Input.';
            return $this->param;
		}
	}

