    // Stroke Volume Calculator
	public function stroke($request){
        // dd($request->all());
        $Cardiac = trim($request->Cardiac);
        $Cardiac_unit = str_replace('/min ', '', trim($request->Cardiac_unit));
        $heart = trim($request->heart);
        $height = trim($request->height_cm);
        $one_height = trim($request->height_ft);
        $sec_height = trim($request->height_in);
        $height_unit = trim($request->unit_ft_in);
        $weight = trim($request->weight);
        $weight_unit = trim($request->weight_unit);

		function unitToLiters($Cardiac, $Cardiac_unit) {
			if ($Cardiac_unit == "mm³") {
				return $Cardiac / 1e+9; // Convert from mm³ to liters
			} elseif ($Cardiac_unit == "cm³") {
				return $Cardiac / 1000; // Convert from cm³ to liters
			} elseif ($Cardiac_unit == "dm³") {
				return $Cardiac; // Already in liters
			} elseif ($Cardiac_unit == "m³") {
				return $Cardiac * 1000; // Convert from m³ to liters
			} elseif ($Cardiac_unit == "in³") {
				return $Cardiac / 61023.7; // Convert from in³ to liters
			} elseif ($Cardiac_unit == "ft³") {
				return $Cardiac * 28.3168; // Convert from ft³ to liters
			} elseif ($Cardiac_unit == "yd³") {
				return $Cardiac / 764.555; // Convert from yd³ to liters
			} elseif ($Cardiac_unit == "ml") {
				return $Cardiac / 1000; // Convert from milliliters to liters
			} elseif ($Cardiac_unit == "cl") {
				return $Cardiac / 100; // Convert from centiliters to liters
			} elseif ($Cardiac_unit == "l") {
				return $Cardiac; // Already in liters
			} elseif ($Cardiac_unit == "US gal") {
				return $Cardiac * 3.78541; // Convert from US gallons to liters
			} elseif ($Cardiac_unit == "UK gal") {
				return $Cardiac * 4.54609; // Convert from UK gallons to liters
			} elseif ($Cardiac_unit == "US fl oz") {
				return $Cardiac / 33.814; // Convert from US fluid ounces to liters
			} elseif ($Cardiac_unit == "UK fl oz") {
				return $Cardiac / 35.1951; // Convert from UK fluid ounces to liters
			} elseif ($Cardiac_unit == "cups") {
				return $Cardiac * 0.284131; // Convert from cups to liters
			} elseif ($Cardiac_unit == "tbsp") {
				return $Cardiac / 67.628; // Convert from tablespoons to liters
			} elseif ($Cardiac_unit == "tsp") {
				return $Cardiac / 202.884; // Convert from teaspoons to liters
			} elseif ($Cardiac_unit == "US qt") {
				return $Cardiac * 0.946353; // Convert from US quarts to liters
			} elseif ($Cardiac_unit == "UK qt") {
				return $Cardiac * 1.13652; // Convert from UK quarts to liters
			} elseif ($Cardiac_unit == "US pt") {
				return $Cardiac / 1.05669; // Convert from US pints to liters
			} elseif ($Cardiac_unit == "UK pt") {
				return $Cardiac / 1.13652; // Convert from UK pints to liters
			} else {
				return null;
			}
		}

		function lambai_unit($height, $height_unit) {
			if ($height_unit == "mm") {
				$height = $height / 10; // 1 cm = 10 mm
			} elseif ($height_unit == "cm") {
				$height;
			} elseif ($height_unit == "m") {
				$height = $height * 100; // 1 m = 100 cm
			} elseif ($height_unit == "km") {
				$height = $height * 100000; // 1 km = 100,000 cm
			} elseif ($height_unit == "in") {
				$height = $height * 2.54; // 1 inch = 2.54 cm
			} elseif ($height_unit == "ft") {
				$height = $height * 30.48; // 1 foot = 30.48 cm
			} elseif ($height_unit == "yd") {
				$height = $height * 91.44; // 1 yard = 91.44 cm
			} elseif ($height_unit == "mi") {
				$height = $height * 160934; // 1 mile = 160,934 cm
			} elseif ($height_unit == "nmi") {
				$height = $height * 185200; // 1 nautical mile = 185,200 cm
			}
			return $height;
		}
		
		function other_lamba($one_height,$sec_height,$height_unit){
			if($height_unit === "ft/in"){
				$worked = ($one_height * 30.48)  + ($sec_height * 2.54);
			}elseif ($height_unit === "m/cm"){
				$worked = ($one_height * 100) + ($sec_height);
			}
			return $worked;
		}
		function wazan_unit($weight, $weight_unit) {
			if ($weight_unit == "µg") {
				$weight = $weight / 1000000; // convert micrograms to kilograms
			} elseif ($weight_unit == "mg") {
				$weight = $weight / 1000; // convert milligrams to kilograms
			} elseif ($weight_unit == "g") {
				// weight is already in grams
			} elseif ($weight_unit == "dag") {
				$weight = $weight / 100; // convert decagrams to kilograms
			} elseif ($weight_unit == "kg") {
				// weight is already in kilograms
			} elseif ($weight_unit == "t") {
				$weight = $weight * 1000; // convert metric tons to kilograms
			} elseif ($weight_unit == "gr") {
				$weight = $weight / 15.4324; // convert grains to kilograms
			} elseif ($weight_unit == "dr") {
				$weight = $weight / 56479.1; // convert drams to kilograms
			} elseif ($weight_unit == "oz") {
				$weight = $weight / 35.274; // convert ounces to kilograms
			} elseif ($weight_unit == "lbs") {
				$weight = $weight / 2.20462; // convert pounds to kilograms
			} elseif ($weight_unit == "st") {
				$weight = $weight / 0.157473; // convert stones to kilograms
			} elseif ($weight_unit == "US ton") {
				$weight = $weight * 907.185; // convert US tons to kilograms
			} elseif ($weight_unit == "long ton") {
				$weight = $weight * 1016.05; // convert long tons to kilograms
			} elseif ($weight_unit == "Earths") {
				$weight = $weight * 5.9722e24; // convert Earths to kilograms
			} elseif ($weight_unit == "me") {
				$weight = $weight * 9.10938356e-31; // convert electron masses to kilograms
			} elseif ($weight_unit == "u") {
				$weight = $weight * 1.660539040e-27; // convert unified atomic mass units to kilograms
			} elseif ($weight_unit == "oz t") {
				$weight = $weight / 35.27396; // convert troy ounces to kilograms
			}
			return $weight;
		}
		
		if(is_numeric($Cardiac) && is_numeric($heart) && is_numeric($weight) && is_numeric($height)){
		$Cardiac = unitToLiters($Cardiac, $Cardiac_unit);
		//ans1
		if($Cardiac <= 0){
            $this->param['error'] = 'cardiac output should be an integer greater than 0.';
            return $this->param;
		}
		if($heart <= 0){
            $this->param['error'] = 'heart rate should be an integer greater than 0.';
            return $this->param;
		}
		if($weight <= 0){
            $this->param['error'] = 'weight should be an integer greater than 0.';
            return $this->param;
		}

		$stroke_volume = $Cardiac / $heart;

		if (empty($one_height) && empty($sec_height)) {
            $this->param['error'] = 'Please! Enter Input.';
            return $this->param;
		}
		if (empty($one_height)) {
			$one_height = 0;
		}
		if (empty($sec_height)) {
			$sec_height = 0;
		}

		if($height_unit === 'ft/in' || $height_unit === 'm/cm'){
			$height =  other_lamba($one_height,$sec_height,$height_unit);
		}else{
			$height =  lambai_unit($height, $height_unit) ;
			
		}
		
		$weight = wazan_unit($weight, $weight_unit);
		//ans2
		if($height <= 0){
            $this->param['error'] = 'height should be an integer greater than 0.';
            return $this->param;
		}
		$bsa = 0.007184 * pow($height, 0.725) * pow($weight, 0.425);
		//ans3
		$stroke_val_index = $Cardiac / $bsa ;
		//ans4
		$stroke_index = $stroke_volume / $bsa;
		}else{
            $this->param['error'] = 'Please! Check Your Input.';
            return $this->param;
        }
		$this->param['stroke_volume'] = $stroke_volume;
		$this->param['bsa'] = $bsa;
		$this->param['stroke_val_index'] = $stroke_val_index;
		$this->param['stroke_index'] = $stroke_index;
		$this->param[ 'RESULT' ] = 1;
        return $this->param;
	}

    // Urine Output Calculator
	public function urine($request){
        // dd($request->all());
        $weight = trim($request->weight);
        $weight_unit = trim($request->weight_unit);
        $time = trim($request->time);
        $time_unit = trim($request->time_unit);
        $urine = trim($request->urine);
        $urine_unit = trim($request->urine_unit);
        $fluid = trim($request->fluid);
        $fluid_unit = trim($request->fluid_unit);
        $output_unit = trim($request->output_unit);
        $balance_unit = trim($request->balance_unit);
        $min = trim($request->time_min);
        $sec = trim($request->time_sec);
        $hours = trim($request->time_min);
        $mins = trim($request->time_sec);

		function converter($weight,$weight_unit){
			if($weight_unit == "g"){
				$weight = $weight * 1000;
			}else if($weight_unit == "dag"){
				$weight = $weight * 100;
			}else if($weight_unit == "kg"){
				$weight = $weight *1;
			}else if($weight_unit == "oz"){
				$weight = $weight * 35.274;
			}else if($weight_unit == "lbs"){
				$weight = $weight * 2.205;
			}
			return $weight;
		}
		function timex($time,$time_unit){
			if($time_unit == "sec"){
				$time = $time * 3600;
			}else if($time_unit == "min"){
				$time = $time * 60;
			}else if($time_unit == "hrs"){
				$time = $time * 1;
			}else if($time_unit == "day"){
				$time = $time / 24;
			}
			return $time;
		}
		function urinex($urine,$urine_unit){
			if($urine_unit == "mm³"){
				$urine = $urine * 1000;
			}else if($urine_unit == "cm³"){
				$urine = $urine /1;
			}else if($urine_unit == "dm³"){
				$urine = $urine / 1000;
			}else if($urine_unit == "cu in"){
				$urine = $urine / 16.387;
			}else if($urine_unit == "ml"){
				$urine = $urine * 1;
			}else if($urine_unit == "cl"){
				$urine = $urine / 10;
			}else if($urine_unit == "liters"){
				$urine = $urine /1000;
			}else if($urine_unit == "us gal"){
				$urine = $urine / 3785;
			}else if($urine_unit == "uk gal"){
				$urine = $urine / 4546;
			}else if($urine_unit == "us fl oz"){
				$urine = $urine / 28.413;
			}else if($urine_unit == "uk fl oz"){
				$urine = $urine /  28.413
				;
			}
			return $urine;
		}

		if(is_numeric($urine) && is_numeric($weight) && is_numeric($time)  && is_numeric($fluid)){
			if($time_unit == "min/sec" || $time_unit == "hrs/min"){
				if ($time_unit === "min/sec") {
					if(is_numeric($min) && is_numeric($sec)){
						$time = ($min / 60) + ($sec / 3600);
						$min_sec=$time;
						$time_ans = $time; 
					}else{
                        $this->param['error'] = 'Please! Check Your Input.';
                        return $this->param;
					}
				}elseif($time_unit === "hrs/min"){
					if(is_numeric($hours) && is_numeric($mins)){
						$time = $hours + ($mins / 60);
						$hour_mins = $time;
						$time_ans = $time; 
					}else{
                        $this->param['error'] = 'Please! Check Your Input.';
                        return $this->param;
					}
				}
			}else{
				$time= timex($time,$time_unit);
				$time_ans = $time;
			}
			$urine= urinex($urine,$urine_unit);
			$weight= converter($weight,$weight_unit);
			$answer_unit=$urine/($weight*$time);
			$answer=converter($answer_unit,$output_unit);	
			$fluid = urinex($fluid,$fluid_unit);
			$sec_answer = $fluid-$urine;
		}else{
            $this->param['error'] = 'Please! Check Your Input.';
            return $this->param;
		}
		$this->param['answer'] = $answer;
		$this->param['sec_answer'] = $sec_answer;
		$this->param['time_ans'] = round($time_ans, 4);
		$this->param[ 'RESULT' ] = 1;
        return $this->param;
	}

