    // Weight Gain Calculator
	public function weightgain($request){
        //  dd($request->all());
        $age = $request->age;
        $height_ft = $request->height_ft;
        $height_cm = $request->height_cm;
        $weight = $request->weight;
        $per_cal = $request->per_cal;
        $gender = $request->gender;
        $percent = $request->percent;
        $activity = $request->activity;
        $stype = $request->stype;
        $start = $request->start;
        $target = $request->target;
        $weight1 = $request->weight1;
        $surplus = $request->surplus;
        $kal_day = $request->kal_day;
        $submit = $request->unit_type;
        $want = "2";

        if (is_numeric($age) && is_numeric($weight) && is_numeric($weight1) && !empty($start) && !empty($target) ) {
            if($submit == "imperial"){
                $height_in 	= $height_ft*2.54;
                $weight = $weight/2.205;
                $weight1 = $weight1/2.205;
                $unit = 'lb';
            }else{
                if (is_numeric($height_cm)) {
                    $height_in = $height_cm ;
                    $unit = 'kg';
                } else {
                    $this->param['error'] = 'Please enter height.';
                    return $this->param;
                }
                
            }	
			if($gender =='Male'){
				$BMR=round((10 * round($weight)) + (6.25 * round($height_cm)) - (5 * $age)+5);
				if ($activity === "sedentary") {
					$tdee=round($BMR * (1.1));
				}elseif ($activity === "Lightly_Active") {
					$tdee=round($BMR * (1.2));
				}elseif ($activity === "Moderately_Active") {
					$tdee=round($BMR * (1.4));
				}elseif ($activity === "Very_Active") {
					$tdee=round($BMR * (1.6));
				}else {
					$tdee=round($BMR * (1.8));
				}
				$Robinson=round(49 + (1.7 * ($height_in - 60)));
				$Miller=round(53.1 + (1.36 * ($height_in - 60)));
				$Devine=round(45.5 + (2.3 * ($height_in - 60)));
				$Hamwi=round(45 + (2.2 * ($height_in - 60)));
			}else{
				$BMR=round((10 * $weight) + (6.25 * $height_cm) - (5 * $age)-161);
				// echo $BMR;
				if ($activity === "sedentary") {
					$tdee=round($BMR * (1.1));
				}elseif ($activity === "Lightly_Active") {
					$tdee=round($BMR * (1.2));
				}elseif ($activity === "Moderately_Active") {
					$tdee=round($BMR * (1.4));
				}elseif ($activity === "Very_Active") {
					$tdee=round($BMR * (1.6));
				}else {
					$tdee=round($BMR * (1.8));
				}
				// echo $tdee;
				$Robinson=round(52 + (1.9 * ($height_in - 60)));
				$Miller=round(56.2 + (1.41 * ($height_in - 60)));
				$Devine=round(50 + (2.3 * ($height_in - 60)));
				$Hamwi=round(48 + (2.7 * ($height_in - 60)));
			
			}
			if (!empty($percent)) {
				$lbm= ($weight * (100 - $percent))/100;
				$BMR=round(370 + (21.6 * $lbm));
			}
			$height_m=$height_in / 39.37;
			$BMI= round($weight / ($height_m * $height_m),2);
			if ($BMI<=18.5) {
				$you_are='Underweight';
			}
			if ($BMI>18.5 && $BMI<=24.9) {
				$you_are='Normal Weight';
			}
			if ($BMI>24.9 && $BMI<=29.9) {
				$you_are='Overweight';
			}
			if ($BMI>29.9 && $BMI<=35) {
				$you_are='Obesity';
			}
			if ($BMI>35) {
				$you_are='Severe Obesity';
			}
			if($submit=='imperial'){
				$ibw= round($Robinson * 2.205).'-'.round($Hamwi * 2.205).'</b><sub> lbs</sub>';
			}else{

				$ibw= $Robinson.'-'.$Hamwi.'</b><sub> kg</sub>';
			}
			$calories=$tdee ;
			$start = new Datetime($start);
			$target = new Datetime($target);
			if (empty($start) && empty($target)) {
                $this->param['error'] = 'Please Enter Start and Target Date.';
                return $this->param;
			}
			if ($start >=$target) {
                $this->param['error'] = 'Target Date must be later than start date.';
                return $this->param;
			}
			$diff = $start->diff($target);
			$days=$diff->days;
			$pounds_daily=round($weight1/$days,2);
			// echo $pounds_daily;
			if($pounds_daily>0.3) $high_risk_weight=true;
			else $high_risk_weight=false;
			if($surplus == 'custom'){
				if($stype == 'Incal'){
					$calories_gain=$kal_day;
				}else{
					$per_cal=$per_cal/100;
					$calories_gain=$calories*$per_cal; 
				}
			}else{
				if($surplus == '0.10'){
					$calories_gain=$calories*0.1;
				}elseif($surplus == '0.15'){
					$calories_gain=$calories*0.15;
				}else{
					$calories_gain=$calories*0.20;
				}
			}	
			$calories_daily=$calories+$calories_gain;	
			$calories_daily=round($calories_daily);
			if($calories_daily<1200) $high_risk_calories=true;
			else $high_risk_calories=false;
			if($submit == "imperial"){
				$goal=round($weight + $weight1,2);
			}else{
				$goal=round($weight + $weight1,2)/2.205;
			}
			$fat = round(($calories_daily /9)* 0.2,);
			$po = round(($calories_daily / 4)* 0.3,);
			$cb = round(($calories_daily / 4)* 0.5,);
			//return values
			$this->param = array (
				"HighRiskWeight" 	=> @$high_risk_weight,
				"PoundsDaily" 		=> @$pounds_daily,
				"HighRiskCalories" 	=> @$high_risk_calories,
				"CaloriesDaily" 	=> $calories_daily,
				"CaloriesLess"		=> round($calories_gain),
				"Calories" 			=> $calories,
				"Goal" 				=> $goal,
				"days" 				=> $days,
				"BMR" 				=> $BMR,
				"BMI" 				=> $BMI,
				"you_are" 			=> $you_are,
				"lbm" 				=> @$lbm,
				"ibw" 				=> $ibw,
				"fat" 				=> $fat,
				"po" 				=> $po,
				"cb" 				=> $cb,
				"want" 				=> $want,
				"unit" 			=> $unit,
				"RESULT" 			=> 1
			);
            return $this->param;
		}else{
            $this->param['error'] = 'Please fill All Fields.';
            return $this->param;
		}
	}

    // Maintenance Calorie Calculator
	public function maintenance($request){
        $submit = $request->unit_type;
        $gender = $request->gender;
        $age = $request->age;
        $ft_in = $request->ft_in;
        $height_cm = $request->height_cm;
        $weight = $request->weight;
        $activity = $request->activity;

		if (is_numeric($age) && is_numeric($weight) && !empty($gender) && !empty($activity)){
			if ($submit === "lbs") {
				if(empty($ft_in)) {
                    $this->param['error'] = 'Please Select Height.';
                    return $this->param;
				}
				$weight_kg = $weight / 2.205;
				$height_cm = $ft_in * 2.54;
			}else{
				if(empty($height_cm)) {
                    $this->param['error'] = 'Please Enter Height.';
                    return $this->param;
				}
				$weight_kg = $weight;
				$height_cm = $height_cm;
			}
			$height_m = $height_cm / 100;
			$height_in = $height_cm / 2.54;
			$weight_lbs = $weight_kg * 2.205;
			$BMI = round($weight_kg / ($height_m * $height_m),2);
			if ($gender==='Female') {
				$rmr=round( 655 + (9.6 * $weight_kg) + (1.8 * $height_cm) - (4.7 * $age));
				$BMR = round(($height_cm * 6.25) + ($weight_kg * 10) - ($age * 5) - 161);
				if ($activity === "Sedentary") {
					$tdee=round($BMR * (1.2));
				}elseif ($activity === "Lightly Active") {
					$tdee=round($BMR * (1.375));
				}elseif ($activity === "Moderately Active") {
					$tdee=round($BMR * (1.55));
				}elseif ($activity === "Very Active") {
					$tdee=round($BMR * (1.725));
				}else {
					$tdee=round($BMR * (1.9));
				}
				$Miller=round(53.1 + (1.36 * ($height_in - 60)));
				$Hamwi=round(45 + (2.2 * ($height_in - 60)));
			}else{
				$rmr=round( 66 + (13.7 * $weight_kg) + (5 * $height_cm) - (6.8 * $age));
				$BMR = round(($height_cm * 6.25) + ($weight_kg * 10) - ($age * 5) + 5);
				if ($activity === "Sedentary") {
					$tdee=round($BMR * (1.2));
				}elseif ($activity === "Lightly Active") {
					$tdee=round($BMR * (1.375));
				}elseif ($activity === "Moderately Active") {
					$tdee=round($BMR * (1.55));
				}elseif ($activity === "Very Active") {
					$tdee=round($BMR * (1.725));
				}else {
					$tdee=round($BMR * (1.9));
				}
				$Miller=round(56.2 + (1.41 * ($height_in - 60)));
				$Hamwi=round(48 + (2.7 * ($height_in - 60)));
			}
			if ($Hamwi >= $Miller) {
				$ibw= $Miller.' - '.$Hamwi;
			} else {
				$ibw= $Hamwi.' - '.$Miller;
			}
			if ($submit === "lbs") {
				$Miller= $Miller * 2.205;
				$Hamwi= $Hamwi * 2.205;
				if ($Hamwi >= $Miller) {
					$ibw = round($Miller).'-'.round($Hamwi);
				} else {
					$ibw = round($Hamwi).'-'.round($Miller);
				}
			}
			$fat = round(($tdee /9)* 0.2,);
			$po = round(($tdee / 4)* 0.3,);
			$cb = round(($tdee / 4)* 0.5,);
			$this->param = array (
				"Calories" 			=> $tdee,
				"BMR" 				=> $BMR,
				"rmr" 				=> $rmr,
				"BMI" 				=> $BMI,
				"ibw" 				=> $ibw,
				"fat" 				=> $fat,
				"po" 				=> $po,
				"cb" 				=> $cb,
				"submit"            => $submit,
				"RESULT" 			=> 1
			);

            return $this->param;
		}else{
            $this->param['error'] = 'Please! Check Your Input.';
            return $this->param;
		}
	}

    // Bench Press Calculator
	public function bench($request){
        // dd($request->all());
        $weight =  trim($request->weight);
        $unit =  trim($request->unit);
        $reps =  trim($request->reps);
        $tableType =  trim($request->tableType);

		if ($unit == "kg") {
            $weight *= 2.20462;
        } elseif ($unit == "stone") {
            $weight *= 14;
        }

        $oneRepMax = (float) $weight * (1 + ((float) $reps / 30));
		if ($unit == "kg") {
            $oneRepMax /= 2.20462;
        } elseif ($unit == "stone") {
            $oneRepMax /= 14;
        }
		
		$this->param['oneRepMax'] = $oneRepMax;
		$this->param[ 'RESULT' ] = 1;
        return $this->param;
	}

    // Body Shape Calculator
	public function body_shape($request){
        // dd($request->all());
        $high = $request->high;
        $chest = $request->chest;
        $waist = $request->waist;
        $hip = $request->hip;
        $high_units = $request->high_units;
        $waist_units = $request->waist_units;
        $hip_units = $request->hip_units;
        $chest_units = $request->bust_units;
        $gender = $request->gender;
		if (is_numeric($high) && is_numeric($chest) && is_numeric($waist) && is_numeric($hip)) {
           function cm_convert($a,$b){
                if($b == 'cm'){
                    $a = $a * 2.54;
                }else{
                    $a = $a;
                }
                return $a;
            }

            $high = cm_convert($high,$high_units);
            $chest = cm_convert($chest,$chest_units);
            $waist = cm_convert($waist,$waist_units);
            $hip = cm_convert($hip,$hip_units);
            if($gender == 'men'){
                if (abs($chest - $waist) <= 2 && abs($waist - $hip) <= 2 && abs($hip - $high) <= 2) {
                    $shape = "Rectangle";
                    $img = "Rectangle_man";
                } elseif ($chest > $waist && $chest > $hip) {
                    $shape = "Inverted Triangle";
                    $img = "male_inver_tri";
                } elseif ($chest > $waist && $chest > $high && !($chest > $waist && $chest > $hip && $chest > $high)) {
                    $shape = "Trapezoid";
                    $img = "Trapezoid";
                } elseif ($hip > $chest && $high > $chest) { // This should match your case
                    $shape = "Triangle";
                    $img = "male_tri";
                } elseif ($waist > $chest && $waist > $hip) {
                    $shape = "Oval";
                    $img = "Oval_man";
                }elseif($waist > $chest && $waist > $high){
                    $shape = "Triangle";
                    $img = "Triangle_man";
                } else {
                    $shape = "Oval";
                    $img = "Oval_man";
                }
                
            }else{
                if((($chest-$hip) <= 1) && (($hip-$chest) < 3.6) && ((($chest - $waist) >= 9) || (($hip - $waist) >= 10))) {
                    $shape="Hourglass";
                    $img="Hourglass";
                }elseif (($hip-$chest)>=3.6 && ($hip-$chest) < 10 && ($hip-$waist)>=9 && ($high/$waist)<1.193) {
                    $shape="Bottom Hourglass";
                    $img="Bottom_Hourglass";
                }elseif (($chest - $hip)>1 && ($chest-$hip)<10 && ($chest-$waist)>=9) {
                    $shape="Top Hourglass";
                    $img="Top_Hourglass";
                }elseif (($hip-$chest)>2 && ($hip - $waist)>=7 && ($high/$waist)>=1.193) {
                    $shape="Spoon";
                    $img="Spoon";
                }elseif (($hip - $chest)>=3.6 && ($hip-$waist)<9) {
                    $shape="Triangle";
                    $img="Triangle";
                }elseif (($chest - $hip)>=3.6 && ($chest-$waist)<9) {
                    $shape="Inverted Triangle";
                    $img="Inverted_Triangle";
                }elseif (($hip - $chest)<3.6 && ($chest-$hip)<3.6 && ($chest-$waist)<9 && ($hip-$waist)<10) {
                    $shape="Rectangle";
                    $img="Rectangle";
                }elseif($chest > $waist && $hip > $high){
                    $shape = "Top Hourglass";
                    $img = "Top_Hourglass";
                }else{
                    $shape="Rectangle";
                    $img="Rectangle";
                }
            }
			$this->param = [
				"shape" => $shape,
				"img" => $img,
				"whr" => round($waist/$hip,2),
			];
            return $this->param;
		}else{
            $this->param['error'] = 'Please Input Values!';
            return $this->param;
		}
	}


    // Cat Calorie Calculator
	public function cat($request){
        $weight = $request->weight;
        $weight_units = $request->weight_units;
        $condition = $request->condition;

		if (isset($weight_units)) {
			if ($weight_units === 'kg') {
				$weight = $weight;
			} elseif ($weight_units === 'oz') {
				$weight = $weight / 35.274;
			} elseif ($weight_units === 'lbs') {
				$weight = $weight / 2.2046;
			}
		}
		if(isset($condition)){
			switch ($condition) {
				case "Neutered adult":
					$maintenance_coefficient = 1.6;
					break;
				case "Non-neutered adult":
					$maintenance_coefficient = 1.8;
					break;
				case "Weight loss":
					$maintenance_coefficient = 1;
                	break;
				case "Weight gain":
					$maintenance_coefficient = 1.7;
					break;
				case "0-4 months old kitten":
					$maintenance_coefficient = 3;
					break;
				case "4 months to adult cat":
					$maintenance_coefficient = 2;
					break;
            }
        }
		if(is_numeric($weight)){
            $weight_kg = $weight;
            $resting_energy = pow($weight_kg, 0.75) * 70;
            $maintenance_energy = $resting_energy * $maintenance_coefficient;
		}else{
            $this->param['error'] = 'Please! Check Your Input.';
            return $this->param;
		}
		$this->param['resting_energy'] = $resting_energy;
		$this->param['maintenance_energy'] = $maintenance_energy;
		$this->param['RESULT'] = 1;
        return $this->param;
	}

	// TDEE Calculator
	public function tdee($request){
        // dd($request->all());
        $age = $request->age;
        $gender = $request->gender;
        if (isset($request->ft_in)) {
            $ft_in = $request->ft_in;
        } else {
            $ft_in = "";
        }
        $weight = $request->weight;
        $percent = $request->percent;
        $activity = $request->activity;
        $submit = $request->unit;
        $height_ft=$request->height_ft;
        $height_in=$request->height_in;
        $height_cm=$request->height_cm;
        $hightUnit=$request->hightUnit;
        if (is_numeric($age) && is_numeric($weight) && !empty($gender) && !empty($activity)){
            if ($percent > 100) {
                $this->param['error'] = 'Body Fat Percentage cannot greater than 100.';
                return $this->param;
            }
            if ($request->unit=="lbs") {
                $weight = $weight / 2.205;
            }
            if($hightUnit === "ft/in"){
                if(isset($request->ft_in)){
                    $height_cm = $request->ft_in * 2.54;
                }else{
                    if (is_numeric($height_ft) && is_numeric($height_in)){
                        if ($request->unit_ft_in==='ft/in') {
                            $height_cm=$height_ft * 30.48;
                            if ($height_in!=null) {
                                $height_in= $height_in * 2.54;
                                $height_cm=$height_cm + $height_in;
                            }
                        }
                    }else{
                        $this->param['error'] = 'Please Enter Height.';
                        return $this->param;
                    }
                }
                
            } else {
                if (is_numeric($height_cm)){
                    $height_cm = $height_cm;
                }else{
                    $this->param['error'] = 'Please Enter Height.';
                    return $this->param;
                }
            }
            $height_m=$height_cm / 100;
            $BMI = round($weight / ($height_m * $height_m),2);
            if ($BMI<=18.5) {
                $you_are='Underweight';
            }elseif ($BMI>18.5 && $BMI<=24.9) {
                $you_are='Normal Weight';
            }elseif ($BMI>24.9 && $BMI<=29.9) {
                $you_are='Overweight';
            }elseif ($BMI>29.9 && $BMI<=35) {
                $you_are='Obesity';
            }elseif ($BMI>35) {
                $you_are='Severe Obesity';
            }
            if ($gender==='female') {
                $BMR = round(($weight * 10) + ($height_cm * 6.25) - ($age * 5) - 161);
            }else{
                $BMR = round((10 * $weight) + (6.25 * $height_cm) - (5 * $age) + 5);
            }
            if ($activity === "Sedentary") {
                $tdee=round($BMR * (1.2));
            }elseif ($activity === "Lightly Active") {
                $tdee=round($BMR * (1.375));
            }elseif ($activity === "Moderately Active") {
                $tdee=round($BMR * (1.55));
            }elseif ($activity === "Very Active") {
                $tdee=round($BMR * (1.725));
            }else {
                $tdee=round($BMR * (1.9));
            }
            // maintance
            // maintance moderate
            $main_mod_pro = (30 * $tdee) / 100;
            $main_mod_pro_ans = round($main_mod_pro/4); 
            $main_mod_fat = (35 * $tdee) / 100;
            $main_mod_fat_ans =  round($main_mod_fat/9); 
            $main_mod_carb = (35 * $tdee) / 100;
            $main_mod_carb_ans = round($main_mod_carb/4);
            $total_main_mod_ans = $main_mod_pro_ans + $main_mod_fat_ans + $main_mod_carb_ans;
            $main_mod_pro_per_ans = round(($main_mod_pro_ans / $total_main_mod_ans) * 100);
            $main_mod_fat_per_ans = round(($main_mod_fat_ans / $total_main_mod_ans) * 100);
            $main_mod_carb_per_ans = round(($main_mod_carb_ans / $total_main_mod_ans) * 100); 
            // maintance lower
            $main_low_pro = (40 * $tdee) / 100;
            $main_low_pro_ans = round($main_low_pro/4); 
            $main_low_fat = (40 * $tdee) / 100;
            $main_low_fat_ans =  round($main_low_fat/9); 
            $main_low_carb = (20 * $tdee) / 100;
            $main_low_carb_ans = round($main_low_carb/4);
            $total_main_low_ans = $main_low_pro_ans + $main_low_fat_ans + $main_low_carb_ans;
            $main_low_pro_per_ans = round(($main_low_pro_ans / $total_main_low_ans) * 100);
            $main_low_fat_per_ans = round(($main_low_fat_ans / $total_main_low_ans) * 100);
            $main_low_carb_per_ans = round(($main_low_carb_ans / $total_main_low_ans) * 100);
            // maintance higer
