        function getClosest($search, $arr) {
            $closest = null;
            foreach ($arr as $item){
                list($calories_burn_act,$act_name_ans_pandran,$act_img_name) = explode("@@", $item);
                if ($closest === null || abs($search - $closest) > abs($calories_burn_act - $search)) {
                    $closest = $calories_burn_act;
                }
            }
            return $closest;
        }
        if (is_numeric($age) && is_numeric($weight) && is_numeric($lose_w) && !empty($gender) && !empty($activity)){

            if($lose_unit === "lbs"){
                $lose_w_lbs = $lose_w;
                $lose_w_kg = $lose_w / 2.205;
            }else{
                $lose_w_kg = $lose_w;
                $lose_w_lbs = $lose_w * 2.205;
            }

            if($weight_unit === "lbs"){
                $weight_lbs = $weight;
                $weight_kg = $weight / 2.205;

                $new_lose_kg = $lose_w_lbs / 2.205;
                $new_lose_lbs = $lose_w_lbs;
            }else{
                $weight_kg = $weight;
                $weight_lbs = $weight * 2.205;

                $new_lose_kg = $lose_w_lbs * 2.205;
                $new_lose_lbs = $lose_w_lbs;
            }
            $weight_diff_kg = $weight_kg - $new_lose_kg;
            $weight_diff_lbs = $weight_lbs - $new_lose_lbs;
            if($hightUnit === "ft/in"){
                if (is_numeric($height_ft) && is_numeric($height_in)){
                    if ($request->unit_ft_in==='ft/in') {
                        $height_cm=$height_ft * 30.48;
                        if ($height_in!=null) {
                            $height_in= $height_in * 2.54;
                            $height_cm=$height_cm + $height_in;
                        }
                    }
                }else{
                    $this->param['error'] = 'Please Enter Height.';
                    return $this->param;
                }
            } else {
                if (is_numeric($height_cm)){
                    $height_cm = $height_cm;
                }else{
                    $this->param['error'] = 'Please Enter Height.';
                    return $this->param;
                }
            }
            $height_m = $height_cm / 100;
            $height_in = $height_cm / 2.54;
            if($gender=='Male'){
                $new_BMR = round((10 * $weight_kg) + (6.25 * $height_cm) - (5 * $age) + 5);
                $ibw = 50 + (2.3 * ($height_in - 60));
            }else{
                $new_BMR = round((10 * $weight_kg) + (6.25 * $height_cm) - (5 * $age) - 161);
                $ibw = 45.5 + (2.3 * ($height_in - 60));
            }
            $BMI= round($weight_kg / ($height_m * $height_m),2);
            if ($BMI<=18.5) {
                $you_are='Underweight';
            }elseif ($BMI>18.5 && $BMI<=24.9) {
                $you_are='Normal Weight';
            }elseif ($BMI>24.9 && $BMI<=29.9) {
                $you_are='Overweight';
            }elseif ($BMI>29.9 && $BMI<=35) {
                $you_are='Obesity';
            }else{
                $you_are='Severe Obesity';
            }
            // $calories = round($new_BMR * $activity);
            $activity = round($new_BMR * $activity);
            $calories = round($new_BMR+$activity);
            if($choose === "by_calories"){
                if (empty($enter_calories)) {
                    $this->param['error'] = 'Enter Kcal/day are you ready to reduce.';
                    return $this->param;
				}
				$calories_less = $enter_calories;
				$calories_daily=$calories-$calories_less;
				$pounds_daily=round($calories_less/3500,3);
				$days=round($weight_diff_lbs/$pounds_daily);
            }else{
                $start = new DateTime($start);
                $end = new DateTime($end);
                $diff = $start->diff($end);
                $days = $diff->days;
                if ($days == 0) {
                    $this->param['error'] = 'Start and target dates must not be the same.';
                    return $this->param;
                }
                $pounds_daily = round($weight_diff_lbs / $days, 2);
                $calories_less = round($pounds_daily * 3500, 0);
                $calories_daily = $calories - $calories_less;
            }
            foreach ($all_activites as $act_val){
                $sab_ki_calories_pandran[] = round($new_BMR * $act_val[0] * (15/1440))."@@".$act_val[1]."@@".$act_val[2];
                $sab_ki_calories_adha[] = round($new_BMR * $act_val[0] * (30/1440))."@@".$act_val[1]."@@".$act_val[2];
                $sab_ki_calories_pona[] = round($new_BMR * $act_val[0] * (45/1440))."@@".$act_val[1]."@@".$act_val[2];
                $sab_ki_calories_hour[] = round($new_BMR * $act_val[0] * (60/1440))."@@".$act_val[1]."@@".$act_val[2];
                $sab_ki_calories_sawa[] = round($new_BMR * $act_val[0] * (75/1440))."@@".$act_val[1]."@@".$act_val[2];
                $sab_ki_calories_dher[] = round($new_BMR * $act_val[0] * (90/1440))."@@".$act_val[1]."@@".$act_val[2];
                $sab_ki_calories_pone[] = round($new_BMR * $act_val[0] * (105/1440))."@@".$act_val[1]."@@".$act_val[2];
                $sab_ki_calories_do[] = round($new_BMR * $act_val[0] * (120/1440))."@@".$act_val[1]."@@".$act_val[2];
            }
            foreach ($sab_ki_calories_hour as $key => $value){
                list($cal_ans_pandran,$name_ans_pandran,$img_name_pandran) = explode("@@", $sab_ki_calories_pandran[$key]); 
                list($cal_ans_adha,$name_ans_adha,$img_name_adha) = explode("@@", $sab_ki_calories_adha[$key]); 
                list($cal_ans_pona,$name_ans_pona,$img_name_pona) = explode("@@", $sab_ki_calories_pona[$key]); 
                list($cal_ans,$name_ans,$img_name) = explode("@@", $value); 
                list($cal_ans_sawa,$name_ans_sawa,$img_name_sawa) = explode("@@", $sab_ki_calories_sawa[$key]); 
                list($cal_ans_dher,$name_ans_dher,$img_name_dher) = explode("@@", $sab_ki_calories_dher[$key]); 
                list($cal_ans_pone,$name_ans_pone,$img_name_pone) = explode("@@", $sab_ki_calories_pone[$key]); 
                list($cal_ans_do,$name_ans_do,$img_name_do) = explode("@@", $sab_ki_calories_do[$key]); 
                $diff_array_pandran[] = [abs($cal_ans_pandran - $calories_less), $cal_ans_pandran, $name_ans_pandran,$img_name_pandran];
                $diff_array_adha[] = [abs($cal_ans_adha - $calories_less), $cal_ans_adha, $name_ans_adha,$img_name_adha];
                $diff_array_pona[] = [abs($cal_ans_pona - $calories_less), $cal_ans_pona, $name_ans_pona,$img_name_pona];
                $diff_array[] = [abs($cal_ans - $calories_less), $cal_ans, $name_ans,$img_name];
                $diff_array_sawa[] = [abs($cal_ans_sawa - $calories_less), $cal_ans_sawa, $name_ans_sawa,$img_name_sawa];
                $diff_array_dher[] = [abs($cal_ans_dher - $calories_less), $cal_ans_dher, $name_ans_dher,$img_name_dher];
                $diff_array_pone[] = [abs($cal_ans_pone - $calories_less), $cal_ans_pone, $name_ans_pone,$img_name_pone];
                $diff_array_do[] = [abs($cal_ans_do - $calories_less), $cal_ans_do, $name_ans_do,$img_name_do];
            }
            sort($diff_array_pandran);
            sort($diff_array_adha);
            sort($diff_array_pona);
            sort($diff_array);
            sort($diff_array_sawa);
            sort($diff_array_dher);
            sort($diff_array_pone);
            sort($diff_array_do);
            $slice_pandran = array_slice($diff_array_pandran, 0, 15);
            $slice_adha = array_slice($diff_array_adha, 0, 15);
            $slice_pona = array_slice($diff_array_pona, 0, 15);
            $slice = array_slice($diff_array, 0, 15);
            $slice_sawa = array_slice($diff_array_sawa, 0, 15);
            $slice_dher = array_slice($diff_array_dher, 0, 15);
            $slice_pone = array_slice($diff_array_pone, 0, 15);
            $slice_do = array_slice($diff_array_do, 0, 15);
            foreach ($slice as $key => $slice_value){
                $final_array_pandran[] = $slice_pandran[$key][1]."@@".$slice_pandran[$key][2]."@@".$slice_pandran[$key][3];
                $final_array_adha[] = $slice_adha[$key][1]."@@".$slice_adha[$key][2]."@@".$slice_adha[$key][3];
                $final_array_pona[] = $slice_pona[$key][1]."@@".$slice_pona[$key][2]."@@".$slice_pona[$key][3];
                $final_array[] = $slice[$key][1]."@@".$slice[$key][2]."@@".$slice[$key][3];
                $final_array_sawa[] = $slice_sawa[$key][1]."@@".$slice_sawa[$key][2]."@@".$slice_sawa[$key][3];
                $final_array_dher[] = $slice_dher[$key][1]."@@".$slice_dher[$key][2]."@@".$slice_dher[$key][3];
                $final_array_pone[] = $slice_pone[$key][1]."@@".$slice_pone[$key][2]."@@".$slice_pone[$key][3];
                $final_array_do[] = $slice_do[$key][1]."@@".$slice_do[$key][2]."@@".$slice_do[$key][3];
            }
            sort($final_array_pandran);
            sort($final_array_adha);
            sort($final_array_pona);
            sort($final_array);
            sort($final_array_sawa);
            sort($final_array_dher);
            sort($final_array_pone);
            sort($final_array_do);
            $activity_first = round((0.2 * $new_BMR * 7) / 3500, 2);
            $activity_second = round((0.375 * $new_BMR * 7) / 3500, 2);
            $activity_third = round((0.55 * $new_BMR * 7) / 3500, 2);
            $activity_four = round((0.725 * $new_BMR * 7) / 3500, 2);
            $activity_five = round((0.9 * $new_BMR * 7) / 3500, 2);
            if ($submit === "lbs") {
                $ans_weight = $weight_lbs;
            } else {
                $ans_weight = $weight_kg;
            }
            
            $this->param = array(
                "PoundsDaily" => $pounds_daily,
                "CaloriesDaily" => $calories_daily,
                "Calories" => @$calories,
                "days" => $days,
                "ans_weight" => $ans_weight,
