                "submit" => $submit,
                "from" => $from,
                "lose_w" => $lose_w,
                "weight" => $weight,
                "final_array_pandran" => @$final_array_pandran,
                "final_array_adha" => @$final_array_adha,
                "final_array_pona" => @$final_array_pona,
                "final_array" => @$final_array,
                "final_array_sawa" => @$final_array_sawa,
                "final_array_dher" => @$final_array_dher,
                "final_array_pone" => @$final_array_pone,
                "final_array_do" => @$final_array_do,
                
                "diff_array_pandran" => $diff_array_pandran,
                "diff_array_adha" => $diff_array_adha,
                "diff_array_pona" => $diff_array_pona,
                "diff_array" => $diff_array,
                "diff_array_sawa" => $diff_array_sawa,
                "diff_array_dher" => $diff_array_dher,
