    // Food Cost Calculator
	public function food($request){
        // dd($request->all());
        $food_type = $request->food_type;
        $menu = $request->menu;
        $measure_unit = $request->measure_unit;
        $units_case = $request->units_case;
        $cost_unit = $request->cost_unit;
        $serving_size = $request->serving_size;
        $other = $request->other;
        $menu_price = $request->menu_price;

		if(is_numeric($menu) && is_numeric($units_case) && is_numeric($cost_unit) && is_numeric($serving_size) && is_numeric($other) && is_numeric($menu_price)){
			if($food_type == 'food_piece'){
				$costPerUnit = $cost_unit;
			}else{
				if(($units_case > 0) && ($cost_unit > 0)){
					$costPerUnit = round($cost_unit / $units_case * 100) / 100;
				}else{
                    $this->param['error'] = 'Please! Check Your Input.';
                    return $this->param;
				}
			}
			// Calculate Serving Size
			if($serving_size > 0) {
				$costPerServing = round($serving_size * $costPerUnit * 100) / 100;
			}else{
                $this->param['error'] = 'Serving Size Cannot be Less Than Zero.';
                return $this->param;
			}
			// Calculate Cost per Plate
			$costPerPlate = $costPerServing + $other;
			// Calculate Contribution per Plate
			// Calculate Food Cost
			if ($menu_price > 0) {
				$contributionPerPlate = $menu_price - $costPerPlate;
				$food_cost = round($costPerPlate / $menu_price * 100);
			}else{
                $this->param['error'] = 'Please! Check Your Input.';
                return $this->param;
			}
			// Calculate Profit Pace
			if(($units_case > 0) && ($serving_size > 0)){
				$servingsPerCase = $units_case / $serving_size;
				$profitPerCase = $contributionPerPlate * $servingsPerCase;
			}else{
                $this->param['error'] = 'Please! Check Your Input.';
                return $this->param;
			}
			$this->param['costPerUnit'] = $costPerUnit;
			$this->param['costPerServing'] = $costPerServing;
			$this->param['costPerPlate'] = $costPerPlate;
			$this->param['contributionPerPlate'] = $contributionPerPlate;
			$this->param['food_cost'] = $food_cost;
			$this->param['profitPerCase'] = $profitPerCase;
			$this->param['RESULT'] = 1;
            return $this->param;
		}else{
            $this->param['error'] = 'Please! Check Your Input.';
            return $this->param;
		}
	}

    // Drug Half Life Calculator
	public function drug($request){
    //   dd($request->all());
        $half = trim($request->time);
        $half_one = trim($request->time_min);
        $half_sec = trim($request->time_sec);
        $half_unit = trim($request->time_unit);
        $dosage = trim($request->dosage);
        $dosage_unit = trim($request->dosage_unit);

		function sec_unit($dosage,$dosage_unit){
			if($dosage_unit=="µg"){
				$dosage=$dosage / 1000;
			}elseif ($dosage_unit=="mg"){
				$dosage=$dosage;
			}elseif ($dosage_unit=="g"){
				$dosage=$dosage*1000;
			}
			return $dosage;
		}
		function time_unit($half,$half_unit){
			if($half_unit=="mins"){
				$half=$half * 60;
			}elseif ($half_unit=="hrs"){
				$half=$half * 3600;
			}elseif ($half_unit=="days"){
				$half=$half*86400;
			}elseif ($half_unit=="sec"){
				$half=$half;
			}
			return $half;
		}		
		function other_time($half_one,$half_sec,$half_unit){
			if($half_unit === "hrs/min"){
				$half = ($half_one *3600) + ($half_sec * 60);
			}elseif ($half_unit === "min/sec"){
				$half = ($half_one * 60) + ($half_sec);
			}
			return $half;
		}

		if($half_unit === 'min/sec' || $half_unit === 'hrs/min'){
			if (empty($half_one) && empty($half_sec)) {
                $this->param['error'] = 'Please! Enter Input.';
                return $this->param;
			}
			if (empty($half_one)) {
				$half_one = 0;
			}
			if (empty($half_sec)) {
				$half_sec = 0;
			}
			if (is_numeric($dosage)){
				if($half == 0) {
                    $this->param['error'] = 'Half life value cannot be equal to zero.';
                    return $this->param;
				}
				if($half_unit === 'min/sec'){
					$half=other_time($half_one,$half_sec,$half_unit);
					$time_convert=$half/60;
				}else{
					$half=other_time($half_one,$half_sec,$half_unit);
					$time_convert=$half/3600;
				}

				$answer=round($time_convert,3);
				$answer_one=round($answer+$answer,2);
				$answer_two=round($answer_one+$answer,2);
				$answer_three=round($answer_two+$answer,2);
				$answer_four=round($answer_three+$answer,2);
				$answer_five=round($answer_four+$answer,2);

				$subanswer= sec_unit($dosage,$dosage_unit)/2;
				$subanswer_one= $subanswer/2;
				$subanswer_sec= $subanswer_one/2;
				$subanswer_three= $subanswer_sec/2;
				$subanswer_four= $subanswer_three/2;
				$subanswer_five= $subanswer_four/2;

				$this->param['subanswer'] = $subanswer;
				$this->param['subanswer_one'] = $subanswer_one;
				$this->param['subanswer_sec'] = $subanswer_sec;
				$this->param['subanswer_three'] = $subanswer_three;
				$this->param['subanswer_four'] = $subanswer_four;
				$this->param['subanswer_five'] = $subanswer_five;
				$this->param['answer'] = $answer;
				$this->param['answer_one'] = $answer_one;
				$this->param['answer_two'] = $answer_two;
				$this->param['answer_three'] = $answer_three;
				$this->param['answer_four'] = $answer_four;
				$this->param['answer_five'] = $answer_five;
			}else{
                $this->param['error'] = 'Please! Check Your Input.';
                return $this->param;
			}
		}else{
			if (is_numeric($half) && is_numeric($dosage)){
					if($half == 0){
                        $this->param['error'] = 'Half life value cannot be equal to zero.';
                        return $this->param;
					}
					
					if($half_unit=="mins"){
						$half= time_unit($half,$half_unit);
						$time_convert=$half / 60;
					}elseif ($half_unit=="hrs"){
						$half= time_unit($half,$half_unit);
						$time_convert=$half / 3600;
					}elseif ($half_unit=="days"){
						$half= time_unit($half,$half_unit);
						$time_convert=$half / 86400;
					}elseif ($half_unit=="sec"){
						$half= time_unit($half,$half_unit);
						$time_convert=$half;
					}

					$answer=round($time_convert,3);
					$answer_one=round($answer+$answer,2);
					$answer_two=round($answer_one+$answer,2);
					$answer_three=round($answer_two+$answer,2);
					$answer_four=round($answer_three+$answer,2);
					$answer_five=round($answer_four+$answer,2);


					$subanswer=sec_unit($dosage,$dosage_unit)/2;
					$subanswer_one= $subanswer/2;
					$subanswer_sec= $subanswer_one/2;
					$subanswer_three= $subanswer_sec/2;
					$subanswer_four= $subanswer_three/2;
					$subanswer_five= $subanswer_four/2;

					$this->param['subanswer'] = $subanswer;
					$this->param['subanswer_one'] = $subanswer_one;
					$this->param['subanswer_sec'] = $subanswer_sec;
					$this->param['subanswer_three'] = $subanswer_three;
					$this->param['subanswer_four'] = $subanswer_four;
					$this->param['subanswer_five'] = $subanswer_five;
					$this->param['answer'] = $answer;
					$this->param['answer_one'] = $answer_one;
					$this->param['answer_two'] = $answer_two;
					$this->param['answer_three'] = $answer_three;
					$this->param['answer_four'] = $answer_four;
					$this->param['answer_five'] = $answer_five;
			}else{
                $this->param['error'] = 'Please! Check Your Input.';
                return $this->param;
			}

		}
		$this->param[ 'RESULT' ] = 1;
        return $this->param;
	}

    // Treadmill Calorie Calculator
	public function treadmill($request){
        // dd($request->all());
        $gradient = $request->gradient;
        $weight = $request->weight;
        $weight_unit = $request->weight_unit;
        $speed = $request->speed;
        $speed_unit = $request->speed_unit;
        $distance = $request->distance;
        $distance_unit = $request->distance_unit;
        $time = $request->time;

		if($gradient < -0.001){
            $this->param['error'] = 'Please input the gradient above 0.';
            return $this->param;
		}
		if($speed < 0){
            $this->param['error'] = 'Please input the speed above 0.';
            return $this->param;
		}
		if($time < 0){
            $this->param['error'] = 'Please input the running-time(min) above 0.';
            return $this->param;
		}
		if($distance < 0){
            $this->param['error'] = 'Please input the running-distance(Mile/Km) above 0.';
            return $this->param;
		}
		if($weight < 0){
            $this->param['error'] = 'Please input the weigh(lbs/Kg) above 0.';
            return $this->param;
		}
		if($weight < 0){
            $this->param['error'] = 'Please input the weigh(lbs/Kg) above 0.';
            return $this->param;
		}
		function same_unit($a, $b){
			if ($a === "mph" || $a === "mile") { 
				$ans = $b * 1.609;
			}else if ($a === "km/h" || $a === "km") {
				$ans = $b / 1.609;
			}
			return $ans;
		} 
		if(is_numeric($speed) && is_numeric($distance) && is_numeric($time)){
            $this->param['error'] = 'Speed, Time, and the Distance cannot be specified at the same time.';
            return $this->param;
		}
		if(empty($speed) && empty($distance) && empty($time)){
            $this->param['error'] = 'Please! Check your Input.';
            return $this->param;
		}
		if(empty($distance) && empty($time)){
            $this->param['error'] = 'Please! Check your Input.';
            return $this->param;
		}
		if(empty($speed) && empty($time)){
            $this->param['error'] = 'Please! Check your Input.';
            return $this->param;
		}
		if(empty($distance) && empty($speed)){
            $this->param['error'] = 'Please! Check your Input.';
            return $this->param;
		}
		if (is_numeric($gradient) && is_numeric($weight)){
			if (is_numeric($speed) && is_numeric($distance)) {
				if ($speed_unit === "km/h" || $distance_unit === "km") { 
					$speed_mph = $speed / 1.609;
					$distance_m = $distance / 1.609;
					$speed_kmh = $speed;
					$distance_km = $distance;
				}else{
					$speed_kmh = $speed * 1.609;
					$distance_km = $distance * 1.609;
					$speed_mph = $speed;
					$distance_m = $distance;

				}
				$time_ans = ($distance_m / $speed_mph) * 60;
			}else if (is_numeric($speed) && is_numeric($time)) {
				if ($speed_unit === "km/h") { 
					$speed_mph = $speed / 1.609;
					$speed_kmh = $speed;
				}else{
					$speed_kmh = $speed * 1.609;
					$speed_mph = $speed;

				}
				$time_ans = $time / 60;
				$distance_m = $speed_mph * $time_ans;
				$distance_km = $distance_m * 1.609;
			}else if (is_numeric($distance) && is_numeric($time)) {
				if ($distance_unit === "km") { 
					$distance_m = $distance / 1.609;
					$distnace_kmh = $speed;
				}else{
					$distance_kmh = $distnace * 1.609;
					$distance_m = $distnace;

				}
				$time_ans = $time / 60;
				$speed_mph = $distance_m / $time_ans;
				$speed_kmh = $speed_mph * 1.609;
			}
			$weight_kg = $weight;
			if ($weight_unit === "lbs") {
				$weight_kg = $weight / 2.205;
			}
			$speed_mph_sec = $speed_mph + $speed_mph * $gradient * 9 / 200;
			$speed_kmh_sec = $speed_kmh + $speed_kmh * $gradient * 9 / 200;
			$distance_m_sec = $speed_mph_sec * $time_ans / 60;
			$distance_km_sec = $speed_kmh_sec * $time_ans / 60;
			$y0 = $speed_kmh + $speed_kmh * $gradient * 9 / 200;

			$cal = ($y0*1000/60+17.5)*$time_ans*$weight_kg/1000;
			$fat = $cal/7/2;
			$fatoz_ans = $fat/28.3495;
			$fatg_ans = $fat;
			$mets = $cal/$weight_kg/$time_ans*60;
			$energy_kj = 4.184 * $cal;
			$energy_kw_ans = $energy_kj / 3600;
			$electric_heater_ans = 60 * $energy_kw_ans;
			$light_bulb_ans = ($electric_heater_ans * 10) / 60;
			$cburger_ans = $cal / 310;
			$beer2_ans = $cal / 153.1;
			$cleanning_ans = $cal/1.59/$weight*60;
			$shop_ans = $cal / 2.5;

			$meter_dash_ans = 360 / $y0;  		//100m for sec
			$meter_run_h_ans = floor(600/$y0);		//10K for min
			$meter_run_m_ans = ((600 / $y0) - $meter_run_h_ans) * 60;

			$half_marathon=21.095 * 60 / $y0;	//Half for min
			$half_marathonh = floor($half_marathon / 60);
			$half_marathonm = floor($half_marathon - $half_marathonh * 60);
			$half_marathons = (($half_marathon - $half_marathonh * 60) - $half_marathonm) * 60;

			$marathon = 42.195 * 60 / $y0;	//Full for min
			$marathonh = floor($marathon/60);
			$marathonm = floor($marathon-$marathonh*60);
			$marathons = (($marathon - $marathonh * 60) - $marathonm) * 60;
			$myrecord = $marathon / 60;
			$record_ans = 2.0275 / $myrecord * 100; //record 2:01:39 
			$this->param = array (
				"speed_mph" 			=> round($speed_mph, 1),
				"speed_kmh" 			=> round($speed_kmh, 1),
				"time_ans" 			=> round($time_ans, 1),
				"distance_m" 			=> round($distance_m, 1),
				"distance_km" 			=> round($distance_km, 1),
				"speed_mph_sec" 			=> round($speed_mph_sec, 1),
				"speed_kmh_sec" 			=> round($speed_kmh_sec, 1),
				"distance_m_sec" 			=> round($distance_m_sec, 1),
				"distance_km_sec" 			=> round($distance_km_sec, 1),
				"cal" 			=> round($cal, 1),
				"fatoz_ans" 			=> round($fatoz_ans, 1),
				"fatg_ans" 			=> round($fatg_ans, 1),
				"mets" 			=> round($mets, 1),
				"energy_kw_ans" 			=> round($energy_kw_ans, 1),
				"electric_heater_ans" 			=> round($electric_heater_ans, 1),
				"light_bulb_ans" 			=> round($light_bulb_ans, 1),
				"cburger_ans" 			=> round($cburger_ans, 1),
				"beer2_ans" 			=> round($beer2_ans, 1),
				"shop_ans" 			=> round($shop_ans, 1),
				"cleanning_ans" 			=> round($cleanning_ans, 1),
				"meter_dash_ans" 			=> round($meter_dash_ans, 1),
				"meter_run_h_ans" 			=> round($meter_run_h_ans, 1),
				"meter_run_m_ans" 			=> round($meter_run_m_ans, 1),
				"half_marathonh" 			=> round($half_marathonh, 1),
				"half_marathonm" 			=> round($half_marathonm, 1),
				"half_marathons" 			=> round($half_marathons, 1),
				"marathonh" 			=> round($marathonh, 1),
				"marathonm" 			=> round($marathonm, 1),
				"marathons" 			=> round($marathons, 1),
				"record_ans" 			=> round($record_ans, 1),
				"gradient" 			=> $gradient,
				"RESULT" 			=> 1
			);
            return $this->param;
		}else{
            $this->param['error'] = 'Please! Check Your Input.';
            return $this->param;
		}
	}

    // Waist to Height Ratio (WHtR) Calculator
	function waist_height($request){
        // dd($request->all());
		if (is_numeric($request->height_ft) || is_numeric($request->height_in) || is_numeric($request->height_cm) && is_numeric($request->waist)) {
			if ($request->unit_ft_in=='ft/in') {
				if (is_numeric($request->height_ft)) {
					$height_cm=$request->height_ft * 30.48;
				}
				if (is_numeric($request->height_in)) {
					$height_cm=($request->height_in * 2.54) + @$height_cm;
				}
			}else{
				$height_cm=$request->height_cm;
			}
			$waist=$request->waist;
			if ($request->unit==='in') {
				$waist=$waist * 2.54;
			}
			$ans= round($waist / $height_cm,2);
			if ($request->gender==='Male') {
				if ($ans<0.34) {
					$color='#20BEC8';
					$left='2%';
					$this->param['under'] = 'Underweight';
					$this->param['xslim'] = 'bg-blue text-white';
				}
				if ($ans>0.34 && $ans<0.42) {
					$color='#20BEC8';
					$left='2%';
					$this->param['slim'] = 'bg-blue text-white';
					$this->param['under'] = 'Underweight';
				}elseif ($ans>=0.42 && $ans<=0.52) {
					$color='#10951D';
					$left="26%";
					$this->param['healthy'] = 'Healthy';
					$this->param['health'] = 'bg-green text-white';
				}elseif ($ans>=0.53 && $ans<=0.57) {
					$color='#CABE52';
					$left="50%";
					$this->param['over'] = 'Overweight';
					$this->param['overc'] = 'bg-trumeric text-white';
				}elseif ($ans>0.58 && $ans<=0.62) {
					$color='#FF0000';
					$left="50%";
					$this->param['over'] = 'Overweight';
					$this->param['overh'] = 'bg-red text-white';
				}elseif ($ans>=0.63 && $ans<=0.80) {
					$color='#FF0000';
					$left="74%";
					$this->param['obese'] = 'Obese';
					$this->param['obesew'] = 'bg-red text-white';
				}elseif ($ans>0.80) {
					$color='#FF0000';
					$left="80%";
					$this->param['obese'] = 'Obese';
					$this->param['obesew'] = 'bg-red text-white';
				}
			}
			if ($request->gender=='Female') {
				if ($ans<0.34) {
					$color='#20BEC8';
					$left='2%';
					$this->param['under'] = 'Underweight';
					$this->param['xslim'] = 'bg-blue text-white';
				}
				if ($ans>34 && $ans<0.42) {
					$color='#20BEC8';
					$left='2%';
					$this->param['slim'] = 'bg-blue text-white';
					$this->param['under'] = 'Underweight';
				}elseif ($ans>=0.42 && $ans<=0.48) {
					$color='#10951D';
					$left="26%";
					$this->param['healthy'] = 'Healthy';
					$this->param['health'] = 'bg-green text-white';
				}elseif ($ans>=0.49 && $ans<=0.53) {
					$color='#CABE52';
					$left="50%";
					$this->param['over'] = 'Overweight';
					$this->param['overc'] = 'bg-trumeric text-white';
				}elseif ($ans>0.53 && $ans<=0.57) {
					$color='#FF0000';
					$left="50%";
					$this->param['over'] = 'Overweight';
					$this->param['overh'] = 'bg-red text-white';
				}elseif ($ans>=0.58 && $ans<=0.80) {
					$color='#FF0000';
					$left="74%";
					$this->param['obese'] = 'Obese';
					$this->param['obesew'] = 'bg-red text-white';
				}elseif ($ans>0.80) {
					$color='#FF0000';
					$left="80%";
					$this->param['obese'] = 'Obese';
					$this->param['obesew'] = 'bg-red text-white';
				}
			}
			$this->param['ratio'] = $ans;
			$this->param['color'] = $color;
			$this->param['left'] = $left;
			$this->param['RESULT'] = 1;
            return $this->param;
		} else {
            $this->param['error'] = 'Please Fill All Fields.';
            return $this->param;
		}		
	}

    public function swimming($request)
	{
        // dd($request->all());
		$weight      = trim($request->input('weight'));
		$weight_unit = trim($request->input('weight_unit'));
		$time        = trim($request->input('time'));
		$time_unit   = trim($request->input('time_unit'));
		$style       = trim($request->input('style'));
		function convert_to_kg($unit, $value)
		{
			if ($unit == 'lb') {
				$ans = $value / 2.205;
			} elseif ($unit == 'kg') {
				$ans = $value;
			} elseif ($unit == 'stone') {
				$ans = $value * 6.35;
			}
			return $ans;
		}

		function convert_to_min($unit, $value)
		{
			if ($unit == 'sec') {
				$ans = $value / 60;
			} elseif ($unit == 'min') {
				$ans = $value;
			} elseif ($unit == 'hrs') {
				$ans = $value * 60;
			}
			return $ans;
		}

		if (is_numeric($style) && is_numeric($weight) && !empty($weight_unit)) {
			if (!empty($time_unit)) {
				if (is_numeric($time)) {
					$final_min = convert_to_min($time_unit, $time);
				} else {
					$this->param['error'] = 'Please! Check Your Inputs';
					return $this->param;
				}
				$final_weight = convert_to_kg($weight_unit, $weight);


				$cal_burned_per_min = ($style * $final_weight * 3.5) / 200;

				$total_cal_burned = $cal_burned_per_min * $final_min;

				$this->param['cal_burned_per_min'] = round($cal_burned_per_min, 2);
				$this->param['total_cal_burned']   = round($total_cal_burned, 2);
				$this->param['RESULT']             = 1;

				return $this->param;
			} else {
				$this->param['error'] = 'Please! Check Your Inputs';
				return $this->param;
			}
		} else {
			$this->param['error'] = 'Please! Check Your Inputs';
			return $this->param;
		}
	}
